-- Poems batch 112
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ea08cfe2-6b4f-4f2d-9aae-c3e2f5921582','寄題起莘家義軒','洪邁','宋','宋诗','song-poetry','','[]','貞觀盛德後，餘慶未渠央。',120,'全唐诗/poet.song.126000.json','["貞觀盛德後，餘慶未渠央。", "舊聞閩海家，欲縱燕山芳。", "教子嗣先訓，開軒翼中堂。", "地偏市朝遠，几浄書簡香。", "先生陳太丘，飯糜百憂忘。", "弟子俱羯胡，不聞觸屏僵。", "一變豪俠窟，遂成鄒魯鄉。", "下車里門外，他年看諸郎。", "坐上紆素髮，詵詵立冠裳。", "我詩自可絃，請以侑壺觴。"]'),
('1cf24778-5e96-4ad0-9287-b18122d736d9','梅花','洪邁','宋','宋诗','song-poetry','','[]','山深春未動，沙淺水欲冰。',144,'全唐诗/poet.song.126000.json','["山深春未動，沙淺水欲冰。", "玉梅於此時，靚粧略無朋。", "露蕊欲的皪，月枝挂鬅鬙。", "儼如江漢女，可愛不可陵。", "他年江南路，曉粧犯嚴凝。", "尋香烟雨中，橫斜插茅簦。", "却數今幾日，癡如秋後蠅。", "北嶺枝欲空，誰與扶一登。", "聊分窺水影，依我照字燈。", "坐使惜花夢，臨風脚騰騰。", "昔如夢中蝶，今學桑下僧。", "了知菩提長，念起我何曾。"]'),
('8ec53a28-7f21-4951-95f6-faf6add1ffd3','十一月十九日與仲猷大年綽中美中飲於南臺','洪邁','宋','宋诗','song-poetry','','[]','空山欲暝雲冥冥，玉梅半開吾眼青。',96,'全唐诗/poet.song.126000.json','["空山欲暝雲冥冥，玉梅半開吾眼青。", "此身垂欲走塵土，聊復舉酒看崢嶸。", "折腰向人不知恥，故園可鋤在千里。", "金昆石友一開眉，珍重道人相料理。", "楚江東岸先人廬，竹君安否久無書。", "歸歟何時應白首，我若食言如此酒。"]'),
('1b1a83c7-e249-4bf6-8c22-45ebfe0754cb','春社齋禁連雨不止賦呈夢得','洪邁','宋','宋诗','song-poetry','','[]','歲豐農猶饑，歲惡何可說。',144,'全唐诗/poet.song.126000.json','["歲豐農猶饑，歲惡何可說。", "哀哉半菽氓，罪歲同一舌。", "年時旱塵漲，臈盡不見雪。", "青皇忽雨我，萬頃麥苗活。", "令尹民父母，溝壑思手挈。", "祈年祓齋居，有酒不忍設。", "那知桃李徑，狼籍香泥滑。", "芳意一如此，坐恐及鶗鴂。", "郊原佇開晴，出勞南畝饁。", "秋成已在眼，一醉宇宙豁。", "更呼湔裙人，勸此側帽客。", "和公斜川詩，磨石鑱歲月。"]'),
('1bf5bdde-5121-4961-8d02-d63b9da206ad','次韻夢得見示長篇  其一','洪邁','宋','宋诗','song-poetry','','[]','雉馴不因媒，鳩煖自呼婦。',216,'全唐诗/poet.song.126000.json','["雉馴不因媒，鳩煖自呼婦。", "詩成桃李陰，知是霹靂手。", "簿書我亦厭，丘壑渠自有。", "却憐支離疏，飽食得薪槱。", "俗夫嘗世味，甘苦半噦嘔。", "知公超然處，心跡兩無垢。", "愁陰老芳物，蟲鳥故相誘。", "浪蕋費收拾，柔條可結揉。", "豈無我輩人，一醉開笑口。", "那知市門底，客倦枕兩肘。", "眼高可人稀，命蹇亨運偶。", "平生願執鞭，見謂余小友。", "細觀豈弟心，宜在帝左右。", "却來塵埃中，寂寞對五柳。", "鷇音藏鵠羽，正待荆雞剖。", "學政容窺譜，問字當載酒。", "虛名翻誤夢，恐坐箕與斗。", "言詩終不稱，永媿賦瓊玖。"]'),
('5cc9dc80-ea2d-4f93-8ad0-a07a504ec31e','次韻夢得見示長篇  其二','洪邁','宋','宋诗','song-poetry','','[]','身閒書有味，吏傲俗不親。',192,'全唐诗/poet.song.126000.json','["身閒書有味，吏傲俗不親。", "小窗據物表，掃盡心眼塵。", "令尹垂珠玉，敲門喚行春。", "作意向芳物，吾車曾未巾。", "愁陰入病骨，鳩婦聲亦嗔。", "冥冥三日雨，桃李迹已陳。", "空餘深枝間，一一青子新。", "穠芳殿春晚，猶堪慰佳辰。", "酴醿曉粧靚，芍藥醉臉勻。", "白萼簪嫋嫋，風枝倒粼粼。", "言當呼短舞，抵掌回雙顰。", "年來得相從，稍覺安沉淪。", "豈不挂俗事，察公極清真。", "眼中醉鄉路，風味良獨醇。", "流光不容玩，尺璧何足珍。", "漓俗益可厭，願言勤問津。"]'),
('acae36ce-eb14-4907-bc34-3cf0cdf14d90','牡丹酴醿各一首呈周宰  其一','洪邁','宋','宋诗','song-poetry','','[]','珍藂壓朝露，無人羞欲敧。',48,'全唐诗/poet.song.126000.json','["珍藂壓朝露，無人羞欲敧。", "春風醉香骨，綽約不自持。", "誰憐曲肱人，一笑遺絃姿。", "不言意可了，君醉當勿疑。"]'),
('4d5b6c34-6587-4531-85e2-a53d2bc6fa77','牡丹酴醿各一首呈周宰  其二','洪邁','宋','宋诗','song-poetry','','[]','妝淡洗逾靚，肌香薰不成。',48,'全唐诗/poet.song.126000.json','["妝淡洗逾靚，肌香薰不成。", "皎然月露姿，一笑午景晴。", "聊移夢蝶牀，相對戶不扃。", "誰令風雨暴，睡起春縱橫。"]'),
('2a4de2f3-bd51-4f66-bbd5-a2ac082b8b81','次韻夢得淺紅芍藥長句','洪邁','宋','宋诗','song-poetry','','[]','十日愁陰病不出，卧看春歸無計惜。',128,'全唐诗/poet.song.126000.json','["十日愁陰病不出，卧看春歸無計惜。", "詩翁遣送淮海春，衰眼熨開雲霧拆。", "胭脂注臉勻未遍，肉紅借酒生春色。", "了知造物著意深，傾倒春工不餘力。", "年來不顧溱洧女，載酒非公復安適。", "且將妙句寫餘妍，欲立佳名付精識。", "一春頗困歌湮沒，回首紛華三太息。", "願言乞與洗心方，歸對爐香誦周易。"]'),
('a2a1cf44-7fcd-4db4-8102-ad5be79d77a1','宿禪寂院','洪邁','宋','宋诗','song-poetry','','[]','夢中一葉摇江湖，困睡不覺身籃輿。',192,'全唐诗/poet.song.126000.json','["夢中一葉摇江湖，困睡不覺身籃輿。", "眼明佛屋麗丹碧，瓦鴟鐵鳳凌空虛。", "疲民日者困苛索，半作頳尾相濡魚。", "鵜鶘數罟兩不置，肯念竭澤明年無。", "道人誰與辦此事，斤琢千指開渠渠。", "頗疑如幻三昧力，上方手攬歸吾廬。", "了知舌本法輪轉，咄嗟檀施爭奔輸。", "不辭割愛一念善，誰謂歲惡窮民愚。", "書生袖手對溝壑，力不能援心煩紆。", "事無大小成者少，談說治亂何區區。", "調卑絃急誠齟齬，鑿圓枘方尤闊疎。", "古今罪歲同一口，撫掌一笑皆愚儒。"]'),
('6672099d-12a7-4698-84dc-c55d743b386e','詩約范直夫遊萬葉寺觀瀑泉','洪邁','宋','宋诗','song-poetry','','[]','范侯隠下吏，夙尚本丘園。',120,'全唐诗/poet.song.126000.json','["范侯隠下吏，夙尚本丘園。", "身投攫金市，聚書以自藩。", "炯然如孤月，不受黄流渾。", "要知句律工，競病何足論。", "我生羣末俗，涇渭同一源。", "同心無楚越，傾蓋如弟昆。", "人生各有役，不暇捧一尊。", "風蒲挂南浦，念欲東南奔。", "對牀定何夕，青燈照晤言。", "懸知吟詩處，千尺銀河翻。"]'),
('33e5587d-e359-469d-aeb7-af288e1502a5','次韻夢得見示之什','洪邁','宋','宋诗','song-poetry','','[]','居楚求齊音，美惡不同土。',96,'全唐诗/poet.song.126000.json','["居楚求齊音，美惡不同土。", "諠豗俗物華，鮮復有佳處。", "時從玉璧人，商略窮萬古。", "詩如粟牛戲，誤得摩頂許。", "望道渺逾遠，浮生真暫寓。", "忍持尺璧陰，空作秋蟲語。", "微言倘傾倒，河漢濯肺腑。", "向來說詩口，自此行可杜。"]'),
('4ecf35a9-ae60-476d-aa50-b564be0420c3','送甌寧魏生赴武舉','洪邁','宋','宋诗','song-poetry','','[]','建安少年請纓客，橫槊賦詩兩無敵。',64,'全唐诗/poet.song.126000.json','["建安少年請纓客，橫槊賦詩兩無敵。", "辭家去作入彀英，氣拂天狼夜無迹。", "廟堂尺箠鞭羌雛，智名勇功付壯夫。", "引弓沒羽世自有，敢聞上策當何如。"]'),
('5b186584-e2fa-43ff-8475-06062c2c9228','陳仲仁止止堂','洪邁','宋','宋诗','song-poetry','','[]','以我有限景，逐彼無涯知。',168,'全唐诗/poet.song.126000.json','["以我有限景，逐彼無涯知。", "失足踐畏途，投身試危機。", "舟車日奔覆，定無丘與夷。", "萬古踐此轍，嗟我與誰歸。", "仲仁古靜者，懷璧照褐衣。", "名途嘗一戲，回首羞前非。", "心如得坎水，不受狂風吹。", "功名憂不免，當復定何之。", "請觀本無作，今復止者誰。", "築堂市門側，著書園不窺。", "蓬藋深一丈，圖書周四圍。", "時有好事人，載酒問所疑。", "攫金奮敏手，倚市誇妍姿。", "回光時自照，何者非吾師。"]'),
('c67eb6ad-ca46-475f-97a2-662520fc910c','送志宏西上','洪邁','宋','宋诗','song-poetry','','[]','九州眼一槩，餘子真瑣瑣。',144,'全唐诗/poet.song.126000.json','["九州眼一槩，餘子真瑣瑣。", "嶽立㟝嶁中，喜此高岋峨。", "如公吾輩人，取友一到我。", "揮毫賦垂天，風雨卷蓬顆。", "相期八表遊，未覺夙心左。", "解龜醉江閣，酒面山月墮。", "起瞻帝鄉雲，感歎不成坐。", "何須飛霞佩，自辦凌風舸。", "瀛洲渺溟渤，萬里一掀簸。", "緘詩寄天涯，秉燭對新火。", "那知市門仙，斗祿事么麽。", "空餘腸九迴，上疏何日果。"]'),
('ea526364-9d79-4b4f-9616-d0dace01b154','有懷舍弟逢年時歸婺源以詩督之','洪邁','宋','宋诗','song-poetry','','[]','木落天未霜，君歸定何時。',216,'全唐诗/poet.song.126000.json','["木落天未霜，君歸定何時。", "相思如驚鵲，中夜未安枝。", "夢中見阿連，鏘然詠新詩。", "寤驚衰葉翻，道是步屐移。", "攬衣下中庭，風露浩淼瀰。", "遥知客衣薄，歸來一何遲。", "平生短檠燈，相對忽解頤。", "萬古一舒卷，佳處良在茲。", "是中及物心，上與稷契期。", "援古以自例，自矢無乃癡。", "夜叉叱九閽，側足不敢窺。", "坐令一寸心，日抱二柄疑。", "遲君商量此，免得兒輩嗤。", "况乃綠髮親，倚門鬢欲絲。", "狶膏非鳳喙，車轄無可脂。", "再拜壽杯分，斑衣舞參差。", "秋芳未云歇，采采黄金蕤。", "萬鍾不足樂，古人豈我欺。"]'),
('e2f7d1da-cfcf-43fb-985b-75bcef53e303','九月十七日夜度蔡道嶺宿彌勒院','洪邁','宋','宋诗','song-poetry','','[]','月出度松嶺，露香霏羽衣。',144,'全唐诗/poet.song.126000.json','["月出度松嶺，露香霏羽衣。", "肅肅夜氣清，蒼蒼烟徑微。", "川光浴秋容，蘿影挂夕輝。", "冰輪碾空闊，飛轍無因依。", "擬掬星渚波，恐觸天孫機。", "偓佺何時見，沆瀣聊獨揮。", "未應青霞志，即與素願違。", "稍休塵外蹤，想此巖下扉。", "清吟寫萬籟，妙想絕百非。", "不須河漢言，盡解紛華圍。", "飛仙亦戲劇，玄學乃庶幾。", "鰲山切丹極，歲晚行將歸。"]'),
('02c0daaf-cd85-4529-b30a-c52364f8a046','游鄭圃','洪邁','宋','宋诗','song-poetry','','[]','城郭不去眼，而得林壑娛。',48,'全唐诗/poet.song.126000.json','["城郭不去眼，而得林壑娛。", "低徊撫壯心，欲吐無與俱。", "鏗然一枝筇，細磴半樵漁。", "挽衣竟與飲，不省誰爲吾。"]'),
('2902a2d7-08f1-4b43-aad0-20614db2226a','女貧苦難妍','洪邁','宋','宋诗','song-poetry','','[]','女貧苦難妍，士貧苦難高。',168,'全唐诗/poet.song.126000.json','["女貧苦難妍，士貧苦難高。", "了知論此者，不識一世豪。", "此身百斛鼎，流俗欲手操。", "寧當捨其中，局促計所遭。", "頗疑有若人，骯髒栖蓬蒿。", "考槃一丘壑，光景不可韜。", "斯人不我忘，空復踰垣逃。", "軒裳亦云華，唾去如腥臊。", "哀哉夸毗子，擾擾冠猿猱。", "恬無齊世心，閔默死滔滔。", "朅來事斗祿，俛仰身桔槔。", "一官戲人間，幾何非餮饕。", "誰言眷此幘，擲去輕秋毫。", "區區欲驕士，一哭嗟兒曹。"]'),
('38d8a575-98b7-4bd5-aafd-f3106fe6d955','溪南梅花','洪邁','宋','宋诗','song-poetry','','[]','巉巉石徑鳴枯筇，意行詰曲無西東。',192,'全唐诗/poet.song.126000.json','["巉巉石徑鳴枯筇，意行詰曲無西東。", "心知幽壑梅已動，一枝寄我曾未蒙。", "清香橫路忽驚顧，冰蕊的皪蠻烟中。", "有如佳人久去眼，邂逅相得情何窮。", "蔬畦壓霜翠羽亂，已覺雪片栖丰茸。", "嗟我辜此來已晚，攀條嚼蕊聊從容。", "玉仙遊戲下塵世，絕艷一洗汞鉛空。", "不知閬苑在何許，叱回風馭無匆匆。", "溪寒沙浄迷俛仰，坐待山月來朦朧。", "豈無尊酒相暖熱，錦裘起舞如驚鴻。", "仇池老仙羽化久，妙曲三疊餘仙風。", "歸時醉倒不知卧，明日來此誰能同。"]'),
('3c112268-b577-4db4-b0cb-539d1ac79f3c','再和求首座','洪邁','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','道人昔曳匡廬筇，五老負雪湓江東。',192,'全唐诗/poet.song.126000.json','["道人昔曳匡廬筇，五老負雪湓江東。", "犯寒貪覓玉梅句，雖有衲被何曾蒙。", "歸來苦雨熟梅子，卷裓深卧蠻烟中。", "詩傳絕境忽入手，置我鄉國情何窮。", "十年不蹈江上路，漠漠海氣昏貂茸。", "異鄉歲晚慰流落，一笑頼此冰雪容。", "嶠南絕唱誰敢和，騎鯨人去塵寰空。", "崑墟下視堪笑閔，雕琢肝腎愁匆匆。", "那知幽子雲雨上，風斤玉斧修朣朧。", "讀詩令我一回首，杳若目送孤飛鴻。", "何時晤語折鐺側，坐聽萬籟號天風。", "拈花特地兩顔解，他時與子真參同。"]'),
('9a282f05-ee5a-42f9-b09b-38a845cc6eb9','奉酬令德寄示長句','洪邁','宋','宋诗','song-poetry','','[]','閒官屋舍如幽栖，寒苦餘業償鹽虀。',208,'全唐诗/poet.song.126000.json','["閒官屋舍如幽栖，寒苦餘業償鹽虀。", "忽聞鵲聲作破竹，尺書入手誰所齎。", "交游勝絕似公少，矯矯鸞鳳依蒿藜。", "青冥側足在咫尺，誰使狡獪捐其梯。", "秋風溪上共尊酒，擺落羈束忘畛畦。", "紅裳起舞意未足，缺月銜嶺星河低。", "只今跌宕走塵土，清夢往復無山蹊。", "新詩驚怪爛盈幅，筆力拗怒蟠虹蜺。", "遥知盤礴小窗底，得喪已著一理齊。", "此生同困造物戲，未覺與世誰雲泥。", "雖無絕唱追白雪，頼有妙契如靈犀。", "一笑從公豈無日，挽袖相屬空玻璃。", "不須俗物敗真賞，但覓佳處同攀躋。"]'),
('51ccbf2e-337e-4027-8756-a8a0e25851d9','答林康民見和梅花詩','洪邁','宋','宋诗','song-poetry','','[]','寒崦人家碧谿尾，一樹江梅卧清泚。',160,'全唐诗/poet.song.126000.json','["寒崦人家碧谿尾，一樹江梅卧清泚。", "仙姿不受白眼汙，風斂天香瘴烟裏。", "向來休沐偶無事，惟我亦游二三子。", "彎碕曲徑一携手，凍雀驚飛莫能委。", "班荆勸客少延佇，酌酒賦詩相料理。", "多情入骨憐閔殊，休倚橫斜嚼冰蕊。", "至今清夢挂殘月，强作短歌傳素齒。", "韻高尚恨白難稱，頼有君詩清且美。", "天涯歲晚感鄉物，歸歟何時路千里。", "枕樓一笛雪漫空，回首江亭淚如洗。"]'),
('720b6c15-56d4-417c-a53c-3f3d186d7401','上丁餘膰置酒招綽中德粲逢年','洪邁','宋','宋诗','song-poetry','','[]','我生無幾求，畢願老葭菼。',168,'全唐诗/poet.song.126000.json','["我生無幾求，畢願老葭菼。", "誰令事斗祿，飯糲羹不糝。", "書生亦可憐，微物有先感。", "朝來食指動，膰肉豐咀啖。", "恭惟魯司寇，道大長壈坎。", "空餘祠千載，不救陳蔡慘。", "永言百世師，願學吾豈敢。", "當饑不忘歌，既飽復何憾。", "安能如王孫，長物貯頤頷。", "急呼講肆人，一醉捨鉛槧。", "相携桃李徑，歷亂蹴紅毿。", "言强三尺喙，氣溢一身膽。", "平生超然處，獨嗜逾昌歜。", "詩成持寄君，莫遺兒輩覽。"]'),
('aff65fe4-1d44-4228-adac-c9c8652bce4b','用綽中韻送正臣正臣欲歸隠而無資故廣其意以告識者','洪邁','宋','宋诗','song-poetry','','[]','華裾錦領烏紗幘，氣蓋當年五陵俠。',128,'全唐诗/poet.song.126000.json','["華裾錦領烏紗幘，氣蓋當年五陵俠。", "胸中磈礧不可平，拂衣歸來抱長鋏。", "軒然寄傲楸枰間，長恨坐隠非雲山。", "相逢笑我眷微粟，我歸未可君何難。", "世人錢作牛吼音，誰能立談壽千金。", "空令擁鼻誦招隠，知君心在仙峯陰。", "故山自歎無歸期，作詩但擬淵明詞。", "却愁他日林下信，千里寄我惟當歸。"]'),
('72040298-8ee1-49fb-9ca4-7fc7e40b704b','秋懷六首  其一','洪邁','宋','宋诗','song-poetry','','[]','庭柯一葉失，風挾涼氣歸。',48,'全唐诗/poet.song.126000.json','["庭柯一葉失，風挾涼氣歸。", "湛湛陂水清，芙蕖脫紅衣。", "非無岑寂士，句法妙玄暉。", "獨懷履霜戒，德人貴知微。"]'),
('8ee75560-ee16-4cae-a32a-4bcdde535ed4','秋懷六首  其二','洪邁','宋','宋诗','song-poetry','','[]','真儒六經學，文字聊解紛。',48,'全唐诗/poet.song.126000.json','["真儒六經學，文字聊解紛。", "長孺棄諸侯，漢庭相公孫。", "兒口乳未乾，妄作黑白分。", "誰能領斯會，事往風中雲。"]'),
('f6cb090d-f292-444e-b6fb-1271a12993b3','秋懷六首  其三','洪邁','宋','宋诗','song-poetry','','[]','導江自岷山，源淺觴可濫。',48,'全唐诗/poet.song.126000.json','["導江自岷山，源淺觴可濫。", "下集大小川，千丈水府暗。", "策策井桐寒，炯炯窗月淡。", "後生抱奇志，黄墨勤點勘。"]'),
('dd645351-c54a-42ef-9cb9-b48d6c285e5e','秋懷六首  其四','洪邁','宋','宋诗','song-poetry','','[]','市朝富危機，匹夫死馮河。',48,'全唐诗/poet.song.126000.json','["市朝富危機，匹夫死馮河。", "何如狎鷗子，烟雨同一波。", "行藏各有趣，不在相詆訶。", "我師陋巷人，千古冠四科。"]'),
('d5acce28-f82b-44b1-97f2-2520609a0e4e','秋懷六首  其五','洪邁','宋','宋诗','song-poetry','','[]','穿堵超玉繩，倒影夜窗寂。',48,'全唐诗/poet.song.126000.json','["穿堵超玉繩，倒影夜窗寂。", "火雲一洗空，月露清欲滴。", "幽人負疴卧，起坐三歎息。", "歸同對牀笫，晤語永佳夕。"]'),
('7fc7756f-e326-47d6-9261-f35d7e90fc53','秋懷六首  其六','洪邁','宋','宋诗','song-poetry','','[]','掩窗耿不寐，道人亦無悰。',48,'全唐诗/poet.song.126000.json','["掩窗耿不寐，道人亦無悰。", "故山新稻香，粥曾警枯桐。", "夢中信了了，推枕聞西風。", "少遲穉金壯，歸善與子同。"]'),
('a3c7a825-164b-4bab-85c0-9de48e8b4d38','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其一','洪邁','宋','宋诗','song-poetry','','[]','丈室掩槐夏，與君同卧疴。',48,'全唐诗/poet.song.126000.json','["丈室掩槐夏，與君同卧疴。", "平生莫逆人，裹飯誰見過。", "跰𨇤起鑑井，萬古寂不波。", "觀心要知是，造物如吾何。"]'),
('e76dfb00-ed2d-4212-a555-1533ccf44c8b','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其二','洪邁','宋','宋诗','song-poetry','','[]','六年別故山，松竹故無恙。',48,'全唐诗/poet.song.126000.json','["六年別故山，松竹故無恙。", "此身已天涯，飄走復何向。", "清源老醫師，砭樓出投狀。", "勿辭一往勤，挹彼上池漲。"]'),
('69284e9e-d0bb-4e62-9310-15b7197cabe5','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其三','洪邁','宋','宋诗','song-poetry','','[]','石梁跨蠔山，永與方壺久。',48,'全唐诗/poet.song.126000.json','["石梁跨蠔山，永與方壺久。", "憑君持一盃，往酹濟川手。", "遥知相携處，溟渤浸箕斗。", "作詩問大鈞，猶有斯人否。"]'),
('b7927b1b-cc86-4260-a93c-aaa809693088','逢年與德粲同之溫陵謁大智禪師醫作四小詩送之  其四','洪邁','宋','宋诗','song-poetry','','[]','山河我四大，物我同一體。',48,'全唐诗/poet.song.126000.json','["山河我四大，物我同一體。", "誰爲苦疾痒，搔按不容擬。", "多生抱此念，耿耿未云已。", "那知知魚樂，更有濠梁子。"]'),
('b5a05d1b-551e-4907-b3c3-2cb0ae39889f','與陳彥時會華嚴道人偶書','洪邁','宋','宋诗','song-poetry','','[]','屋頭烟雲屯，屋下波濤諠。',264,'全唐诗/poet.song.126000.json','["屋頭烟雲屯，屋下波濤諠。", "團圞坐已久，起扣丹霞門。", "客至苦舌强，目擊翻無言。", "元龍湖海士，懷哉夙契敦。", "清坐鼎足峙，妙語流潺湲。", "君游華嚴海，貝葉手自翻。", "此心於身世，鳥度空無痕。", "笑吾流浪中，久被業識吞。", "讀書談古今，綺語生禍根。", "望道渺未見，況乃躐其藩。", "職卑困掣肘，見溺不得援。", "未知造物心，頗復哀黎元。", "近窺賢稷意，未敢遽掩關。", "躬耕亦細事，會要五畝園。", "釋羈牛在牧，駕鼓馬伏轅。", "居然見優劣，不比魚熊膰。", "持問跏趺人，一笑霜眉掀。", "相携妙峰頂，暝色窺遠村。", "解衣略輩行，班坐搴芳蓀。", "欲歸意未已，幽徑相與捫。", "蒼崖出玉醴，不受瘴毒溫。", "願言同酌此，我語庶不諼。"]'),
('6780a84d-3e10-459f-baea-ad334418ea18','書栟櫚院壁','洪邁','宋','宋诗','song-poetry','','[]','側身西來度千山，列仙仙去空孱顔。',64,'全唐诗/poet.song.126000.json','["側身西來度千山，列仙仙去空孱顔。", "斗升自役應笑我，何苦詰曲戲塵寰。", "歸耕無田仕難合，疑此二柄首尾間。", "摩挲崖石三歎息，我心安得如汝頑。"]'),
('0c51100b-fa21-4db1-ac4c-4b263f220086','次志宏韻督成壽置酒','洪邁','宋','宋诗','song-poetry','','[]','歸耕食吾言，回首媿江水。',144,'全唐诗/poet.song.126000.json','["歸耕食吾言，回首媿江水。", "方爭揚子席，誰置穆生醴。", "鄧侯傾蓋舊，小寢藝桃李。", "走書約啗我，涎迸齧脣齒。", "朝來獨何事，怒色劇染指。", "雖微射鴻游，顧有捩手鬼。", "平生談天口，得酒便鋒起。", "年來病不觴，但要謳貼耳。", "真成畫蛇足，足就酒空矣。", "樊川吐怨句，想見紫雲美。", "何時咄嗟辦，一醉吾亦擬。", "噂沓聽羣兒，口實爭笑鄙。"]'),
('36616738-3a85-44e8-961c-eef3f6ad1b8d','寄題分繡閣','洪邁','宋','宋诗','song-poetry','','[]','新閣何隆隆，經營自茲歲。',96,'全唐诗/poet.song.126000.json','["新閣何隆隆，經營自茲歲。", "其前山送青，其下竹交翠。", "景物日夕佳，登臨春秋異。", "治中公事暇，領客共留憩。", "四座歡相酬，壽主珍重意。", "向來蓬瀛上，視此毋乃媿。", "主稱客意好，是事幸且置。", "拄頰飽看山，朝來殊爽致。"]'),
('93b7a13c-369a-47dc-b74b-ce5844f56e7e','送制置使王剛中帥蜀','洪邁','宋','宋诗','song-poetry','','[]','上都門外垂楊陌，葉葉經霜不堪折。',128,'全唐诗/poet.song.126000.json','["上都門外垂楊陌，葉葉經霜不堪折。", "春光猶未到梅花，何物當扳送行客。", "路人驚問去者誰，高牙大纛爭光輝。", "君王應念蜀父老，故輟侍臣來紫微。", "明光起草文章手，却聽元戎報刁斗。", "回首翔鸞一夢中，玉簫緩送成都酒。", "邛郲九折何足驅，慷慨功名真丈夫。", "成都花錦君莫戀，早晚歸凱持鈞樞。"]'),
('098d591f-3ea0-40f2-8982-409f5969ca57','車駕幸玉津園晚歸進詩','洪邁','宋','宋诗','song-poetry','','[]','五更猶自雨如麻，無限都人仰翠華。',64,'全唐诗/poet.song.126000.json','["五更猶自雨如麻，無限都人仰翠華。", "翻手作雲方悵望，舉頭見日共驚嗟。", "天公的有施生妙，帝力堪同造物誇。", "上苑春光無盡藏，何須羯鼓更催花。"]'),
('3ab528f4-6f56-4d66-961a-55a3af9f023e','王龜齡王嘉叟木藴之同過小園用郡圃植花韻','洪邁','宋','宋诗','song-poetry','','[]','節到中和暖尚賒，東風隨處起芳華。',64,'全唐诗/poet.song.126000.json','["節到中和暖尚賒，東風隨處起芳華。", "自慙翳翳松三逕，相對蕭蕭馬五花。", "老去醉鄉爲日月，年來痼疾在烟霞。", "午橋別墅歸公手，早定淮西取白麻。"]'),
('f9bc572f-524a-4c5a-828f-90166061ba03','送楊簡遷國子博士','洪邁','宋','宋诗','song-poetry','','[]','楊君解墨綬，去作國子師。',180,'全唐诗/poet.song.126000.json','["楊君解墨綬，去作國子師。", "邑人十萬戶，遮道嬰兒啼。", "曩歲天旱苦，赤地無餘遺。", "饑殍千百輩，上山爭採薇。", "採薇有時盡，詎能救長饑。", "慨然顧自任，舍我將告誰。", "昧爽出廳事，日暮忘旋歸。", "大家貯陳粟，出糶不敢遲。", "偷兒紛狗鼠，鋤治如平時。", "一意摩手撫，如子得母慈。", "明年麰麥登，比屋無流移。", "史牒載循吏，于今親見之。", "我亦受一廛，惜哉輕語離。", "橋山未迄役，酌餞疎酒巵。", "聊述路人頌，持作送君詩。"]'),
('5b5cfdf0-3e8b-4a1a-becc-195f8a40acb1','朝天菊','洪邁','宋','宋诗','song-poetry','','[]','但見荼䕷能上架，那知甘菊解朝天。',32,'全唐诗/poet.song.126000.json','["但見荼䕷能上架，那知甘菊解朝天。", "亭亭秀出風烟上，冷落東籬却可憐。"]'),
('58fde818-2650-46ad-9361-e918565b48a2','與葉晦叔同考校諸生鎖宿貢院作','洪邁','宋','宋诗','song-poetry','','[]','沈沈廣厦清如水，市聲人聲不到耳。',160,'全唐诗/poet.song.126000.json','["沈沈廣厦清如水，市聲人聲不到耳。", "一閒十日豈天賜，慙媿紛紛白袍子。", "相逢更得金玉人，久矣眼中無此士。", "連牀夜語不成寐，往往鷄聲忽驚起。", "是中差樂真難名，昔者相過安得此。", "但憐時節不相謀，正墮清明寒食裏。", "梨花已空海棠謝，外間物色知餘幾。", "只恐風雨摧折之，負此一春吾過矣。", "謝公尋山飽閒暇，應笑腐儒黏故紙。", "錦囊得句應已多，萬一相思頻寄似。"]'),
('9ffc7442-27ca-428d-946d-c9e564d02ec0','上清宮','洪邁','宋','宋诗','song-poetry','','[]','振策衝暮雲，携琴宿仙境。',108,'全唐诗/poet.song.126000.json','["振策衝暮雲，携琴宿仙境。", "松風生夜凉，蘿月散秋影。", "洞遠落猿聲，溪清鳴鶴頂。", "中宵夢仙翁，乘車停翠嶺。", "獅子身五色，鸞鳳互相引。", "上有朱幡幢，金碧不可省。", "風吹雲璈徧，顧我忽而哂。", "遺以丹篆文，再拜豁心領。", "明當謝浮榮，飄然從結軫。"]'),
('a41bb03c-6a15-46df-ac92-39c4d970655c','和朱子淵石柏詩','洪邁','宋','宋诗','song-poetry','','[]','海底靈根石效奇，山經地志不曾知。',64,'全唐诗/poet.song.126000.json','["海底靈根石效奇，山經地志不曾知。", "凝紅幻出珠千顆，染紫裝成玉一枝。", "鶴骨龍姿隨質見，鸞棲鳳宿與香宜。", "元戎高唱真難和，愧我年來筆力衰。"]'),
('d2fca888-8bbe-4305-9c0a-1695f3affab3','宣瑣','洪邁','宋','宋诗','song-poetry','','[]','禁門深鎖寂無譁，濃墨淋漓兩相麻。',32,'全唐诗/poet.song.126000.json','["禁門深鎖寂無譁，濃墨淋漓兩相麻。", "唱徹五更天未曉，一池月浸紫薇花。"]'),
('9b2bd11a-6056-4c05-97f0-b8e7f7ad49ea','琵琶亭','洪邁','宋','宋诗','song-poetry','','[]','香山居士頭欲白，秋風吹作湓城客。',128,'全唐诗/poet.song.126000.json','["香山居士頭欲白，秋風吹作湓城客。", "眼看世事等虛空，雲夢胸中無一物。", "舉觴獨醉天爲家，詩成萬象遭梳爬。", "不管時人皆欲殺，夜深江上聽琵琶。", "賈胡老婦兒女語，淚濕青衫如著雨。", "此公豈作少狂夢，與世浮沉聊爾汝。", "我來後公三百年，潯陽至今無管絃。", "長安不見遺音寂，依舊康廬翠掃天。"]'),
('b9b9e7a6-eb9a-42f2-ad5a-9be0e298702e','清閟堂','洪邁','宋','宋诗','song-poetry','','[]','昔聞王子猷，借宅亦種竹。',96,'全唐诗/poet.song.126000.json','["昔聞王子猷，借宅亦種竹。", "此君固可喜，人亦清不俗。", "伯氏貧而癯，一飯不飽肉。", "堂前自經始，護此無盡綠。", "一官歲强半，餘日如轉燭。", "待其長稚子，而已牽歸轂。", "何由享嘉蔭，償我志願足。", "應煩彼邦人，日報平安幅。"]'),
('977e644a-6c0f-4706-b35a-5f74d22b0482','有懷大兄正字','洪邁','宋','宋诗','song-poetry','','[]','今日思兄弟，江東望浙東。',48,'全唐诗/poet.song.126000.json','["今日思兄弟，江東望浙東。", "別離無奈久，書札且頻通。", "雨溼芭蕉碧，風乾薜荔紅。", "何時尊酒共，夜語小窗中。"]'),
('13899f3d-2e7a-423a-888b-cdb94256f8c7','峽州','洪邁','宋','宋诗','song-poetry','','[]','自昔夷陵爭戰地，時平不復問干戈。',32,'全唐诗/poet.song.126000.json','["自昔夷陵爭戰地，時平不復問干戈。", "三游洞裏尋遺跡，至喜亭前足雅歌。"]'),
('69933cac-e15c-4d46-a5f1-4a1072b8ba3b','赴建安守泛舟游九曲','洪邁','宋','宋诗','song-poetry','','[]','武夷之山如畫圖，中有玉洞藏仙都。',160,'全唐诗/poet.song.126000.json','["武夷之山如畫圖，中有玉洞藏仙都。", "一溪穿空舞澎湃，九曲度盡方盤紆。", "細看直疑路中斷，已轉始覺川平鋪。", "諸峯削成鳥亦怖，危磴豈復人能踰。", "機巖學館第傳授，鼓樓石牀知有無。", "坐令丹梯化一鶴，又喚立筍成三姑。", "遊人來觀但借問，道士指說猶驚呼。", "神君曾孫在何許，想見幔亭空藥爐。", "千崖萬壑心賞倦，正喜松風清坐隅。", "歸舟瞥然箭脫手，醉目眩我雙明珠。"]'),
('6476ccdb-4721-4b2f-bd4c-c9a9972305d7','詩一首','洪邁','宋','宋诗','song-poetry','','[]','集仙仙客問生涯，買得漁舟度歲華。',32,'全唐诗/poet.song.126000.json','["集仙仙客問生涯，買得漁舟度歲華。", "案有黄庭尊有酒，少風波處便爲家。"]'),
('90a9b74f-a6a6-4424-8915-e926ab3de14c','送王龜齡自著作丞外補','洪邁','宋','宋诗','song-poetry','','[]','不奈諸公厭石渠，年年送客意何如。',64,'全唐诗/poet.song.126000.json','["不奈諸公厭石渠，年年送客意何如。", "直言飽誦劉蕡策，大意爭傳賈誼書。", "今日朝廷唯主聖，異時風俗要人鉏。", "須君早晚歸遺補，莫戀王門久曳裾。"]'),
('abcde4f0-4827-4428-88fe-38fee5c71b5f','送沈虞卿秘監將漕江東二首  其一','洪邁','宋','宋诗','song-poetry','','[]','天上圖書羣玉府，仙晨日月道家山。',64,'全唐诗/poet.song.126000.json','["天上圖書羣玉府，仙晨日月道家山。", "行行合在煙霄地，去去猶參論譔班。", "使者繡衣看更好，從官華橐未應慳。", "褰帷了却江東事，不到終更便賜環。"]'),
('00f92636-7ad0-4d0a-9694-d9e49aae957d','送沈虞卿秘監將漕江東二首  其二','洪邁','宋','宋诗','song-poetry','','[]','無復同趨尺五天，湖山佳處想聯翩。',64,'全唐诗/poet.song.126000.json','["無復同趨尺五天，湖山佳處想聯翩。", "看君揮手謝送者，使我銷魂惟黯然。", "閃雨不成張祖席，停雲空自寄詩篇。", "過家莫作多時住，聞道東人正可憐。"]'),
('5c291922-210c-43ba-a6f3-d1cb3f417a2d','送通判范朝散秩滿造朝  其一','洪邁','宋','宋诗','song-poetry','','[]','打鼓發姑孰，送君朝帝鄉。',48,'全唐诗/poet.song.126000.json','["打鼓發姑孰，送君朝帝鄉。", "風流夸半刺，耆舊憶襄陽。", "別酒不成醉，征途能底忙。", "只應旗脚轉，趁此麥天凉。"]'),
('443298b9-8b8c-4a44-ba44-a4dc6bb4bb47','送通判范朝散秩滿造朝  其二','洪邁','宋','宋诗','song-poetry','','[]','我欲菟裘老，推排强典州。',48,'全唐诗/poet.song.126000.json','["我欲菟裘老，推排强典州。", "同官有才俊，坐嘯得遨遊。", "便作烟霄去，知難郡縣留。", "畫船看不見，江水自東流。"]'),
('ed1c4f4f-d73d-4a70-bd0a-f53d7ac70b01','送王誠之舍人使北方得揮字','洪邁','宋','宋诗','song-poetry','','[]','歲晏滯急景，霜雪日霏霏。',120,'全唐诗/poet.song.126000.json','["歲晏滯急景，霜雪日霏霏。", "家居尚無奈，何况披征衣。", "舍人使持節，正爾辭帝畿。", "揚鞭出門去，言面無幾微。", "中朝第一人，沙漠今宣威。", "朔庭天驕子，應覺眼見希。", "青春反南轅，花柳相光輝。", "雍容對宣室，便可持樞機。", "蛾眉含笑迎，酌酒爭勞歸。", "金碗大如斗，客醉時一揮。"]'),
('6d05e8b0-3946-465b-90a2-daa58751edf2','送王舍人制置四川','洪邁','宋','宋诗','song-poetry','','[]','昭代推人傑，誰登上將壇。',240,'全唐诗/poet.song.126000.json','["昭代推人傑，誰登上將壇。", "君王念方面，侍從輟儒冠。", "魏闕成高拱，梁州遠監觀。", "九天開幕府，萬里入征鞍。", "往昔先多士，歸歟樂考槃。", "中年思賈誼，見晚歎嚴安。", "禁掖侵霄漢，秋空刷羽翰。", "文章變龍虎，班級上鴛鸞。", "謀帥西南急，登庸歲月寬。", "智謀回睿眷，節制妙朝端。", "風采今如此，家聲定不刊。", "雪山方始重，蜀道幾曾難。", "地迥江驚急，雲孤峽怒蟠。", "梅花春欲動，水國暮生寒。", "行路艱初起，籌邊策未殫。", "郫筒無惜醉，岷芋且加餐。", "鄉曲霑投分，蓬萊忝備官。", "丹心空自喜，青眼獨相看。", "此地從公別，何時話夜闌。", "歸來消息近，鵬背一朝摶。"]'),
('1eb618a1-8c5b-4dca-a018-1fa6b6dc0931','邢臺懷古','洪邁','宋','宋诗','song-poetry','','[]','蕞爾邢侯國，巍然昭義軍。',48,'全唐诗/poet.song.126000.json','["蕞爾邢侯國，巍然昭義軍。", "未能爲晉重，忽已被梁分。", "壤沃連三郡，時移出四君。", "蒼茫懷古意，群醜謾紛紜。"]'),
('5d9bfb01-e9bb-477a-9a8c-b1cb0a418eda','自鳴山','洪邁','宋','宋诗','song-poetry','','[]','文安陸子幽棲日，張氏諸賢盡執經。',64,'全唐诗/poet.song.126000.json','["文安陸子幽棲日，張氏諸賢盡執經。", "自昔衣冠儀里閈，至今詩禮擅家庭。", "巖陰夏閣風泉白，溪曲春疇雨稻青。", "天上真人躡鳬舄，移文休勒此山名。"]'),
('eaf284a0-e0c9-4ae7-b405-d16ffc4104b0','題蔣億極目樓','洪邁','宋','宋诗','song-poetry','','[]','樓下高低萬井煙，樓頭極目思悠然。',64,'全唐诗/poet.song.126000.json','["樓下高低萬井煙，樓頭極目思悠然。", "山圍風景無餘地，戶接星河不盡天。", "閩嶺百重通北路，楚江千里繫東船。", "客星先自留連在，慚愧郎官葉縣賢。"]'),
('dd8d0aa3-00b0-46ad-a38e-06b07673f6a7','野處亭','洪邁','宋','宋诗','song-poetry','','[]','莫厭攻臺萬杵聲，芝亭入望得雙聲。',64,'全唐诗/poet.song.126000.json','["莫厭攻臺萬杵聲，芝亭入望得雙聲。", "快邀明月無餘地，俯瞰澄江不礙城。", "花雨著人迷杖屨，松風呼夢遶廂榮。", "弟兄丘壑平生事，付與鳴琴一再行。"]'),
('dbf42a64-a0c4-4cde-80df-fe29f6f0731f','剩溪別墅','洪邁','宋','宋诗','song-poetry','','[]','龍停休憶柳垂堤，正喜高風集剩溪。',64,'全唐诗/poet.song.126000.json','["龍停休憶柳垂堤，正喜高風集剩溪。", "流水直隨青嶂下，孤烟更在白雲西。", "村舂接響聲相赴，浦樹連雲望自迷。", "無限新詩兼有酒，可能容我醉時題。"]'),
('b7a58a62-bddf-445a-87c9-fd32fe9ec662','秀川館聯句','洪邁','宋','宋诗','song-poetry','','[]','江聲牀摇寒，山色窗拗綠。',288,'全唐诗/poet.song.126000.json','["江聲牀摇寒，山色窗拗綠。", "歸舟著沙邊，客夢遶鄉曲。", "簪盍豁秋悲，筵開從夜卜。", "黄花散疎籬，蒼竹圍破屋。", "詩豪爭擊銅，談劇屢消燭。", "借君五言城，洗我萬斛愁。", "主人意無窮，客子去敢速。", "杯寬怯鯨吞，詞澀媿貂續。", "注瓦亦傾銀，聯珠仍綴玉。", "天迥月明洲，霜清風隕木。", "飛齊水擊鵬，揮退日斜鵩。", "臭味漆投膠，芬芳蘭間菊。", "味甘一臠嘗，話勝十年讀。", "未用賦驪駒，方看舉鴻鵠。", "行當歲九遷，勿憚晝三宿。", "妙語子蟬嫣，孤蹤吾鹿獨。", "一老上星辰，三君進鳬鶩。", "平生仰高山，此夕霑賸馥。", "飛龍十九章，金馬三千牘。", "儻非論石渠，定是讐天祿。", "筆健翻狂瀾，辯雄噴飛瀑。", "抄傳疲小胥，侍立倦更僕。", "力舉六鼇連，肘運千兔禿。", "庖厨洗玉盤，萍豆鄙金谷。"]'),
('00371b56-70d5-4047-938a-1f6f392b4d66','句  其一','洪邁','宋','宋诗','song-poetry','','[]','願儲醫國三年艾，不博江心百鍊銅。',16,'全唐诗/poet.song.126000.json','["願儲醫國三年艾，不博江心百鍊銅。"]'),
('6264e415-5a87-41ff-be7b-79262f5fc543','句  其二','洪邁','宋','宋诗','song-poetry','','[]','天上長留滕六在，人間會有葛三來。',16,'全唐诗/poet.song.126000.json','["天上長留滕六在，人間會有葛三來。"]'),
('ee7b3f62-62c8-48dc-877c-937b7f684a82','句  其三','洪邁','宋','宋诗','song-poetry','','[]','居然丈室巧剸裁，截竹爲楹不染埃。',16,'全唐诗/poet.song.126000.json','["居然丈室巧剸裁，截竹爲楹不染埃。"]'),
('914411fb-900f-4247-a7d3-ea82d8e622a6','句  其四','洪邁','宋','宋诗','song-poetry','','[]','懷人空結九回腸。',8,'全唐诗/poet.song.126000.json','["懷人空結九回腸。"]'),
('ca8bb488-67cd-434f-abec-ee70db6015a1','句  其五','洪邁','宋','宋诗','song-poetry','','[]','謾遶清流欲浣衣。',8,'全唐诗/poet.song.126000.json','["謾遶清流欲浣衣。"]'),
('cbb249d0-a343-47a7-954f-c802f80f1219','留別龍隠巖','許子紹','宋','宋诗','song-poetry','','[]','矯首初來北斗峰，直穿山腹作玲瓏。',64,'全唐诗/poet.song.126000.json','["矯首初來北斗峰，直穿山腹作玲瓏。", "石間蛻骨痕猶在，淵底藏珠水更通。", "霖雨幾時岩墅去，卧龍底處草廬空。", "眼中要識真英物，寓迹何勞想下風。"]'),
('65f339ee-7739-43dc-91d7-ed4065a79280','秀川館聯句','許子紹','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.126000.json','["無正文。"]'),
('8cb2cae6-6286-4e81-933b-e1eeeb005c5d','秀川館聯句','黄介','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.126000.json','["無正文。"]'),
('76db7fb4-730b-4ef2-a5c1-2bda1c9f3e3e','故舊相送出城門','黄介','宋','宋诗','song-poetry','','[]','策馬國門南，行役感時節。',96,'全唐诗/poet.song.126000.json','["策馬國門南，行役感時節。", "唧唧寒螿亂，皎皎層巒潔。", "脩途遵廣川，衰林夕陽滅。", "含情不忍語，眷舊詎忍別。", "抱疴謝紱冕，寄情戀巖穴。", "樹臨越海潮，山背吳門雪。", "各勉疇昔心，音書戒遼絕。", "儻訊幽栖子，杜關理丹訣。"]'),
('459a589c-78d6-4a08-a204-e42b105005dd','皇太后輓歌','黄介','宋','宋诗','song-poetry','','[]','夾日光先業，寒星聚夜臺。',48,'全唐诗/poet.song.126000.json','["夾日光先業，寒星聚夜臺。", "慈名千古重，哀詔九天來。", "地底雞人少，雲中鶴使催。", "宮門芳草遍，從此不須開。"]'),
('5fdeaca7-49c0-4d58-a2e3-9e7377909484','秋日看雲','黄介','宋','宋诗','song-poetry','','[]','曉雨沾山路，秋雲看野亭。',48,'全唐诗/poet.song.126000.json','["曉雨沾山路，秋雲看野亭。", "薄從川上起，低向屋邊停。", "合處山林白，消來天地青。", "人生無定跡，不止是浮萍。"]'),
('48504a69-8a33-4352-af17-d54a16507f61','老妓自稱汴京宮人泣而贈之','黄介','宋','宋诗','song-poetry','','[]','薄粧自敘老深宮，一曲悲歌聽不終。',64,'全唐诗/poet.song.126000.json','["薄粧自敘老深宮，一曲悲歌聽不終。", "黑髮尚沾梁苑雪，素衣還带上林風。", "殘春柳葉蕭條綠，破國桃花冷落紅。", "收拾琵琶蹙眉黛，教人同在淚痕中。"]'),
('273a2972-b2d0-4f40-b996-abe48adf01db','宿直留詩','程大昌','宋','宋诗','song-poetry','','[]','抖擻身章却冒塵，褭蹏顧影也逡巡。',64,'全唐诗/poet.song.126000.json','["抖擻身章却冒塵，褭蹏顧影也逡巡。", "鑾坡寓宿非其地，蓮燭操文自有真。", "字直由來同古語，位高兼復見今人。", "迎潮有諾無輕爽，季老當年不諉貧。"]'),
('4769f300-b578-44cf-af65-1ecb0800ceae','次韻陸務觀海棠','程大昌','宋','宋诗','song-poetry','','[]','喚回殘睡强矜持，淺破朱脣倚笛吹。',32,'全唐诗/poet.song.126000.json','["喚回殘睡强矜持，淺破朱脣倚笛吹。", "千古妖妍磨不盡，長隨春色上花枝。"]'),
('2c1a7620-4dc1-4e5f-921f-3d74cf047f59','高宗皇帝挽詞  其一','程大昌','宋','宋诗','song-poetry','','[]','先漢運嘗屯，令周曆再新。',48,'全唐诗/poet.song.126000.json','["先漢運嘗屯，令周曆再新。", "必知天地泰，爲有帝王真。", "立極綿三紀，垂鴻更萬春。", "鼎龍俄夭矯，昇鶴肯逡巡。"]'),
('117d1139-8403-4ea4-984c-37d35f44ae24','高宗皇帝挽詞  其二','程大昌','宋','宋诗','song-poetry','','[]','英明如藝祖，慈厚類仁宗。',48,'全唐诗/poet.song.126000.json','["英明如藝祖，慈厚類仁宗。", "民隠深憂惻，天驕入益容。", "前芳嘗北指，鳴鏑自回功。", "戢動皆時當，居然八政農。"]'),
('a1c8ab76-3fc4-4d88-9ca7-06b8c888d2e5','高宗皇帝挽詞  其三','程大昌','宋','宋诗','song-poetry','','[]','智超黄屋表，不以位爲怡。',48,'全唐诗/poet.song.126000.json','["智超黄屋表，不以位爲怡。", "罷省齋居事，安持壽殿巵。", "尊榮天子父，巍煥聖王師。", "盛德幾無古，惟堯始濟茲。"]'),
('3862893a-e1a2-4412-b600-6cf2ff91e920','高宗皇帝挽詞  其四','程大昌','宋','宋诗','song-poetry','','[]','九齡幾協夢，三載忽纏喪。',48,'全唐诗/poet.song.126000.json','["九齡幾協夢，三載忽纏喪。", "地卜周巡舊，山因禹穴傍。", "雲卿飛步闊，風沛著思長。", "八表神遊處，天高鞏洛陽。"]'),
('7a3a9674-d104-4b1a-8053-04a06d7b87b2','次林光朝八月十五日道出南昌寄龔帥實之韵','程大昌','宋','宋诗','song-poetry','','[]','聞有挐音掃榻埃，尚疑却棹酒船回。',64,'全唐诗/poet.song.126000.json','["聞有挐音掃榻埃，尚疑却棹酒船回。", "錦囊忽至詩傳諾，玉麈未交心已開。", "邂逅四人今楚尾，班聯十載舊蘭臺。", "尊前莫發粗官嘆，奇絕江山直一來。"]'),
('676d748f-d549-43b6-8346-c46785e7d2cf','和劉侍郎九日登女郎臺','程大昌','宋','宋诗','song-poetry','','[]','霜枝凋翠雁橫秋，莫倚危樓動旅愁。',32,'全唐诗/poet.song.126000.json','["霜枝凋翠雁橫秋，莫倚危樓動旅愁。", "菊有清香樽有酒，茱萸不插也風流。"]'),
('8aa06050-bf8a-4c73-a9b0-8199b75e7546','覓梅','程大昌','宋','宋诗','song-poetry','','[]','花中結子酸連骨，正味森嚴衆苦之。',32,'全唐诗/poet.song.126000.json','["花中結子酸連骨，正味森嚴衆苦之。", "待得和羹渠自會，如今莫管皺雙眉。"]'),
('7a190d12-e7f8-4b90-a6e7-73e50f3d837a','冬至','程大昌','宋','宋诗','song-poetry','','[]','世間剝復每相乘，此理幾幾喚得譍。',32,'全唐诗/poet.song.126000.json','["世間剝復每相乘，此理幾幾喚得譍。", "萬木凍僵梅有信，黄河冰合井如蒸。"]'),
('b8c49550-13dc-4ca9-af55-337b9378776f','句  其一','程大昌','宋','宋诗','song-poetry','','[]','著庭謹護籜龍兒，養就堅高抗雪姿。',16,'全唐诗/poet.song.126000.json','["著庭謹護籜龍兒，養就堅高抗雪姿。"]'),
('4e686bec-e8fb-44e4-92e9-2b3dabcdae70','句  其二','程大昌','宋','宋诗','song-poetry','','[]','有底滑稽堪羨處，金蓮燭裏話窮酸。',16,'全唐诗/poet.song.126000.json','["有底滑稽堪羨處，金蓮燭裏話窮酸。"]'),
('7fe7180e-3558-43fb-a88e-3d0f26f2eb10','句  其三','程大昌','宋','宋诗','song-poetry','','[]','戲作風枝斜，垂惱玉堂宿。',12,'全唐诗/poet.song.126000.json','["戲作風枝斜，垂惱玉堂宿。"]'),
('4a03aaef-f2b4-451c-9472-c13bcc2c0271','游碧落洞','釋希賜','宋','宋诗','song-poetry','','[]','難到不難到，一游成屢游。',48,'全唐诗/poet.song.126000.json','["難到不難到，一游成屢游。", "人間常拘束，物外恣冥搜。", "白隠團團露，清涵寸寸秋。", "丹砂無問處，騷客冷猿啾。"]'),
('3047248a-8e05-41a3-820d-bdd3910ee7a3','石龍泛海作','莫汲','宋','宋诗','song-poetry','','[]','一帆點破碧落界，八面展盡虛無天。',32,'全唐诗/poet.song.126000.json','["一帆點破碧落界，八面展盡虛無天。", "柂樓長嘯海波闊，今夕何夕吾其仙。"]'),
('893e655b-fc4a-4d2a-a85c-88b8ef23d11a','舟行江上','方汝疆','宋','宋诗','song-poetry','','[]','平林漠漠暝烟齊，竹樹蕭疏望眼迷。',32,'全唐诗/poet.song.126000.json','["平林漠漠暝烟齊，竹樹蕭疏望眼迷。", "相喚幾聲何處雁，斷霞明處一行低。"]'),
('1cd2ea38-4203-44cb-82a8-517fffb9cd8b','江上晚行','方汝疆','宋','宋诗','song-poetry','','[]','疏雲薄日冷吳江，江色蘆花共渺茫。',64,'全唐诗/poet.song.126000.json','["疏雲薄日冷吳江，江色蘆花共渺茫。", "四五點山烟靄淡，兩三枝槳水雲長。", "遊鱼避網驚微浪，幽鷺窺汀下夕陽。", "興罷歸來更回首，滿身明月踏溪霜。"]'),
('08bcab4a-ce5b-4fbe-978b-ed67e9b36ddb','江上晚望','方汝疆','宋','宋诗','song-poetry','','[]','柳邊茅舍倚漁磯，沙上輕禽貼水飛。',32,'全唐诗/poet.song.126000.json','["柳邊茅舍倚漁磯，沙上輕禽貼水飛。", "千頃夕陽秋練浄，誰家一葉晚來歸。"]'),
('4c35b202-1f44-4c3c-922d-350e9b3d905f','題萬壑風煙亭百韻','彭郁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','風在不周山空闕，底事問煙訪兩浙。',384,'全唐诗/poet.song.126000.json','["風在不周山空闕，底事問煙訪兩浙。", "煙生廬阜香爐峰，孰使隨風至吳越。", "風乎與煙相得外，還有風雷并雨雪。", "煙兮與風相好餘，仍有煙波及霞月。", "誰知此處一萬壑，祇樂風煙餘不說。", "括蒼攙天三百里，熊熊魂魂迷嵽嵲。", "蓋竹騰空一千丈，洩洩熒熒蜚崒嵂。", "洪濛霧氣蕩歸鴻，滉澒嵐芬惑回鷢。", "前岑不陣有旌旆，後岫無人何幕帟。", "𩅿霏冷逼盧橘秋，薄浥輕縑礲硉矹。", "䬌𪋖遥觸楊梅寒，細擗新綿摩崒屼。", "望海尖頭培塿細，盤匜瓊瑒高拋𥻦。", "帢幘巾邊花草蔫，彝博栴檀飄馥苾。", "劉晨長嘯出天台，填填浩氣陵寒䨚。", "王母馳車返玄圃，繽繽羽旆揮斜日。", "雙巖瑞巖插雲漢，寒䬝冷𩅀紛膠葛。", "大固小固竝闤闠，碧瓦青炊浮𩘹𩘐。", "黄巖洞裏石老人，曬袚兵編資飄䫻。", "白鶴山頭丁令威，清音嘹唳渾䫹䫾。", "玉帝盤桓石鼻宮，鬰葱佳氣浮山梲。", "天王宿留墉外岫，羽儀仙隊輝天閲。", "長河匹練耀白帝，鉅浸杯醪飲紅蜺。", "永慶憑陵睥睨寒，蒼狗白衣勞目刮。", "護郭崢嶸星斗爛，霧髻雲鬟誰指結。"]'),
('e8ca4b38-043a-4a43-9244-61a5e719de85','南張道中','釋曇瑩','宋','宋诗','song-poetry','','[]','北山松粉落輕黄，濯雨蝦鬚麥吐芒。',32,'全唐诗/poet.song.126000.json','["北山松粉落輕黄，濯雨蝦鬚麥吐芒。", "槐火石泉寒食後，十分春事屬農桑。"]'),
('4b2e8b5f-bacc-45a4-8dc3-4941f1964bf1','睡起','釋曇瑩','宋','宋诗','song-poetry','','[]','蕙帳煙凝晝掩關，落花時節雨闌珊。',32,'全唐诗/poet.song.126000.json','["蕙帳煙凝晝掩關，落花時節雨闌珊。", "客來驚起還鄉夢，繞屋春風綠樹寒。"]'),
('9bb1edcf-35cd-4a9c-b545-c1c1894ae504','姚江','釋曇瑩','宋','宋诗','song-poetry','','[]','沙尾鱗鱗水退潮，柳行出沒見漁樵。',32,'全唐诗/poet.song.126000.json','["沙尾鱗鱗水退潮，柳行出沒見漁樵。", "客船自載鍾聲去，落日殘僧立寺橋。"]'),
('6783eba6-4a99-4772-b811-53a14942c563','示超然上人','釋曇瑩','宋','宋诗','song-poetry','','[]','往事明明是夢中，髮霜那有舊形容。',32,'全唐诗/poet.song.126000.json','["往事明明是夢中，髮霜那有舊形容。", "客牀對卧秋深雨，聽得鄰僧半夜鍾。"]'),
('29005482-c416-4f33-b163-ff1b11248d44','宿香積寺','釋曇瑩','宋','宋诗','song-poetry','','[]','拂榻香凝夜，清眠擁衲衣。',48,'全唐诗/poet.song.126000.json','["拂榻香凝夜，清眠擁衲衣。", "五更聞喚起，一路聽催歸。", "山雨寒仍重，溪雲溼不飛。", "幽花短臨水，蜂蝶冷相依。"]'),
('14e98ce9-7140-407b-bab5-5d1ea43b4b7d','頌古二首  其一','釋曇瑩','宋','宋诗','song-poetry','','[]','溪山盡處夕陽斜，溪上冬風雪滿沙。',32,'全唐诗/poet.song.126000.json','["溪山盡處夕陽斜，溪上冬風雪滿沙。", "便是江南舊行路，和烟隔水見梅華。"]'),
('4c51f0d6-911c-4488-b081-c8bd41dd0898','頌古二首  其二','釋曇瑩','宋','宋诗','song-poetry','','[]','百結襴衫破幞頭，年年落第出神州。',32,'全唐诗/poet.song.126000.json','["百結襴衫破幞頭，年年落第出神州。", "却因一隻穿楊箭，臨老來封馬上侯。"]'),
('812d5428-8a54-4a99-ac35-a5fde2c264ab','句','釋惠臻','宋','宋诗','song-poetry','','[]','禍來患至不由人，土地伽藍固弗靈。',16,'全唐诗/poet.song.126000.json','["禍來患至不由人，土地伽藍固弗靈。"]'),
('9995eb25-972a-47f7-aea5-52ba8043b4d3','偈頌二首  其一','釋圓日','宋','宋诗','song-poetry','','[]','悟無不無，得無不得，九年面壁空勞力。',46,'全唐诗/poet.song.126000.json','["悟無不無，得無不得，九年面壁空勞力。", "三脚馿兒跳上天，泥牛入海無蹤跡。", "爲甚麽如此，九九八十一。"]'),
('530c0429-7d69-4b26-9d82-ffc287df384b','偈頌二首  其二','釋圓日','宋','宋诗','song-poetry','','[]','倒腹傾腸幾箇知，更無絲髮可相依。',32,'全唐诗/poet.song.126000.json','["倒腹傾腸幾箇知，更無絲髮可相依。", "直饒徹底承當去，也落他家第二機。"]'),
('6996d8aa-7e65-4abf-bbfe-0ad71dc12678','赤壁','曾用孫','宋','宋诗','song-poetry','','[]','白浪高於屋，風回熨帖平。',24,'全唐诗/poet.song.126000.json','["白浪高於屋，風回熨帖平。", "周郎呼不醒，久立聽江聲。"]'),
('48cefad3-7bc3-4e22-83a1-c2d3d8299285','題秦昌齡寫真','魚肉和尚','宋','宋诗','song-poetry','','[]','動著萬丈懸崖，不動當處沉埋。',44,'全唐诗/poet.song.126000.json','["動著萬丈懸崖，不動當處沉埋。", "彌勒八萬樓閣，擊著處處門開。", "會得紫羅帳裏事，不妨行處作徘徊。"]'),
('8151f882-00f1-4a48-9905-18a1feef6c35','游老君洞','張說','宋','宋诗','song-poetry','','[]','枕漱鑱鍼泉石肓，登臨又刮山川目。',240,'全唐诗/poet.song.126000.json','["枕漱鑱鍼泉石肓，登臨又刮山川目。", "太清飛出離宮景，平地分爲散仙福。", "知津有頼大夫松，避道尤勤居士木。", "層巒破曉霞散綺，斷岸涵空霧披縠。", "界遠都歸粟粒藏，脈近寧勞杖頭縮。", "不愁風引輕舟却，更喜村通小徑曲。", "妙含道德五千餘，迥出洞天三十六。", "青牛稅駕從嬾卧，寶猊回拱長蹲伏。", "猶餘砥室燦金星，安用柔宗扶玉局。", "巖前日月自朝夕，物外乾坤豈寒燠。", "蛇靈必化第須時，豹隠唯鄰聊協卜。", "共知容與樂無限，誰想緒餘善非獨。", "兩柱擎天壽八荒，一水爲霖登百穀。", "深嗟晚到償疇昔，爭忍疎游逾信宿。", "癡兒浪作謝鯤圖，坐進因明天下谷。"]'),
('5b694b7e-5f13-4321-a20b-83003d8389ac','讀中興碑','秋隠里叟','宋','宋诗','song-poetry','','[]','辭本春秋作，聱翁策固長。',24,'全唐诗/poet.song.126000.json','["辭本春秋作，聱翁策固長。", "漫嗟褒貶迹，孰繼老汾陽。"]'),
('be1ca53b-4ace-4800-8b9e-5e5617fc5549','讀許右丞所作陳少陽諫議哀詞','劉鄂','宋','宋诗','song-poetry','','[]','并州更作桑乾客，道逢舍者來爭席。',288,'全唐诗/poet.song.126000.json','["并州更作桑乾客，道逢舍者來爭席。", "掀髯對座有鉅人，開口劇談如舊識。", "試問客子從何方，興言扼腕微有傷。", "吾祖昔遑卹緯計，屢以直論干君王。", "讒諛弄國賢者避，禍福相乘呼吸異。", "懸知必有代庖責，被髮纓冠赴東市。", "大明既爭日月光，真與天地同久長。", "嗟予之生後長者，却識前輩奚其詳。", "大臣罔上擅行戮，揚以浮言蓋私曲。", "誅姦發德示後世，右丞之文端可復。", "中興名門凡幾門，聖朝報稱非少恩。", "紈蘭袖出承命帖，猶幸及識公之孫。", "春秋愛賢許之宥，十世已往未爲厚。", "况今公議方大明，叩天大叫君無後。", "故人夢想規大賢，景仰高行思執鞭。", "典刑方及見故物，倏爾長別良依然。", "土田未足爲君勸，官爵未足酬君願。", "行矣志意勿倦遊，歸而視之有家傳。"]'),
('cfaa361b-fcc7-41ec-acdc-3914a054ebf6','登般若臺','趙彥齡','宋','宋诗','song-poetry','','[]','撥置文書强作閒，佩壺聊得共躋攀。',32,'全唐诗/poet.song.126000.json','["撥置文書强作閒，佩壺聊得共躋攀。", "歸雲不識游人意，遮盡江南一带山。"]'),
('979cc8ff-8fd4-4790-a00f-de9764ac209c','題巾山','趙彥齡','宋','宋诗','song-poetry','','[]','一夜空山聞杜鵑，落花流水兩茫然。',32,'全唐诗/poet.song.126000.json','["一夜空山聞杜鵑，落花流水兩茫然。", "憑欄不覺春歸去，目極平蕪綠際天。"]'),
('a6805950-67dd-4294-8812-8d5be8a6cd8b','題南峰精舍藍光軒','趙彥齡','宋','宋诗','song-poetry','','[]','一溪带郭靜潺湲，寺在溪旁碧岫巔。',64,'全唐诗/poet.song.126000.json','["一溪带郭靜潺湲，寺在溪旁碧岫巔。", "塔影遠連空翠塢，鐘聲高入蔚藍天。", "竹房僧定侵窗月，沙步人稀滿樹烟。", "剛被名韁挽歸去，久居應作地行仙。"]'),
('5a0409e5-27f6-4134-8182-758ac358f993','題石洞','曹冠','宋','宋诗','song-poetry','','[]','茲山融結幾千年，天劃神剜巧自然。',64,'全唐诗/poet.song.126000.json','["茲山融結幾千年，天劃神剜巧自然。", "瀑派星河飛雪練，桂分月窟聳雲烟。", "人疑蓋竹舊福地，我道金華小洞天。", "乘興登臨供勝賞，依然身是十洲仙。"]'),
('3d7ce7bd-9839-4684-8f21-0a07425e83f9','涵碧亭  其一','曹冠','宋','宋诗','song-poetry','','[]','翠巖森秀爽，蟠結混沌初。',168,'全唐诗/poet.song.126000.json','["翠巖森秀爽，蟠結混沌初。", "唐朝遇藻鑑，勝景方發舒。", "飛泉注碧潭，流觴繞雙魚。", "烟霏足奇態，雅稱幽人居。", "劉郎賦丹青，詩思尚有餘。", "使其親拭目，發興當何如。", "年來頗湮厄，亭館幾邱墟。", "寺僧殺風景，古木半剪除。", "騷人罷登臨，過客徒欷歔。", "物理不終否，蓬藋新芟鋤。", "松篁亦欣榮，垂條再扶疏。", "伊余事幽討，徙倚聊與娛。", "寄傲引壺觴，招隠携琴書。", "涓辰此卜築，何羨諸葛廬。"]'),
('3d2015ed-c248-4033-b5a8-97872934e053','涵碧亭  其二','曹冠','宋','宋诗','song-poetry','','[]','平生事澹泊，榮利不關心。',96,'全唐诗/poet.song.126000.json','["平生事澹泊，榮利不關心。", "杜門久謝客，豈容俗塵侵。", "令尹有佳招，聯轡游雲林。", "流觴遶雙魚，茂樾棲幽禽。", "揮毫寫佳句，騷雅寓意深。", "玎璫泉聲玉，瑣碎竹影金。", "開懷拚劇飲，預約盟再尋。", "搔首賡險韻，杜陵不勝簪。"]'),
('60d1f8fe-7ed0-413b-958b-04d3e87befd8','涵碧亭  其三','曹冠','宋','宋诗','song-poetry','','[]','杖藜乘興縱幽尋，野寺松篁藹翠陰。',64,'全唐诗/poet.song.126000.json','["杖藜乘興縱幽尋，野寺松篁藹翠陰。", "流水潺湲如有恨，白雲舒卷本無心。", "龍鍾誰識天津叟，高卧曾爲梁甫吟。", "靜奏瑶琴聊自適，祇應風月是知音。"]'),
('8dbfb896-ecb3-4543-bfdb-2e0032091eb6','句','黄鈞','宋','宋诗','song-poetry','','[]','水遠山遥疑劍斷，風愁雨恨只鈴知。',16,'全唐诗/poet.song.126000.json','["水遠山遥疑劍斷，風愁雨恨只鈴知。"]'),
('11a4ff4b-dbd7-47c0-8df3-aab3f1be9792','挽薛艮齋  其一','甄龍友','宋','宋诗','song-poetry','','[]','驥不由窮巷，龍曾演瑞圖。',48,'全唐诗/poet.song.126000.json','["驥不由窮巷，龍曾演瑞圖。", "衣傳袁道潔，夢接邵堯夫。", "四十年全未，三千行豈無。", "飄然何太速，愁殺奠生芻。"]'),
('790b3cb8-d164-4d7f-a9be-272a5db222a8','挽薛艮齋  其二','甄龍友','宋','宋诗','song-poetry','','[]','贈別文章妙，分携六見秋。',48,'全唐诗/poet.song.126000.json','["贈別文章妙，分携六見秋。", "真書藏相府，循吏說湖州。", "不作三公入，同誰八極遊。", "朔風吹壯淚，應滿藕池頭。"]'),
('afdf5c1f-2843-4fab-ab5c-a93892ce610d','挽薛艮齋  其三','甄龍友','宋','宋诗','song-poetry','','[]','有子才而美，知君死不亡。',48,'全唐诗/poet.song.126000.json','["有子才而美，知君死不亡。", "刀圭徒有驗，兵法豈無妨。", "玉樹新埋沒，金丹舊渺茫。", "魂兮來止些，極樂在西方。"]'),
('dbee6b23-1cf7-45ef-b515-3b956e241b9b','薛氏鏡山','甄龍友','宋','宋诗','song-poetry','','[]','我生不是先，偶與前輩隔。',120,'全唐诗/poet.song.126000.json','["我生不是先，偶與前輩隔。", "古人猶愛水，况此千丈碧。", "孤圓本然明，萬象紛如繹。", "行吟鬼破膽，坐釣風生腋。", "疏梅逞晨妝，漏月印金璧。", "奇峰列雲影，平橋漲春澤。", "四時如劈剪，一照成虛射。", "緬想亭中人，屢憩泉上石。", "心空見了了，起覓已他適。", "吾詩復何言，鏡鏡如痕迹。"]'),
('bac26d97-47a6-405b-b315-135a850a21e8','望君山','甄龍友','宋','宋诗','song-poetry','','[]','大洞黄庭太乙家，君山一葉泛蓮花。',64,'全唐诗/poet.song.126000.json','["大洞黄庭太乙家，君山一葉泛蓮花。", "南征客認湘靈瑟，北上人疑漢使槎。", "尚想飛仙遊白鶴，偶於懷袖落青蛇。", "玉皇香案真如此，我欲晨奔到廣霞。"]'),
('71546d0d-d789-4c99-8cab-26c4f70436fb','謝康侍郎送米','甄龍友','宋','宋诗','song-poetry','','[]','折腰鄉里愧陶潜，五斗黄陳飯莫嫌。',32,'全唐诗/poet.song.126000.json','["折腰鄉里愧陶潜，五斗黄陳飯莫嫌。", "一介古來難取與，先生傷惠我傷廉。"]'),
('ae9ebb3f-d127-4928-8885-3ca5bae66d69','岳陽樓望洞庭','甄龍友','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','風定空澄氣渾然，恍如太極未分前。',64,'全唐诗/poet.song.126000.json','["風定空澄氣渾然，恍如太極未分前。", "只因有浪知爲水，若遇無雲總是天。", "舊說君山張帝樂，新同老木識飛仙。", "而今大洞黄庭客，又著題詩記歲年。"]'),
('d8b6a187-c7cf-4d33-80fc-3252498b8261','臨安北山大佛頭頌','甄龍友','宋','宋诗','song-poetry','','[]','色如黄金，面如滿月。',20,'全唐诗/poet.song.126000.json','["色如黄金，面如滿月。", "盡大地人，只見一橛。"]'),
('2036c15c-f0f1-4307-8abf-59bcbc6b4da6','挽呂東萊二首  其一','陳良祐','宋','宋诗','song-poetry','','[]','家學相傳久，天資自得高。',48,'全唐诗/poet.song.126000.json','["家學相傳久，天資自得高。", "讀書如夙習，授業更忘勞。", "史筆追遷左，詩編繼鄭毛。", "淵源有如此，沾丐及吾曹。"]'),
('f747ce48-821c-4a3e-9011-96a8fd45162d','挽呂東萊二首  其二','陳良祐','宋','宋诗','song-poetry','','[]','講道東陽郡，門生數百人。',48,'全唐诗/poet.song.126000.json','["講道東陽郡，門生數百人。", "從游傾里社，忻慕滿朝紳。", "仕宦淹難進，聲名烱不泯。", "伯牛有斯疾，夫子亦悲辛。"]'),
('a8d36efb-fde6-4b5d-91fd-ffc8c07a6cef','挽郭丈彥鄒','陳良祐','宋','宋诗','song-poetry','','[]','誰起相如疾，空悲武子亡。',48,'全唐诗/poet.song.126000.json','["誰起相如疾，空悲武子亡。", "平生有高志，屬意在諸郎。", "夢斷駒過隙，風高雁折行。", "莫陪千乘送，妙選媿東床。"]'),
('4e84ae3f-4b95-4e1c-9da6-60a8bc22e1a8','初夏遣悶三絕  其一','趙伯溥','宋','宋诗','song-poetry','','[]','何事東皇不暫延，祝融今日遽當權。',32,'全唐诗/poet.song.126000.json','["何事東皇不暫延，祝融今日遽當權。", "匡床睡起渾無語，一握薰風入五絃。"]'),
('276fe1ea-71c9-4fc1-9e93-53785acfb470','初夏遣悶三絕  其二','趙伯溥','宋','宋诗','song-poetry','','[]','日脚初長雨滿川，杜鵑聲老夕陽天。',32,'全唐诗/poet.song.126000.json','["日脚初長雨滿川，杜鵑聲老夕陽天。", "予心底慍難爲解，故向南風奏管弦。"]'),
('e9b170ff-66dc-4614-aded-ba0ab5e1d093','初夏遣悶三絕  其三','趙伯溥','宋','宋诗','song-poetry','','[]','運行南陸赤精然，閣外新篁籜未蠲。',32,'全唐诗/poet.song.126000.json','["運行南陸赤精然，閣外新篁籜未蠲。", "冉冉綠陰剛晝永，焦桐謾欲繼薰絃。"]'),
('52b3a05a-642e-4d07-ba88-bc663a33d87a','讀先大人伐金遺疏','趙伯溥','宋','宋诗','song-poetry','','[]','□□無情不可親，年年遣使浪填津。',32,'全唐诗/poet.song.126000.json','["□□無情不可親，年年遣使浪填津。", "武侯會有兩篇表，讀罷令人淚滿巾。"]'),
('1824170b-46d4-40b9-95fc-60d45638c4ad','宿齋堂','趙伯溥','宋','宋诗','song-poetry','','[]','燈前孤影弔焭焭，爲憶親恩未有窮。',32,'全唐诗/poet.song.126000.json','["燈前孤影弔焭焭，爲憶親恩未有窮。", "夜半子規啼血處，陡聞澗底鼓松風。"]'),
('1e0196a6-b5bc-48ca-8e7b-80adc29e2c32','詩一首','趙師訓','宋','宋诗','song-poetry','','[]','慶元宰相事紛紛，說著令人暗斷魂。',32,'全唐诗/poet.song.126000.json','["慶元宰相事紛紛，說著令人暗斷魂。", "好聽當時劉弼語，分些官職乞平原。"]'),
('99dd3bec-6653-4a13-b89c-2bf4accc4839','題學宮','趙廱','宋','宋诗','song-poetry','','[]','峩峩玉城山，地勢北龍岡。',24,'全唐诗/poet.song.126000.json','["峩峩玉城山，地勢北龍岡。", "是中産人物，英傑常相望。"]'),
('529e0f31-ca89-4912-9d81-06b77dac454a','烟雨樓','趙廱','宋','宋诗','song-poetry','','[]','畫棟飛雲暮靄寒，樓臺城堞有無間。',32,'全唐诗/poet.song.126000.json','["畫棟飛雲暮靄寒，樓臺城堞有無間。", "烟收雨霽曾看否，見盡東南萬疊山。"]'),
('2378bdc4-1065-418c-a3f6-18a24fd94da9','凝霜閣','趙廱','宋','宋诗','song-poetry','','[]','修竹蕭蕭三兩竿，公餘時得靜中看。',32,'全唐诗/poet.song.126000.json','["修竹蕭蕭三兩竿，公餘時得靜中看。", "何須更避人間暑，滿腹冰霜六月寒。"]'),
('34fdfbb7-2aee-4c50-9247-d17dde94cf36','南湖','趙廱','宋','宋诗','song-poetry','','[]','每憶南湖上，青帘賣酒亭。',48,'全唐诗/poet.song.126000.json','["每憶南湖上，青帘賣酒亭。", "柳條魚頰翠，花片馬蹄馨。", "寒食經行路，晴窗入夢屏。", "因循春又晚，風緊攪空冥。"]'),
('2e6576c7-1434-4018-a354-adeaf695651d','雪夜黄州城下','趙廱','宋','宋诗','song-poetry','','[]','雪後人家早閉門，江寒水落見沙痕。',32,'全唐诗/poet.song.126000.json','["雪後人家早閉門，江寒水落見沙痕。", "黄州城下東坡路，月浸梅花正斷魂。"]'),
('f635b824-f725-4f6e-893d-abe2d9225e9f','紀遊','趙廱','宋','宋诗','song-poetry','','[]','古端有奇勝，名巖擬天星。',288,'全唐诗/poet.song.126000.json','["古端有奇勝，名巖擬天星。", "傳聞輦轂下，往往極口稱。", "有爲背馳說，曾不如邱陵。", "請君勿誇山，恐非動者情。", "請君勿譽水，靜必惡淙琤。", "玄酒薄滋味，衆口難調羹。", "甲乙獨相囗，馬不同牛耕。", "海上有逐臭，寧云爾德馨。", "主人何負盜，勢固爲盜憎。", "茲山豈求全，乃與人事并。", "言言而疑疑，世態犬吠聲。", "百聞輸一見，日月中天明。", "我綰高要章，往返萬里程。", "凜凜民社寄，旦旦朱墨榮。", "及茲瓜戍期，作意星巖行。", "星巖有佳處，丈人試靜聽。", "空洞似容德，不禁魑魅停。", "其中百尋泉，澄撓無濁清。", "神龍倏兮來，穩穩石榻橫。", "忽焉風雲合，霹靂行雷霆。", "驅逐百種怪，慄慄心膽驚。", "爲山何用高，有此足以名。", "提携麴居士，賓從盡豪英。", "刻山與題柱，悔罪付兩黥。"]'),
('4a95273a-bcff-434b-9718-1b456497e3ae','句  其一','趙廱','宋','宋诗','song-poetry','','[]','金風凉夜深，吹我蕭蕭髮。',12,'全唐诗/poet.song.126000.json','["金風凉夜深，吹我蕭蕭髮。"]'),
('35d36b55-1252-4eed-b5b5-e7e6dc9ce20f','句  其二','趙廱','宋','宋诗','song-poetry','','[]','汴水一灣秋色冷，中原千里暮雲低。',16,'全唐诗/poet.song.126000.json','["汴水一灣秋色冷，中原千里暮雲低。"]'),
('a8d47c95-5fc6-482a-8758-542b2c859485','高宗皇帝挽詞  其一','黄謙','宋','宋诗','song-poetry','','[]','火德興王統，天威讋獷夷。',48,'全唐诗/poet.song.126000.json','["火德興王統，天威讋獷夷。", "重恢周境土，復振漢威儀。", "顯號崇瑶冊，耆年慶玉巵。", "鼎成龍去遠，扳慕不勝悲。"]'),
('cd6b3d08-97ee-4760-940b-5967be9c27b5','高宗皇帝挽詞  其二','黄謙','宋','宋诗','song-poetry','','[]','整頓乾坤後，邊烽久已銷。',48,'全唐诗/poet.song.126000.json','["整頓乾坤後，邊烽久已銷。", "和親來北虜，溫凊樂東朝。", "歷數躬傳舜，文章煥有堯。", "會稽天仗路，傷心綵雲遥。"]'),
('78c361c0-a0d0-4e82-a992-2a95c64cb992','秀野亭  其一','范端臣','宋','宋诗','song-poetry','','[]','乞得天公五畝春，暫拋手板著綸巾。',64,'全唐诗/poet.song.126000.json','["乞得天公五畝春，暫拋手板著綸巾。", "搴花露粉頻沾袖，洗竹山光忽傍人。", "金點流鶑田冪冪，雪翹幽鷺水粼粼。", "尊前無地棲榮辱，秀野亭中自在身。"]'),
('c3538741-1f14-4171-8d8a-6246f884ea60','秀野亭  其二','范端臣','宋','宋诗','song-poetry','','[]','不敢尋詩怕雨催，須知挈榼爲春來。',64,'全唐诗/poet.song.126000.json','["不敢尋詩怕雨催，須知挈榼爲春來。", "天公未放陽烏出，坐客何妨笑臉開。", "寒食花光猶照眼，亂山雲氣欲侵罍。", "黄昏數點池南雨，似惜香塵逐馬回。"]'),
('05b150b0-b40e-4e49-a3c8-ccdc09ab8fa9','半山亭','范端臣','宋','宋诗','song-poetry','','[]','窈窕轉巖腹，劃然見孤亭。',36,'全唐诗/poet.song.126000.json','["窈窕轉巖腹，劃然見孤亭。", "橫分樹矗矗，下枕溪泠泠。", "日暮人跡絕，猶聞樵斧聲。"]'),
('e261d575-c427-423a-b8cc-85492551a958','藏春園','范端臣','宋','宋诗','song-poetry','','[]','園徑蕭條草樹荒，半山林影浄回塘。',64,'全唐诗/poet.song.126000.json','["園徑蕭條草樹荒，半山林影浄回塘。", "牆根遶薺春還近，亭角舒梅暖自香。", "兩鬢斜知隨節改，百憂差喜得身强。", "尋詩問酒追豪勝，且送殘年入醉鄉。"]'),
('f927c903-bd9f-4bb5-a7c3-a78d78269323','題密山寺壁','范端臣','宋','宋诗','song-poetry','','[]','籬落鄰林麓，江灣應靄煙。',48,'全唐诗/poet.song.126000.json','["籬落鄰林麓，江灣應靄煙。", "烏鴉依野屋，獨鹿度平田。", "孤閣高竿隔，籃櫺綠柳連。", "僧棲心象息，游衍亦夤緣。"]'),
('8165dc77-024b-4066-9e39-bb7545807b85','喜智者華藏二禪老到寶惠','范端臣','宋','宋诗','song-poetry','','[]','雲窗共盥石潭冷，雪屋對吟山葉紅。',32,'全唐诗/poet.song.126000.json','["雲窗共盥石潭冷，雪屋對吟山葉紅。", "我欲徑尋蓮社去，莫將歸目掛飛鴻。"]'),
('d258fe71-fe9e-41b1-82a9-70354a32cabc','冬日寓寶惠教寺','范端臣','宋','宋诗','song-poetry','','[]','觀書倦棐几，理策開蓬門。',96,'全唐诗/poet.song.126000.json','["觀書倦棐几，理策開蓬門。", "縈紆竹溪步，迤邐僧家園。", "雲容釀密雪，煙景收殘暾。", "人語野橋店，鳥鳴桑柘村。", "山深古殿閟，澗曲回流喧。", "松桂不改色，梅蕊亦已繁。", "久厭城市卑，愈覺山林尊。", "歸途偶成詠，所樂非所言。"]'),
('0ee49e6f-3577-4105-9641-f09a145ba6be','此君軒','范端臣','宋','宋诗','song-poetry','','[]','主人結屋清溪側，對敞軒扉幽更僻。',112,'全唐诗/poet.song.126000.json','["主人結屋清溪側，對敞軒扉幽更僻。", "自憐桃李涴塵泥，故植琅玕對叢碧。", "只今俗子紛廛闠，銅臭熏天誇侈極。", "曲眉皓齒宴華堂，嫚綠妖紅醉春色。", "爭如此處是瀟洒，左右牙籤散圖籍。", "暑風韵玉脫豹胎，凉月影金交兎魄。", "我來登軒同賦詩，試問何如嚴武宅。"]'),
('414828d5-4543-486a-ab7e-624eb9bcd47d','城南塔院','范端臣','宋','宋诗','song-poetry','','[]','青天寥廓地輪囷，雲海蒼茫萬里春。',32,'全唐诗/poet.song.126000.json','["青天寥廓地輪囷，雲海蒼茫萬里春。", "渺渺江風吹不斷，塔中人與太虛鄰。"]'),
('e6821255-6e6a-4fbd-9d77-25d03432ee4c','登釣臺','范端臣','宋','宋诗','song-poetry','','[]','此地有天險，雙臺千仞崗。',48,'全唐诗/poet.song.126000.json','["此地有天險，雙臺千仞崗。", "眼寬知世窄，皇極便神傷。", "慘澹諸峰立，縈紆一水長。", "振衣懷古罷，新句入斜陽。"]'),
('813c7912-61cb-4eb1-8f27-902bb60842c6','又仙山行','范端臣','宋','宋诗','song-poetry','','[]','仙山仙山鬰嵯峩，紫煙氤氳生綠波。',64,'全唐诗/poet.song.126000.json','["仙山仙山鬰嵯峩，紫煙氤氳生綠波。", "飛瓊玉樓不知處，雜佩丁璫隔烟語。", "三青山鳥去不來，六龍落日只啣哀。", "呼聲嗷嗷動天地，老蛟吹涎海波沸。"]'),
('44f49225-2fdc-48f9-8bf9-d398f4e7c74a','嶺南鞭春','范端臣','宋','宋诗','song-poetry','','[]','一辭湖上月，三見嶺南春。',48,'全唐诗/poet.song.126000.json','["一辭湖上月，三見嶺南春。", "怪鳥呼如鬼，癡猿立似人。", "蠻商通海舶，漁戶雜江濱。", "尚有鞭牛扑，紛拏起路塵。"]'),
('60582875-0e65-4d7d-bb72-294f1ad847ea','題靈洞路','范端臣','宋','宋诗','song-poetry','','[]','傍溪多立石，逕轉特勾衣。',36,'全唐诗/poet.song.126000.json','["傍溪多立石，逕轉特勾衣。", "雲兼晚色至，葉带秋聲飛。", "孤鷺忽驚去，片雲明殘暉。"]'),
('5379a053-beb9-4756-8006-8f174e0fd882','石磴','范端臣','宋','宋诗','song-poetry','','[]','短策將我影，照盡山前溪。',36,'全唐诗/poet.song.126000.json','["短策將我影，照盡山前溪。", "夤緣入風磴，歷覽窮攀躋。", "不須剪梧桐，自倚青冥梯。"]'),
('767c2523-83d5-41c9-bbba-5de0c3327d03','洞橋','范端臣','宋','宋诗','song-poetry','','[]','橋邊十丈水，折幹餘風霆。',36,'全唐诗/poet.song.126000.json','["橋邊十丈水，折幹餘風霆。", "橋下一泓水，泠然照吾纓。", "世故暫如失，茲山得深行。"]'),
('d46a52ac-ea58-47df-94d5-fb695c9cefb7','下洞','范端臣','宋','宋诗','song-poetry','','[]','孤煙靈洞遠，未羨三茅山。',36,'全唐诗/poet.song.126000.json','["孤煙靈洞遠，未羨三茅山。", "柏子得妙見，梅花有奇攀。", "雖無金碧麗，高士昔所關。"]'),
('827954ab-0fab-42a6-b5b5-eaf0c960a4c7','怪石','范端臣','宋','宋诗','song-poetry','','[]','人間足安危，頃刻異候狀。',36,'全唐诗/poet.song.126000.json','["人間足安危，頃刻異候狀。", "唯應山中石，不受客塵障。", "搜奇貯元龍，飛雲勞魯望。"]'),
('62adb15c-1d67-47f3-a503-acc3e53fdba7','天池泉','范端臣','宋','宋诗','song-poetry','','[]','天然水泓洞，不涸亦不涌。',36,'全唐诗/poet.song.126000.json','["天然水泓洞，不涸亦不涌。", "紛披石苔靜，掩翳寒茗擁。", "微風不生波，金剎影時動。"]'),
('1b7734d4-55c7-483f-8c10-b34db7e28fdf','輓龍圖待制徐良能墓','范端臣','宋','宋诗','song-poetry','','[]','少日蜚聲竦白袍，暮年策足上青霄。',64,'全唐诗/poet.song.126000.json','["少日蜚聲竦白袍，暮年策足上青霄。", "功名略已追前輩，事業真堪托後凋。", "諫草半焚烟寂寂，瑣窗一夢夜寥寥。", "古塘原上誰行路，只有哀笳引葬簫。"]'),
('13675d80-059b-4fe7-b9f6-1aa386228bbc','新嫁別','范端臣','宋','宋诗','song-poetry','','[]','隣家新婦誰家女，昨日嫁來今日去。',240,'全唐诗/poet.song.126000.json','["隣家新婦誰家女，昨日嫁來今日去。", "徘徊欲去呼問之，何乃遽遭姑舅怒。", "婦欲致詞先淚雨，妾在村東年十五。", "長成只待嫁良人，不識人間離別苦。", "妾從五歲遭亂離，頻年况逢年凶饑。", "母躬蠶桑父鉏犁，耕無餘糧織無衣。", "十年辛苦寸粒積，倒篋傾囊資女適。", "豈知薄命嫁良人，招得偷兒夜穿壁。", "曉看奩橐無餘遺，羅綺不見空淚垂。", "公姑忌妾遣妾去，歡意翻成長別離。", "公姑遣妾妾難住，出門惘失來時路。", "不恨良媒恨妾身，生離不爲夫征戍。", "我聞此語長嗟咨，誰知賊遣人分離。", "撫人捕賊官乃職，縱賊不捕官何爲。", "婦言妾去君莫語，偷兒如鼠官如虎。"]'),
('3cf5af76-79b3-44b5-9990-9cc0f61bbaec','題游叫巖','范端臣','宋','宋诗','song-poetry','','[]','溪心磧石圓如磨，巖腹精廬冷似冰。',32,'全唐诗/poet.song.126000.json','["溪心磧石圓如磨，巖腹精廬冷似冰。", "弭楫來游衝夜雨，翛然一叟對孤僧。"]'),
('f4ac2f2d-df69-487f-8e12-ca44af79f6d5','鵝湖山','范端臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','繚垣千尺秀峰環，臺殿參差杳靄間。',32,'全唐诗/poet.song.126000.json','["繚垣千尺秀峰環，臺殿參差杳靄間。", "更借西湖一千頃，爲君題作小孤山。"]'),
('f60fbe37-db9a-41ac-944c-6ad86c59b534','秀野亭','范端杲','宋','宋诗','song-poetry','','[]','高着春山最蔚藍，截然屹立白雲端。',32,'全唐诗/poet.song.126000.json','["高着春山最蔚藍，截然屹立白雲端。", "小亭爲愛依青壁，野色當窗指點看。"]'),
('031b9550-b648-407a-a6a3-045d9fc4fd72','遊寶惠寺山','范端杲','宋','宋诗','song-poetry','','[]','不到茲山久，寒梅又著花。',48,'全唐诗/poet.song.126000.json','["不到茲山久，寒梅又著花。", "白煙叢古木，烏鵲倚枯槎。", "路轉衝危石，泉流漲淺沙。", "不堪回首處，樵唱起嘔啞。"]'),
('3ad83a32-ec68-4100-b1ba-2ad9a44ee88d','香山塔院','范端杲','宋','宋诗','song-poetry','','[]','招提登覽處，野客興偏濃。',48,'全唐诗/poet.song.126000.json','["招提登覽處，野客興偏濃。", "路入千層翠，窗涵萬疊峰。", "溪聲來小院，雲影落長松。", "幸對老僧榻，焚香話苦空。"]'),
('7b0dea5c-bd3a-4628-ad77-b31f9e22303b','賦青田','姚述堯','宋','宋诗','song-poetry','','[]','水繞山圍景物賒，樓臺相望酒旗斜。',64,'全唐诗/poet.song.126000.json','["水繞山圍景物賒，樓臺相望酒旗斜。", "暮雲低鎖門前柳，曉日輕籠陌上花。", "簇簇魚鹽喧賈市，聲聲弦誦半儒家。", "我來亦爲邦人慶，寫入新詩一笑誇。"]'),
('28b18055-f777-48b8-887e-cd516435e137','句','姚述堯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾濕西湖雨。',6,'全唐诗/poet.song.126000.json','["曾濕西湖雨。"]'),
('35d3846d-42bd-4149-abe6-7fda311e9730','乙丑仲冬自甯遠來遊陽華','李長庚','宋','宋诗','song-poetry','','[]','沿崖渡水六七里，劃見幽巖畫屏倚。',64,'全唐诗/poet.song.126000.json','["沿崖渡水六七里，劃見幽巖畫屏倚。", "却躡長虹信步行，下瞰淺清皆脚底。", "漫郎泉石之董狐，妙語品題良不誣。", "千巖萬壑果何似，吾家九疑真不如。"]'),
('0e6d565b-d20c-4f9e-8690-37c5ca8a2350','丁卯清明約鄧致道遊陽華','李長庚','宋','宋诗','song-poetry','','[]','我來挈挈倦塵沙，下馬無心更憶家。',64,'全唐诗/poet.song.126000.json','["我來挈挈倦塵沙，下馬無心更憶家。", "不怨客中逢熟食，只知醉裏是生涯。", "花邊頓覺春光老，柳外還驚日脚斜。", "甚欲與君尋勝去，何妨著脚到陽華。"]'),
('6202cf1b-c582-43c5-aaf7-d1d3bc35f4df','與致道約遊陽華尋以雨阻追和山谷集中岑公澗二絕句韻  其一','李長庚','宋','宋诗','song-poetry','','[]','垂垂雨脚幾時晴，便擬扁舟乘興行。',32,'全唐诗/poet.song.126000.json','["垂垂雨脚幾時晴，便擬扁舟乘興行。", "想得斜川今更好，勝遊恨不繼淵明。"]'),
('836358ba-27d7-44a4-b837-64f0c9403809','與致道約遊陽華尋以雨阻追和山谷集中岑公澗二絕句韻  其二','李長庚','宋','宋诗','song-poetry','','[]','陽華妙處吾能說，泉響風摇環珮聲。',32,'全唐诗/poet.song.126000.json','["陽華妙處吾能說，泉響風摇環珮聲。", "定是山靈嫌俗駕，電光掣過雨如傾。"]'),
('4ff55e74-2026-4f9f-9292-a8f3afb7d743','己巳七月遊陽華','李長庚','宋','宋诗','song-poetry','','[]','遥指斷崖如削瓜，碧雲一朵是陽華。',64,'全唐诗/poet.song.126000.json','["遥指斷崖如削瓜，碧雲一朵是陽華。", "莫言空洞中無物，須信嶄巉不可家。", "已聽泉聲響環珮，更看山色媚煙霞。", "一邱一壑平生事，不覺歸鞍带暝鴉。"]'),
('e737f653-7fc1-4f18-9f16-a38511cb672d','長庚紹興十九年七月十九日嘗遊陽華後十有二年復以是月是日從鄉曲諸公再到巖下感今追昔因成十韻','李長庚','宋','宋诗','song-poetry','','[]','陽華近七里，不到餘十年。',120,'全唐诗/poet.song.126000.json','["陽華近七里，不到餘十年。", "乃知聲名鎖，能障山水緣。", "今日與鄰曲，勝遊追斜川。", "瘦藤穿犖确，一葉弄潺湲。", "巖扃隠翠竹，梵宇浄青蓮。", "一笑躡飛虹，毛骨清欲仙。", "婆娑寶瓔珞，放浪玉壺天。", "曲肱卧盤石，滌耳聽流泉。", "片雲飛雨來，更覺秋凜然。", "酒盡與歸去，千林昏暝煙。"]'),
('9c33d416-ec07-4820-afea-d221f17ec303','次韻江府判遊陽華江丈□春間携家再來','李長庚','宋','宋诗','song-poetry','','[]','塵外非無境，壺中自有天。',48,'全唐诗/poet.song.126000.json','["塵外非無境，壺中自有天。", "從來招別駕，於此漱寒泉。", "銘已得元結，記須煩子年。", "重遊知更好，出谷趁鶑遷。"]'),
('fdacfc6d-4e07-4dea-813d-4bdcda017aae','陳士淳主簿舉似與嚴慶曾主簿鄧伯允仙尉同到陽華佳句且有巖下弄琴舟中吹笛之樂長庚雖不奉勝遊輒繼高韻  其一','李長庚','宋','宋诗','song-poetry','','[]','說着幽巖意已清，那堪地近一牛鳴。',32,'全唐诗/poet.song.126000.json','["說着幽巖意已清，那堪地近一牛鳴。", "塵縈俗累不容到，若見山靈煩寄聲。"]'),
('6592ea6c-8b29-4d2b-bb90-33ada6be9a43','陳士淳主簿舉似與嚴慶曾主簿鄧伯允仙尉同到陽華佳句且有巖下弄琴舟中吹笛之樂長庚雖不奉勝遊輒繼高韻  其二','李長庚','宋','宋诗','song-poetry','','[]','陽華山水自雙清，况弄朱絃金石鳴。',32,'全唐诗/poet.song.126000.json','["陽華山水自雙清，况弄朱絃金石鳴。", "我是行人那敢聽，恐翻別調作離聲。"]'),
('c1ce04eb-7d03-426c-bbb8-ee2ee9864f48','陳士淳主簿舉似與嚴慶曾主簿鄧伯允仙尉同到陽華佳句且有巖下弄琴舟中吹笛之樂長庚雖不奉勝遊輒繼高韻  其三','李長庚','宋','宋诗','song-poetry','','[]','雲水光中語更清，從他山寺晚鍾鳴。',32,'全唐诗/poet.song.126000.json','["雲水光中語更清，從他山寺晚鍾鳴。", "滿船載月歸來好，一笛穿雲裂石聲。"]'),
('966059b6-af96-4567-80bb-8cf389d611ee','紹熙癸丑二月二十六日蔣助教言正招遊陽華婆娑巖下薄暮乃歸得詩五絕以紀其事  其一','李長庚','宋','宋诗','song-poetry','','[]','春風今日扇微和，觸目江山發興多。',32,'全唐诗/poet.song.126000.json','["春風今日扇微和，觸目江山發興多。", "如畫幽巖無十里，輕衫短帽得婆娑。"]'),
('01e03ea0-002b-43c0-ab95-b1e1de4acda8','紹熙癸丑二月二十六日蔣助教言正招遊陽華婆娑巖下薄暮乃歸得詩五絕以紀其事  其二','李長庚','宋','宋诗','song-poetry','','[]','偶尋三逕到陽華，碧玉珍瓏真可家。',32,'全唐诗/poet.song.126000.json','["偶尋三逕到陽華，碧玉珍瓏真可家。", "追想舊游如夢寐，摩挲石刻但咨嗟。"]'),
('fff22617-d85d-4b47-9924-22d3dd75428e','紹熙癸丑二月二十六日蔣助教言正招遊陽華婆娑巖下薄暮乃歸得詩五絕以紀其事  其三','李長庚','宋','宋诗','song-poetry','','[]','巖下留連且盡歡，不知紅日半銜山。',32,'全唐诗/poet.song.126000.json','["巖下留連且盡歡，不知紅日半銜山。", "歸時林壑風煙暝，頼有昏鴉相伴還。"]'),
('a8205b9a-2be3-4183-9c13-2bd69c505565','紹熙癸丑二月二十六日蔣助教言正招遊陽華婆娑巖下薄暮乃歸得詩五絕以紀其事  其四','李長庚','宋','宋诗','song-poetry','','[]','我老思爲漫浪翁，暫來却恨去匆匆。',32,'全唐诗/poet.song.126000.json','["我老思爲漫浪翁，暫來却恨去匆匆。", "山頭日色赤如血，照映川原草木紅。"]'),
('9d689a8a-0dac-4502-8867-a513c8a473a7','紹熙癸丑二月二十六日蔣助教言正招遊陽華婆娑巖下薄暮乃歸得詩五絕以紀其事  其五','李長庚','宋','宋诗','song-poetry','','[]','我識陽華六十年，當時面目故依然。',32,'全唐诗/poet.song.126000.json','["我識陽華六十年，當時面目故依然。", "清泉白石都無恙，華髮蒼顔只自憐。"]'),
('2aa2dc9e-863e-44b5-816b-a63cc30fb7ed','紹熙甲寅五月十七日從令尹張濟之早飯獅子巖晚飲陽華巖夜闌乘月泛舟而歸  其一','李長庚','宋','宋诗','song-poetry','','[]','朝游獅子晚陽華，翫水看山樂可涯。',32,'全唐诗/poet.song.126000.json','["朝游獅子晚陽華，翫水看山樂可涯。", "野鶴沙鷗慣看客，一雙對立渡頭沙。"]'),
('62ec3d38-7424-41db-b9ab-72a4f9b45fd7','紹熙甲寅五月十七日從令尹張濟之早飯獅子巖晚飲陽華巖夜闌乘月泛舟而歸  其二','李長庚','宋','宋诗','song-poetry','','[]','到此令人憶漫郎，筆端妙語發天藏。',32,'全唐诗/poet.song.126000.json','["到此令人憶漫郎，筆端妙語發天藏。", "泉聲潄玉生秋思，不減湖中五月凉。"]'),
('f78c3cc9-23cf-41a4-a0b4-0cdc8c9d4c9f','紹熙甲寅五月十七日從令尹張濟之早飯獅子巖晚飲陽華巖夜闌乘月泛舟而歸  其三','李長庚','宋','宋诗','song-poetry','','[]','雨餘山色媚晴暉，無事孤雲自在飛。',32,'全唐诗/poet.song.126000.json','["雨餘山色媚晴暉，無事孤雲自在飛。", "坐到黄昏尤不惡，載將明月滿船歸。"]'),
('5611075b-adbd-4bf1-a682-cb05da684466','題昭明廟','汪遠猷','宋','宋诗','song-poetry','','[]','生爲明哲沒爲神，一點英靈著處新。',64,'全唐诗/poet.song.126000.json','["生爲明哲沒爲神，一點英靈著處新。", "秋浦溪山最留意，法華禪定是前身。", "九州託庇陰功大，六字加封寵渥頻。", "更有使君書事實，幽沉從此愈昭伸。"]'),
('ea5229b5-d480-445f-acb7-310b6d8bf147','題靈巖洞','李知己','宋','宋诗','song-poetry','','[]','三巖九洞絕塵寰，問訊真人得縱觀。',64,'全唐诗/poet.song.126000.json','["三巖九洞絕塵寰，問訊真人得縱觀。", "丹就已乘仙鶴去，雲深元有老龍蟠。", "鐵船泛海源流遠，玉柱擎天星斗寒。", "劈破莓苔認詩句，欲歸傳作畫圖看。"]'),
('a6ec8469-840c-4b7e-8596-1b675ac23912','句','朱時敏','宋','宋诗','song-poetry','','[]','集英殿下初登第，神虎門前便挂冠。',16,'全唐诗/poet.song.126000.json','["集英殿下初登第，神虎門前便挂冠。"]'),
('08d3322e-dbf4-42d2-bbf5-7b701ee44b37','早朝','魏吉甫','宋','宋诗','song-poetry','','[]','鳴珂曉入奉天門，仰見宸居氣象尊。',64,'全唐诗/poet.song.126000.json','["鳴珂曉入奉天門，仰見宸居氣象尊。", "斗轉星回新歲月，龍盤虎踞舊乾坤。", "國威震疊邊陲肅，帝澤汪洋浪井溫。", "雒邑鎬京相對峙，萬年周業付神孫。"]'),
('95640da4-e149-4989-a386-2e89e31389fb','比同彥平謁希顔千里昆仲千里留醉短項翁彥平有作鄙拙者亦不能已勉强亂道幸笑覽','樂備','宋','宋诗','song-poetry','','[]','君不見便腹邊先生，齁齁晝眠貯五經。',178,'全唐诗/poet.song.126000.json','["君不見便腹邊先生，齁齁晝眠貯五經。", "又不見長頭賈都尉，喋喋問字聒人耳。", "兩人挾策煩天機，俱忘其羊乃其理。", "不如此翁不知書，肩高頤隠形侏儒。", "胸中無物祇嗜酒，酒至輒盡甯留餘。", "有時花帽賓客前，清辯傾倒如流泉。", "不辭伴客竟佳夕，第恐吻燥舌本乾。", "主人從今莫言窮，有此自足當萬鍾。", "但令時與聖賢對，勿學鄙士中空空。", "我昔已自聞其風，向來一笑欣相逢。", "他時訪戴不必見，徑須奓戶呼此翁。"]'),
('d9b95d91-ffdd-4994-8e4a-11a1c2b65b03','次馬得閒幽居客至韵','樂備','宋','宋诗','song-poetry','','[]','吾道如君有幾人，生憎輕薄白頭新。',64,'全唐诗/poet.song.126000.json','["吾道如君有幾人，生憎輕薄白頭新。", "林泉卜築何妨靜，詩酒尋盟不厭頻。", "小雨汀洲松浦霽，斜陽花草玉峰春。", "芒鞵竹杖須乘興，快取平生見嬾真。"]'),
('28fceb48-8fb5-4fae-889e-f62d7c66b86e','次韵得閒晚春即事','樂備','宋','宋诗','song-poetry','','[]','新晴初照屋山頭，春欲歸時事事幽。',64,'全唐诗/poet.song.126000.json','["新晴初照屋山頭，春欲歸時事事幽。", "詩著硬黄容我掃，酒拚大白共君浮。", "幸聞邊備初無警，喜見農功漸可鳩。", "老去所期如此爾，人間底事更關愁。"]'),
('54d75af3-9f09-4414-b9a8-7231d0dafe39','某屬聞少伊廣文歸別墅將挂其冠然乎富貴恐不免耳欲謁未能因成古詩奉迓某無策可去斷章不忘健羨也','樂備','宋','宋诗','song-poetry','','[]','明光宮高麗鳷鵲，三聲朝雞報宮鑰。',192,'全唐诗/poet.song.126000.json','["明光宮高麗鳷鵲，三聲朝雞報宮鑰。", "車如流水馬如龍，門外斗量無處著。", "歸來日晏僕亦痡，豪芒飽暖歸妻孥。", "豈無道德絢爛者，意作霖雨言爲謨。", "何人著眼高蓬蓽，彊仕之年髮如漆。", "便抽手版挂衣冠，把住窮愁甘似蜜。", "人言進退誠兩塗，退者真智進者愚。", "要當程力之所底，未省逸路排輕車。", "馬侯制行如圭璧，五色文章發金石。", "不知持此將安之，天下寶當天下惜。", "秋郊凉入菰蒲間，新詩落筆不作難。", "應憐俗駕難回者，更費移文過北山。"]'),
('84da524a-df38-4c84-9a61-fd1cc80167fd','玉笥山鄧仙','何异','宋','宋诗','song-poetry','','[]','有懷霽月光風度，出宰青山綠水鄉。',32,'全唐诗/poet.song.126000.json','["有懷霽月光風度，出宰青山綠水鄉。", "羽檄交馳公事了，一鋪真畫一爐香。"]'),
('b5548b4a-4730-49a3-815f-9618e1de5637','一犁春雨圖','何异','宋','宋诗','song-poetry','','[]','負郭先疇二頃餘，飽看雨後著耕夫。',32,'全唐诗/poet.song.126000.json','["負郭先疇二頃餘，飽看雨後著耕夫。", "軟紅塵裏家山夢，却就君家閲畫圖。"]'),
('75292702-7518-4e3f-8f73-088515389a98','章少機建小閣用陳伯强韵','何异','宋','宋诗','song-poetry','','[]','樓居草草假三間，便覺星辰手可攀。',64,'全唐诗/poet.song.126000.json','["樓居草草假三間，便覺星辰手可攀。", "最喜坐中先得月，不妨睡處也看山。", "林疏啼鳥秋彈曲，天闊飛鴻曉捲班。", "對鏡清吟無限好，典衣冷債幾時還。"]'),
('2952a7f1-fb7d-4800-a8de-57d3a4d5344a','題李國博東園','何异','宋','宋诗','song-poetry','','[]','東園吟思玉蟾清，園客開門古意生。',64,'全唐诗/poet.song.126000.json','["東園吟思玉蟾清，園客開門古意生。", "冰硯雲燈深洞宇，春花秋草舊宮城。", "人藏密樹尋聲見，鷺下寒池照影驚。", "三十分司泉石主，馬蹄塵外得聞名。"]'),
('51500f2d-ee64-4765-b986-8a47ef63f92f','題環翠閣','何异','宋','宋诗','song-poetry','','[]','環翠閣邊無點埃，盡收清致助吟才。',64,'全唐诗/poet.song.126000.json','["環翠閣邊無點埃，盡收清致助吟才。", "溪頭月落漁煙散，岸口城低野色來。", "斜檻半依秋樹出，小窗知爲北山開。", "沙禽古水閒相趁，悞入疏簾靜却回。"]'),
('aafe61a7-10b2-44bc-b40f-8b3b3337d276','宗老堂','何异','宋','宋诗','song-poetry','','[]','巋然獨存靈光殿，再世襲封康樂公。',64,'全唐诗/poet.song.126000.json','["巋然獨存靈光殿，再世襲封康樂公。", "此堂宗老正類此，盡在相傳衣鉢中。", "佳人一笑粲玉齒，願公壽考仍歡喜。", "子如父，父如子，燈燈接續無窮已。"]'),
('ef953d5e-e70f-4565-96f4-04d812359d51','控巴臺  其一','何异','宋','宋诗','song-poetry','','[]','閲武弓刀勁利，留賓歌舞清妍。',28,'全唐诗/poet.song.126000.json','["閲武弓刀勁利，留賓歌舞清妍。", "紅映連檣燈火，翠浮隔岸人煙。"]'),
('ecedf698-1c6a-472c-a109-09f84b27a89b','控巴臺  其二','何异','宋','宋诗','song-poetry','','[]','臺上小留歸客，臺前穩繫扁舟。',28,'全唐诗/poet.song.126000.json','["臺上小留歸客，臺前穩繫扁舟。", "三宿翠微閣上，一程白帝城頭。"]'),
('574c5761-919c-4c29-84c5-74bb99df38c9','浮石山莊','何异','宋','宋诗','song-poetry','','[]','天巧不易覷，覷巧不難著。',120,'全唐诗/poet.song.126000.json','["天巧不易覷，覷巧不難著。", "狐裘或反衣，鑄鐵真成錯。", "此亭對此石，層層水初落。", "憑高得其要，他景皆可略。", "蒼波繞廬阜，白浪縈衡霍。", "魚龍出變怪，鱗鬣紛拏攫。", "初疑海上來，根株相連絡。", "又疑泗濱渡，清潤可磨琢。", "水石兩奇特，賓主一笑樂。", "猶想峴山亭，清名與山託。"]'),
('2c17902d-6238-4ae3-a102-545475948975','高峰山','何异','宋','宋诗','song-poetry','','[]','快登十里壇，望極千里眼。',48,'全唐诗/poet.song.126000.json','["快登十里壇，望極千里眼。", "天近風轉清，地高日難晚。", "禽聲自圓熟，山色真平遠。", "再來除荆棘，踏月歸路穩。"]'),
('d39bda25-dc67-4ef0-b26a-eedfd0c2edd5','安源院','何异','宋','宋诗','song-poetry','','[]','施田樂貳卿，讀書吳吏部。',48,'全唐诗/poet.song.126000.json','["施田樂貳卿，讀書吳吏部。", "石跡猶可尋，青山亦如故。", "春深笋蕨香，歲熟倉箱富。", "坐久遂忘歸，更問鍾山路。"]'),
('39587cd5-bcb1-4ba4-ac89-c9bb2579c2ff','鍾山寺','何异','宋','宋诗','song-poetry','','[]','貳卿追綠野，一壑飽清泉。',48,'全唐诗/poet.song.126000.json','["貳卿追綠野，一壑飽清泉。", "詩到永嘉上，山如靈隠前。", "生涯歸古寺，遺照對枯禪。", "二百餘年話，來同三月天。"]'),
('f315394a-b754-4326-9d82-9738378fc43c','大華山','何异','宋','宋诗','song-poetry','','[]','地靈推寶蓋，奇崛跨三州。',288,'全唐诗/poet.song.126000.json','["地靈推寶蓋，奇崛跨三州。", "帝座聯樞極，星躔值斗牛。", "江南誇絕勝，仙伯揖浮邱。", "舊觀依山脚，崇壇冠嶺頭。", "懷哉二真意，特地一時留。", "爭謂神丹熟，誰知瑞氣浮。", "妄傳異人氣，遽遣老臣收。", "雲外嘗交戰，風前枉運籌。", "利鋒皆瓦礫，勇銳失貔貅。", "歛幟驚逋伏，還兵敢逗遛。", "桂司歸內府，芝檢動前旒。", "遺鏃砮牙細，纏灘馬蹟稠。", "一承丹凰詔，雙擁翠雲裘。", "功滿三千行，神參八極遊。", "後先鸞與鶴，乘跨虎兼虬。", "仙樂宣新響，文枰化故楸。", "玄壇開豁敞，紫洞鎖深幽。", "雞豢餘空竇，龍投按舊湫。", "斬妖留血樹，化石望仙舟。", "鵝垍晴飛雪，茶凹暑挾秋。", "退心披峻嶺，浄手掬寒流。", "石銳矛頭似，山長劍脊侔。", "路危行九曲，臺險過三休。", "靈藥從人乞，薰爐足意謀。"]'),
('606bee6b-e71c-4d89-9b54-6c4d1134106d','將之豫章別葆光先生','張堅','宋','宋诗','song-poetry','','[]','西山喚我陪輕舉，上館留君養大還。',32,'全唐诗/poet.song.126000.json','["西山喚我陪輕舉，上館留君養大還。", "莫起世間離別念，他年相見兩童顔。"]'),
('0f2b1fe3-cfbb-4374-8d5d-ac3fd12c0c8d','鶴廟松','張堅','宋','宋诗','song-poetry','','[]','誰種飛仙百丈梯，風摧雨折昔人非。',32,'全唐诗/poet.song.126000.json','["誰種飛仙百丈梯，風摧雨折昔人非。", "憑誰寄語楊員外，留取孫枝待令威。"]'),
('5ec5d6b1-8ea9-4e11-a088-3b786864a8c1','茅山雨中','張堅','宋','宋诗','song-poetry','','[]','踈踈霧雨閟朝晴，不那浮雲先自生。',32,'全唐诗/poet.song.126000.json','["踈踈霧雨閟朝晴，不那浮雲先自生。", "傳語洞靈休勒駕，而今逋客已歸耕。"]'),
('f1d0ec33-4614-4385-965c-0514c3ddf5e8','句','郭見義','宋','宋诗','song-poetry','','[]','半落半開梅好處，似無似有草生時。',16,'全唐诗/poet.song.126000.json','["半落半開梅好處，似無似有草生時。"]'),
('3e10a26e-960c-4c5e-b8a6-ab8c5cb9a217','和姜邦傑感興','葉翥','宋','宋诗','song-poetry','','[]','枌梓交遊盡，靈光巋獨存。',24,'全唐诗/poet.song.126000.json','["枌梓交遊盡，靈光巋獨存。", "聲名今綺皓，公論自推尊。"]'),
('e53b5411-f9d5-4cd7-9b4e-15d21bff3e56','送芍藥  其一','葉翥','宋','宋诗','song-poetry','','[]','清和天氣屬良辰，芳事枝頭迹已陳。',64,'全唐诗/poet.song.126000.json','["清和天氣屬良辰，芳事枝頭迹已陳。", "閒涉小園銷永晝，尚留紅藥殿餘春。", "栽培元是根宜地，幻化須知花有神。", "約定明年身更健，詩篇又見一番新。"]'),
('b39311d4-210b-4266-8a0c-0be1fffac9c9','送芍藥  其二','葉翥','宋','宋诗','song-poetry','','[]','枌社光榮晝錦歸，新移紅藥著花時。',32,'全唐诗/poet.song.126000.json','["枌社光榮晝錦歸，新移紅藥著花時。", "慇懃折贈難虛擲，要向詩翁覓好詩。"]'),
('a15301df-aee6-44ca-8bf9-bc0a724c343d','題謝清音道人扇面','葉翥','宋','宋诗','song-poetry','','[]','歸休謝去世間忙，看畫題詩引興長。',64,'全唐诗/poet.song.126000.json','["歸休謝去世間忙，看畫題詩引興長。", "忽見遠山來几席，方知妙筆出閨房。", "百杯歌徹行雲住，萬象心營點墨香。", "珍重製成團月扇，清風滿座自生凉。"]'),
('7a3d4f35-a1c6-4e6d-8800-6192272840d2','同姜邦傑游南湖','葉翥','宋','宋诗','song-poetry','','[]','聯騎上南明，清譚意自傾。',48,'全唐诗/poet.song.126000.json','["聯騎上南明，清譚意自傾。", "雲垂山掩翠，風靜雨飛聲。", "幽壑藏舒景，清溪漾晚晴。", "從容共樽酒，欲別正關情。"]'),
('157f1bbc-36e4-4159-b7d0-2824c873fbe8','和姜邦傑贈別','葉翥','宋','宋诗','song-poetry','','[]','研席當時輩，凋零只兩翁。',48,'全唐诗/poet.song.126000.json','["研席當時輩，凋零只兩翁。", "榮歸會面喜，話舊此心同。", "景物詩篇富，交情古道隆。", "明朝斟別酒，問訊付郵筒。"]'),
('b89cae84-0525-463c-bbac-756d42cb69aa','題興道院藍光軒','葉翥','宋','宋诗','song-poetry','','[]','出郭纔咫尺，便覺山意幽。',204,'全唐诗/poet.song.126000.json','["出郭纔咫尺，便覺山意幽。", "招提立絕頂，寶塔凌空浮。", "小軒足娛客，下有清溪流。", "翠岫供遠眺，直欲明雙眸。", "平蕪草肥軟，飽飼眠吳牛。", "沙頭水色靜，飛上馴白鷗。", "人稀日亭午，野渡橫孤舟。", "坐久意逾爽，吹袂風颼颼。", "想當三伏天，凜然如素秋。", "簿書叢裏來，恍若脫羈囚。", "乘興偶登覽，不謂成勝游。", "平生志所願，一壑與一邱。", "脚力到佳處，須作信宿留。", "南峯只在眼，不必勞冥搜。", "當時輞川圖，景物有此不。", "學貴守所見，出處各異謀。", "淵明亦高哉，未肯屈督郵。"]'),
('d29e9492-79ef-469a-a3e4-f9fa9cbc70bd','顧野王讀書堆','錢良臣','宋','宋诗','song-poetry','','[]','伊昔邊烽備不虞，太平移作梵王居。',32,'全唐诗/poet.song.126000.json','["伊昔邊烽備不虞，太平移作梵王居。", "而今江表全無事，借我三椽更讀書。"]'),
('ed15cc8e-69ab-4c1d-b18e-eb731ed6ed8e','題龍潭石巖','馬大同','宋','宋诗','song-poetry','','[]','攬轡觀風只課程，風雲要挹楚鄉清。',64,'全唐诗/poet.song.126000.json','["攬轡觀風只課程，風雲要挹楚鄉清。", "晨旌幾礙觀山目，夜柝翻驚夢月情。", "觀者寧知部使者，平生元是老書生。", "滄浪何處無人識，欲往從之一濯纓。"]'),
('78f15490-a153-40a6-8527-474eb152a4da','過九疑','馬大同','宋','宋诗','song-poetry','','[]','帝德于今祀萬年，如何遺像託疏椽。',32,'全唐诗/poet.song.126000.json','["帝德于今祀萬年，如何遺像託疏椽。", "憑誰爲假丹青手，付與梅仙十萬錢。"]'),
('aa155659-88b7-4ab5-ae42-2b6021e16c07','過九疑  其一','馬大同','宋','宋诗','song-poetry','','[]','平生夢想九疑高，原隰驅馳敢憚勞。',32,'全唐诗/poet.song.126000.json','["平生夢想九疑高，原隰驅馳敢憚勞。", "肅肅衣冠朝帝所，此行端不爲遊遨。"]'),
('52b3f25c-fbc5-41ac-9e1d-fa808b796289','過九疑  其二','馬大同','宋','宋诗','song-poetry','','[]','行盡平岡十里間，好山迎我翠相環。',32,'全唐诗/poet.song.126000.json','["行盡平岡十里間，好山迎我翠相環。", "九疑更在雲深處，祇恐天高不可攀。"]'),
('471ba670-adb9-465a-b5a7-fc435a25eca4','過九疑  其三','馬大同','宋','宋诗','song-poetry','','[]','宇宙纔分便有山，茲山戢戢序成班。',32,'全唐诗/poet.song.126000.json','["宇宙纔分便有山，茲山戢戢序成班。", "重華遠矣遺風在，好似相從揖遜還。"]'),
('161f602a-7f45-4386-8543-cd2b8284c1ee','過九疑  其四','馬大同','宋','宋诗','song-poetry','','[]','人與韶音渺莫聞，山如羽衛自森森。',32,'全唐诗/poet.song.126000.json','["人與韶音渺莫聞，山如羽衛自森森。", "不封不樹知何處，漫說零陵古到今。"]'),
('799196f5-3fdf-41e0-b5da-ad1290e11232','過九疑  其五','馬大同','宋','宋诗','song-poetry','','[]','二妃千古恨難刊，不謂南巡遂不還。',32,'全唐诗/poet.song.126000.json','["二妃千古恨難刊，不謂南巡遂不還。", "空使湘江江上竹，至今猶染淚痕斑。"]'),
('d1a543d1-d336-4181-a239-d4c48fced310','過九疑  其六','馬大同','宋','宋诗','song-poetry','','[]','何侯拔宅登仙去，虞帝因山作廟基。',32,'全唐诗/poet.song.126000.json','["何侯拔宅登仙去，虞帝因山作廟基。", "人物由來相代謝，不知陵谷幾遷移。"]'),
('30e9e851-1809-4a4b-81b1-135582745dff','答誠齋','程如','宋','宋诗','song-poetry','','[]','衡門時反關，一室甘却掃。',72,'全唐诗/poet.song.126000.json','["衡門時反關，一室甘却掃。", "文墨脫紛總，書林恣論討。", "闖然未足意，清矣濯懷抱。", "揮灑烏絲新，浸淫黄卷好。", "後來應手摹，前輩休腹稿。", "君意不期知，予心以爲寶。"]'),
('c5e8cd77-f028-4566-8346-3f934676911d','句','曾槃','宋','宋诗','song-poetry','','[]','還持病眼將昏力，來看仙山未了青。',16,'全唐诗/poet.song.126000.json','["還持病眼將昏力，來看仙山未了青。"]'),
('a0bc3adb-3d33-4b86-8c04-39c8efc4db87','題呂公巖','金靖','宋','宋诗','song-poetry','','[]','護田綠水轉山樊，滴翠羣峰列巨杉。',96,'全唐诗/poet.song.126000.json','["護田綠水轉山樊，滴翠羣峰列巨杉。", "洞外僧藍侵斗漢，澗邊人跡隔仙凡。", "深深雲谷春長在，寂寂松扉夜不緘。", "此處得名爰自我，要須題作呂公巖。", "不用湔廳向水邊，乘風宜坐此巖巔。", "山陰樂事真何似，觴詠終能勝管絃。"]'),
('5d688bcd-caaf-41de-afe5-7301c3b609d7','題浄樂院壁','薛仲邕','宋','宋诗','song-poetry','','[]','再到招提已六年，谿山雲霧總依然。',32,'全唐诗/poet.song.126000.json','["再到招提已六年，谿山雲霧總依然。", "飄零莫笑渾無用，自謂功名可著鞭。"]'),
('67468196-0e4d-4182-b007-d0691c25aaaa','胡澹庵招宴','余鳳','宋','宋诗','song-poetry','','[]','稱藩割地竟何如，抗疏孤臣只索居。',64,'全唐诗/poet.song.126000.json','["稱藩割地竟何如，抗疏孤臣只索居。", "萬死不回三寸舌，千金空募一封書。", "醉中益抱蒙塵恨，夢裏猶呼和議愚。", "長脚老奸今已朽，請君努力上安車。"]'),
('08a7a458-a130-4aa1-935c-51f412b74399','子吳子某既結茆竹洲以娛親復于居之前沼爲亭以朝爽名之蓋亭西面於晨興看山爲宜','吳儆','宋','宋诗','song-poetry','','[]','抱甕自灌園，勝遊貴人門。',220,'全唐诗/poet.song.126000.json','["抱甕自灌園，勝遊貴人門。", "有口自酌酒，勝與俗人言。", "園中多蔓草，晨夕費鋤芟。", "遇夜或風雨，安得久盤旋。", "村酒不常有，有亦多苦酸。", "而况醉中語，繆誤人所嫌。", "不如飽喫飯，清風北窗眠。", "眠多則無覺，夢境仍多端。", "惟有古斷簡，言行皆聖賢。", "讀之未竟篇，眵昏如夢間。", "讀竟亦何爲，聚訟徒喧煩。", "厭煩以靜勝，又類枯木禪。", "揠苗不耘苗，亡羊兩茫然。", "何如池上亭，虛曠可看山。", "山色日夕佳，晨興夜氣還。", "宴坐日過午，清陰猶未遷。", "西山倦拄頰，南山興悠然。", "晚山雖好不遮日，誰能觸熱望長安。"]'),
('da09a499-fadc-49a9-a5c5-d436a4538753','題新安僉廳拄笏亭','吳儆','宋','宋诗','song-poetry','','[]','高山如高人，可仰不可褻。',108,'全唐诗/poet.song.126000.json','["高山如高人，可仰不可褻。", "山中老鋤犁，山前走車轍。", "終日對孱顔，如目不見睫。", "高人與高山，千里風期接。", "妙思入青冥，毫端寄明滅。", "况復簿領中，見此寒岌嶪。", "悠然境意會，芻豢端自悅。", "手板亦何爲，趨走背汗浹。", "從渠且倒持，吾自支吾頰。"]'),
('c142569d-bea2-44c5-b3c3-865ac0e41d81','題騎牛圖','吳儆','宋','宋诗','song-poetry','','[]','汗血聲利場，舉世循一軌。',84,'全唐诗/poet.song.126000.json','["汗血聲利場，舉世循一軌。", "霜風老觳觫，松路石齒齒。", "牛瘦僕夫疲，累累山谷裏。", "兩翁非病狂，顧獨不取彼。", "牛背有佳處，未可語俗子。", "夷齊向千載，凜凜有生氣。", "試問齊景公，烏用馬千駟。"]'),
('2a35c51f-fe07-496f-85f6-4f63f91eeb21','代陳無己述懷','吳儆','宋','宋诗','song-poetry','','[]','胡馬嘶北風，越鳥依南枝。',72,'全唐诗/poet.song.126000.json','["胡馬嘶北風，越鳥依南枝。", "人生有氣類，千里傾風期。", "君看漆室女，中宵倚楹悲。", "從君不憚遠，秋露濕人衣。", "南山白石爛，漫漫何時旦。", "獨立占少微，搔手空三歎。"]'),
('81437bd1-c354-4b91-a0fd-4d036d6b2678','和孫先生彥及棣華堂詩韵','吳儆','宋','宋诗','song-poetry','','[]','大雅久不作，聲色淫鄭紫。',288,'全唐诗/poet.song.126000.json','["大雅久不作，聲色淫鄭紫。", "古來非一秦，焚厄故如此。", "西都盛經學，聚訟自茲始。", "建安委道真，典午事玄理。", "錦縠蔚雲霧，組紃亦信美。", "後生不著眼，千古空信耳。", "誦習號純儒，曠達稱高士。", "有如富賢賈，多藏不能使。", "又如病酒狂，沉酣糟粕旨。", "源流日以遠，循襲不爲恥。", "先生秉大雅，江東今夫子。", "持身不夷惠，漫仕無慍喜。", "學術心自得，筌蹄視經史。", "蘭舟翼桂楫，巨川端可涘。", "我家世從公，公欲出泥滓。", "愚不堪世用，非人不我以。", "破屋蔭蓬根，春薺老牆址。", "寂寞誰肯顧，公獨不我鄙。", "遺之珠玉篇，諄諄說友弟。", "直欲障頹波，肯與爲茅靡。", "觀公用意處，可與召穆比。", "弟兄吾手足，父母吾怙恃。", "盡此菽水歡，還勝有酒醑。", "古來願爲兄，日月不可弭。"]'),
('0dd1b0ec-85a3-4c6e-a75f-ab4ca935bad9','寄題鄭集之醉夢齋','吳儆','宋','宋诗','song-poetry','','[]','利欲醺人心，濃如飲醇酎。',228,'全唐诗/poet.song.126000.json','["利欲醺人心，濃如飲醇酎。", "沉湎死不休，寧論千日久。", "豈知糟邱中，醒狂亦時有。", "天地育萬彙，亦各賦匹偶。", "人情豈相遠，好惡隨妍醜。", "集之年方壯，濯濯春月柳。", "性獨與人殊，無婦奉箕箒。", "丈室誇醉夢，作詩詔朋友。", "古來醉夢人，亡羊孰先後。", "寒儒醉糟粕，酸澀寧可口。", "莊生夢蝴蝶，幻境徒紛糾。", "富貴得志士，列屋羅螓首。", "象牀粲錦幄，疎綺深朱牖。", "酣寢喚不醒，鼻息春雷吼。", "梅花霜雪姿，紙帳蔬荀臭。", "問君有何好，甘作老鰥叟。", "窮狀徒纍纍，鴦債長負負。", "猶如荷旃人，難論純綿厚。", "但問雪煎茶，何如羊羔酒。"]'),
('2cbcd92f-9649-4332-8f2c-46bcc313d1d9','次韵南軒先生榕溪閣閣山谷所名也','吳儆','宋','宋诗','song-poetry','','[]','紹聖用事臣，黨與紛相樛。',156,'全唐诗/poet.song.126000.json','["紹聖用事臣，黨與紛相樛。", "當代幾忠良，一朝咸黜幽。", "太史坐直筆，愈黜名愈休。", "消長關否泰，天意匪人謀。", "纍臣誰司城，獨爲景物留。", "當時西復南，萬里不停輈。", "誰知百年定，欲起九京遊。", "積莽新陳迹，寒泉薦冰甌。", "想當千騎臨，水木寒蕭颼。", "我公今伊傅，茲焉少夷猶。", "炎方凋瘵餘，公來今已瘳。", "榕溪兩甘棠，千載誰劣優。", "太史後凋松，公如巨川舟。"]'),
('0ee7525b-9afe-4d9c-bdb4-596eceb9889e','汪叔耕見訪不數日別去惡語爲贈兼簡子用子美二友','吳儆','宋','宋诗','song-poetry','','[]','負釁得老窮，掃軌事幽屏。',144,'全唐诗/poet.song.126000.json','["負釁得老窮，掃軌事幽屏。", "跫然羅雀門，有客頎而整。", "悲歡十年別，樽酒清夜永。", "妙句時驚人，盈軸肯傾廩。", "三日語未休，霜寒夢歸省。", "臨流分別袂，波光照孤影。", "重念吾故人，雪屋清燈冷。", "劉子抱遺經，深井汲修綆。", "曹子中庸學，天理窮性命。", "老驥鼓不作，搴旗望公等。", "天晴風日佳，何時過鼪徑。", "石鼎燃豆萁，冰葅煮湯餠。"]'),
('dd4279a9-33e5-466b-bc09-916162ac1405','題陳仲禮四知軒且當折柳之意','吳儆','宋','宋诗','song-poetry','','[]','陳侯一世豪，筆力萬人敵。',160,'全唐诗/poet.song.126000.json','["陳侯一世豪，筆力萬人敵。", "卧之百尺樓，平視劉玄德。", "收斂湖海氣，一室僅容膝。", "平生不欺心，自護如拱璧。", "客來問字細論文，旋糶官粱買酒樽。", "夜深四壁冷徹骨，酒酣一笑溫如春。", "三年官滿何所畜，滿船稚乳書幾束。", "長安侯門高於天，束薪炊米桂炊玉。", "問君持此將安歸，君言歲收可百斛。", "吾儕本無膏粱念，况今老矣其何欲。", "宰相時來則爲之，切莫倒行夸食肉。"]'),
('ff08b604-e637-46a6-b900-c9b30f57c11d','寄題淳安陳令君讀書林','吳儆','宋','宋诗','song-poetry','','[]','能吏事深刻，商利謹毫釐。',168,'全唐诗/poet.song.126000.json','["能吏事深刻，商利謹毫釐。", "俗吏趨期會，簿書自羈縻。", "寥寥絃歌聲，千古空餘思。", "還淳山水邑，令君丘壑姿。", "邑民本無事，君亦何所爲。", "治己物自治，化行風薦移。", "君復何所欲，讀書常不足。", "拄腹五千卷，插架三萬軸。", "曾未出毫芒，萬室已蒙福。", "堂東松竹林，昔時閟荒榛。", "堂中燈燭光，昔時照紅裙。", "今何聲吾伊，蕭蕭風雨晨。", "問君有社稷，亦復有人民。", "奈何獨自苦，學道則愛人。"]'),
('6e02e650-8fae-4b59-9554-7e6c2fec9946','以竹牀贈楊信伯古詩代簡','吳儆','宋','宋诗','song-poetry','','[]','此君丘壑姿，不受世炎凉。',140,'全唐诗/poet.song.126000.json','["此君丘壑姿，不受世炎凉。", "那知猶有用，未免斤斧傷。", "矯揉加尺度，指繞百鍊剛。", "直節甘枕藉，凜氣薦冰霜。", "紈扇有用舍，杞桮真賊戕。", "所用已卑賤，幸升君子堂。", "用之苟非人，珪璧污閨房。", "君家鴻鵠羣，風雨今對牀。", "故令厠其間，貴賤可兩忘。", "他時飛雪或不常，煩君拂拭懸虹梁。", "除非高士延孺子，無令年少辱真王。"]'),
('50b7cc8e-734f-4cfb-a13b-1bafc1ff558d','和唐秘校見貽長篇','吳儆','宋','宋诗','song-poetry','','[]','君才離奇卧壑松，力回萬牛匠非哲。',243,'全唐诗/poet.song.126000.json','["君才離奇卧壑松，力回萬牛匠非哲。", "我如坎井可窺底，短綆未汲固自竭。", "饑寒驅置簿領中，巧匠旁觀指濡血。", "逢人首下尻益高，敢遇督郵腰不折。", "憧憧往來窮朝昏，負負江湖弄風月。", "邑雖陋室無佳士，稍輸城府開私謁。", "平生聞人說項斯，秀句秋江更清澈。", "鼯徑經雨忽蛩然，傾囷倒廩不我屑。", "渥洼汗血絕後殿，天球河圖合前列。", "要知冷煖須自知，舐蜜中邊不容說。", "癡兒徒癡不了事，相留湯餠未暇設。", "如今豈止傾蓋舊，向者固已聞風說。", "命之窮達有宿分，男兒功名在晚節。", "未應種豆趣南山，試一上書干北闕。", "君不見少陵流落老更窮，長歎自比稷與契。"]'),
('5ff63441-f9a8-4500-8409-a5cd0b01a3e5','題李休寧藏齋','吳儆','宋','宋诗','song-poetry','','[]','璧玉世所珍，常以十襲藏。',156,'全唐诗/poet.song.126000.json','["璧玉世所珍，常以十襲藏。", "虎豹亦自愛，霧雨澤其章。", "璧玉瑱玷缺，郊廟登琮璜。", "虎豹養成文，倏變風飛揚。", "李侯知愛子，納於道德場。", "劚翳開雲扃，挹潔抗風窗。", "萬軸架牙籤，千篇垂琳琅。", "燈火秋夜永，爐薰春晝長。", "黄卷對聖賢，北窗卧羲皇。", "欲不接耳目，心靜發天光。", "性守蹈宮庭，禮教嚴範防。", "城堅無畏敵，楫具川可航。", "茲焉寄游息，鵬路觀翺翔。"]'),
('8a849157-cf65-4295-9e31-ff71f507e56a','宿神潭洪氏醉經堂','吳儆','宋','宋诗','song-poetry','','[]','久客急歸程，風雨事馳騖。',132,'全唐诗/poet.song.126000.json','["久客急歸程，風雨事馳騖。", "黄流鳴澗壑，餘波或被路。", "堆埼珠聯屬，石徑齒齟齬。", "籃輿惴危登，杖策阻深度。", "行行忽平崗，神潭渺東注。", "徒旅鳩後先，煙火休薄暮。", "主人延客入，丈室千卷聚。", "醉經揭佳名，巨軸舒新句。", "我亦舊高陽，糟粕嘗已屢。", "人言薄滋味，舌根恐未具。", "君但中聖賢，當自知佳處。"]'),
('105b9ae1-fa50-4ff9-a40b-932f7b240c7c','題祝聖寺','吳儆','宋','宋诗','song-poetry','','[]','金碧照征涂，松竹開幽徑。',84,'全唐诗/poet.song.126000.json','["金碧照征涂，松竹開幽徑。", "山僧壽八十，腴貌精視聽。", "囊鉢罄錙銖，棟宇事嚴整。", "如公方外人，視世一泡影。", "辛勤畢此生，更欲傳不泯。", "當家茀父菑，居位蠹國政。", "視公豈容誅，三歎發深省。"]'),
('81ab6c06-bf44-4085-b0c4-d6eda195af5d','楊村道中邂逅趙仁甫','吳儆','宋','宋诗','song-poetry','','[]','修途轉清溪，孤村带寒日。',96,'全唐诗/poet.song.126000.json','["修途轉清溪，孤村带寒日。", "瀟灑竹間亭，意行成小立。", "賓主莫誰何，悠然良自適。", "俄有貴公子，胡驄摇寶勒。", "下馬相勞苦，呼酒道疇昔。", "遂令麋鹿姿，頗爲人物色。", "佳實進霜堅，異釀引寒碧。", "興盡還獨歸，沙頭寒月白。"]'),
('b62e5c54-f062-41e5-8ac8-080e6c9bca2e','題陽山寺','吳儆','宋','宋诗','song-poetry','','[]','憶昨去家時，凉風肅巾屨。',168,'全唐诗/poet.song.126000.json','["憶昨去家時，凉風肅巾屨。", "閭里重遠別，祖席煩親故。", "期會趨晷刻，倉卒戒徒御。", "首尾遍吳楚，復退分携處。", "歲月拂塵壁，廊廡識故步。", "故人新絳帷，方屨盈外戶。", "褰裳喜我來，寒溫問良苦。", "樽酒開驩顔，雞黍羞珍具。", "欲少爲君留，歸心已先騖。", "年少未仕初，飽食厠庠序。", "束書事遨遊，光陰等閒度。", "一爲升斗縻，奔走窮朝暮。", "欲學不可得，雖悔復誰諉。", "諸君其早圖，前覆戒吾車。"]'),
('f2fb8999-c7f5-477f-8268-706dbb0d17e2','獨酌','吳儆','宋','宋诗','song-poetry','','[]','松竹開幽徑，蓬蒿閟荆扉。',60,'全唐诗/poet.song.126000.json','["松竹開幽徑，蓬蒿閟荆扉。", "庭前兩梧桐，濃綠涵清輝。", "南楹開半山，晨夕異煙霏。", "樽酒自賓主，幽鳥更塤箎。", "飲罷兩無言，還讀淵明詩。"]'),
('c501b2d0-40ae-4648-bc23-992672a90aa5','早起','吳儆','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','積雨霽窮秋，柴扃立清曉。',60,'全唐诗/poet.song.126000.json','["積雨霽窮秋，柴扃立清曉。", "溪光照煙岫，未覺秋容老。", "溪邊烏臼林，他日沒飛鳥。", "濃綠半枯枝，殷紅亂衰草。", "摇落想騷人，洞庭風嫋嫋。"]'),
('5f0aa63c-956f-45bd-b518-0379665cc2c3','送吳令君','吳儆','宋','宋诗','song-poetry','','[]','吾欲贈君以彭澤江邊之柳，不如贈君以傅巖野外之梅。',88,'全唐诗/poet.song.126000.json','["吾欲贈君以彭澤江邊之柳，不如贈君以傅巖野外之梅。", "柳色但知管離別，梅花獨首百花開。", "花開雖托桃李徑，成實終爲廊廟材。", "冰霜清冷溪橋側，聊與人間作春色。", "日邊調鼎待君來，已聞驛使傳消息。"]'),
('9387e8ae-eb6d-44e6-aa59-ee999eb3205a','贈吳令君','吳儆','宋','宋诗','song-poetry','','[]','綠槐庭院鎖薰風，雙雙乳燕穿簾櫳。',224,'全唐诗/poet.song.126000.json','["綠槐庭院鎖薰風，雙雙乳燕穿簾櫳。", "石榴花蹙宮羅樣，荔子枝翻蜀錦紅。", "海山秀色藏日色，衮作英豪儀上國。", "鵬翼瀾翻徙北溟，龍媒夭矯東西極。", "高蹤逸韵不容攀，家聲世德以蟬聯。", "吏能精銳龔黄上，人物風流晉宋間。", "海寧巖邑千山底，牛刀割雞聊爾耳。", "卷入河陽滿縣花，風行鄭國垂街李。", "往歲如今杅桐空，今年衣褐足虞冬。", "往歲如今新陳腐，今年麰麥盈千鍾。", "田家宴喜歌時豐，咸知陰相有神功。", "炰羔擊豕趨城東，金璧樓臺煙靄中。", "瞻彼南山遥舉酒，插花起舞爲君壽。", "神人歡樂何其多，令君福祿如山河。"]'),
('7758ee6c-d01f-4c87-9246-04dc19a894e1','送王國器歸宣城','吳儆','宋','宋诗','song-poetry','','[]','吾不送君以南浦傷離之曲，吾不送君以渭城惜別之觴。',152,'全唐诗/poet.song.126000.json','["吾不送君以南浦傷離之曲，吾不送君以渭城惜別之觴。", "君今跨馬行遠陌，陌上槐花日已黄。", "槐花黄時舉子忙，君心應逐白雲翔。", "君來桃李春未晚，喜君幽韵如蘭芳。", "東風披拂香滿路，君不即人人豈忘。", "澄江靜練楚天長，疊嶂高樓秋月凉。", "使君高會羅紅粧，樽前醉客第王楊。", "明年上國富春光，風帘煙柳沙河塘。", "集英班退馬蹄疾，都人爭看綠衣郎。"]'),
('5c89e7e2-8e25-4641-826c-4a0ac6c8d648','題古巖舊嘗侍孫先生題名巖中二首  其一','吳儆','宋','宋诗','song-poetry','','[]','白日瀟瀟松徑靜，紅蕖冉冉洞門深。',64,'全唐诗/poet.song.126000.json','["白日瀟瀟松徑靜，紅蕖冉冉洞門深。", "風涵廣宇生虛籟，夢破西窗上夕陰。", "景物眼前渾似舊，塵埃題處忍重尋。", "羸驂落日孤村路，塵土依然滿病襟。"]'),
('3fb5719e-dbb6-471c-92c5-213a640a4ec0','題古巖舊嘗侍孫先生題名巖中二首  其二','吳儆','宋','宋诗','song-poetry','','[]','覆簣一拳進，嵌空百肘寬。',48,'全唐诗/poet.song.126000.json','["覆簣一拳進，嵌空百肘寬。", "僧房因石室，蟻穴夢槐安。", "塵路十年別，松風六月寒。", "凄凉舊題處，不忍更重看。"]'),
('bee90577-34e7-4902-a83d-1c2e85800f08','過叢桂堂故叔祖教授讀書之所','吳儆','宋','宋诗','song-poetry','','[]','古瓦頹垣迹已陳，孤猿別鶴自哀吟。',64,'全唐诗/poet.song.126000.json','["古瓦頹垣迹已陳，孤猿別鶴自哀吟。", "可憐叢桂煙蕪沒，惟有一池春水深。", "秀木千章新過雨，寒山一带暮傷心。", "清風明月時來此，夢斷雲飛何處尋。"]'),
('7e60a6cc-31f5-42b6-8d2c-a119e09edc3e','送洪史君赴闕移節會府','吳儆','宋','宋诗','song-poetry','','[]','史君文彩漢相如，暫向明時綰左符。',64,'全唐诗/poet.song.126000.json','["史君文彩漢相如，暫向明時綰左符。", "爲郡似家身似客，視民如子吏如奴。", "魯公金石光千古，吏部文章妙兩都。", "戴白垂髫相與語，如公治行向來無。"]'),
('01fbc96f-ab8b-40bb-9ad3-0dce1df0018c','酹月亭','吳儆','宋','宋诗','song-poetry','','[]','周郎人道古英雄，漢室顛危合奮忠。',64,'全唐诗/poet.song.126000.json','["周郎人道古英雄，漢室顛危合奮忠。", "萬里中原猶未復，一朝赤壁偶成功。", "新亭且對江山勝，陳迹俱隨歲月空。", "把酒仍歌前後賦，九原喚起老坡翁。"]'),
('156376f3-7306-4979-a85f-99a610b1bac0','和金尚書棣華堂詩韵','吳儆','宋','宋诗','song-poetry','','[]','自甘顔巷傳家學，敢比虞庠覿國光。',64,'全唐诗/poet.song.126000.json','["自甘顔巷傳家學，敢比虞庠覿國光。", "幸不北轅求適楚，寧須挾策去遊梁。", "下承上覆期相庇，蒂固根深會益芳。", "吾黨未能冥一唯，爲裁狂簡斐然章。"]'),
('08322e0b-b701-4c81-8d7e-f12a2b1be1e2','晚步','吳儆','宋','宋诗','song-poetry','','[]','水靜偏明眼，山高不受塵。',48,'全唐诗/poet.song.126000.json','["水靜偏明眼，山高不受塵。", "晴沙棲白鳥，野渡集歸人。", "問字誰持酒，行歌有負薪。", "娟娟孤月影，獨覺向人新。"]'),
('1141e837-13fe-4339-b2e1-85c81d891e26','拾梧子','吳儆','宋','宋诗','song-poetry','','[]','雞犬三家市，蓬蒿一畝宮。',48,'全唐诗/poet.song.126000.json','["雞犬三家市，蓬蒿一畝宮。", "春盤厭笋蕨，秋子積梧桐。", "客夢五年過，文盟千里同。", "時清臺省貴，衮衮看諸公。"]'),
('9c2ce677-c864-410a-8142-8ba12ef2c998','送錢虞仲兄弟','吳儆','宋','宋诗','song-poetry','','[]','燈火相從總角初，只今已是十年餘。',64,'全唐诗/poet.song.126000.json','["燈火相從總角初，只今已是十年餘。", "窮愁懶漫吾猶故，文采雍容子甚都。", "連璧肯來同寂寞，歸鞍寧不少躊躇。", "風流一別應如雨，儻有來鴻細作書。"]'),
('10abb86e-27a0-47c3-8c61-9a648405fc0e','次韵李提點雪中登樓之什二首  其一','吳儆','宋','宋诗','song-poetry','','[]','高情應與水雲寬，江北江南望渺漫。',64,'全唐诗/poet.song.126000.json','["高情應與水雲寬，江北江南望渺漫。", "逐馬銀盃端可賞，屯邊鐵甲得無寒。", "已知與國同休戚，且慶豐年表治安。", "殺氣已消春意動，曈曈日色上雲端。"]'),
('c43f1440-1f71-4015-b946-6ec6abeb6161','次韵李提點雪中登樓之什二首  其二','吳儆','宋','宋诗','song-poetry','','[]','朝來園柳變融和，深院啼鴉少客過。',64,'全唐诗/poet.song.126000.json','["朝來園柳變融和，深院啼鴉少客過。", "清坐漸看銀色遍，佳眠更覺溜聲多。", "謾誇明月舟中興，爭似銷金帳底歌。", "夜入蔡州擒叛將，擬將椽筆頌元和。"]'),
('fcdd4ba8-f5d8-45f4-97b2-dddc53e3bad4','和呂守環秀堂三首  其一','吳儆','宋','宋诗','song-poetry','','[]','久合鳴珂上九關，一麾猶許飽看山。',64,'全唐诗/poet.song.126000.json','["久合鳴珂上九關，一麾猶許飽看山。", "豐年諸縣公事少，燕寢清香兵衛閒。", "鳥度屏風明水鏡，雲生畫棟擁螺鬟。", "向來蛛網蝸涎污，勝處豈非天地慳。"]'),
('17218021-7b0b-4b38-97fd-a4c627bbae3f','和呂守環秀堂三首  其二','吳儆','宋','宋诗','song-poetry','','[]','一州如斗带溪山，空翠家家遶畫欄。',64,'全唐诗/poet.song.126000.json','["一州如斗带溪山，空翠家家遶畫欄。", "丘壑自非胸次有，雲煙誰暇靜中看。", "衣冠共識家風在，閭里方知漢法寬。", "戴白垂髫相與語，今年有飯飽加餐。"]'),
('c33689a9-50de-4c9c-b1b4-589ff65e932e','和呂守環秀堂三首  其三','吳儆','宋','宋诗','song-poetry','','[]','田家但識豐年樂，見說花城日更長。',64,'全唐诗/poet.song.126000.json','["田家但識豐年樂，見說花城日更長。", "如獲從公時拄笏，尚能援筆侑飛觴。", "雞豚社甕年年酒，柿栗園林樹樹霜。", "更倩漁郎問樵徑，深山深處是吾鄉。"]'),
('5cfe4e64-54d8-4de0-9750-b1043594158b','休日飲直之運屬家','吳儆','宋','宋诗','song-poetry','','[]','天與吾人臭味同，一官落魄郡城東。',64,'全唐诗/poet.song.126000.json','["天與吾人臭味同，一官落魄郡城東。", "偶逢休暇追鳬鶩，閒拂塵埃勘鼎鐘。", "適意不知華衮貴，醉餘聊看舞裙紅。", "只愁寒漏催羣動，又踏朝靴逐曉風。"]'),
('d340bfcb-46a0-4991-82c6-98ca7910ef5c','次徐令韵','吳儆','宋','宋诗','song-poetry','','[]','少日曾披九虎關，誰憐投老却乘邊。',64,'全唐诗/poet.song.126000.json','["少日曾披九虎關，誰憐投老却乘邊。", "貳車謾說半刺史，多稼惟欣大有年。", "榆柳關河無犬吠，牛羊阡陌斷烽煙。", "玉關人老知無用，廟算如今出萬全。"]'),
('3d8928ee-7fa1-47cd-a906-3052f0775111','還程彥舉詩卷','吳儆','宋','宋诗','song-poetry','','[]','文采於菟見一斑，舊知句法有淵源。',64,'全唐诗/poet.song.126000.json','["文采於菟見一斑，舊知句法有淵源。", "慇懃不廢琢磨力，圓熟幾無斧鑿痕。", "明日風煙空有夢，何時樽酒得重論。", "秋來景物皆佳句，寫寄銀鈎莫厭煩。"]'),
('29e55431-2f44-4658-904a-d431c8ad18f7','清明陰雨呈同舍','吳儆','宋','宋诗','song-poetry','','[]','薄薄輕寒作許陰，村村花柳爲誰新。',64,'全唐诗/poet.song.126000.json','["薄薄輕寒作許陰，村村花柳爲誰新。", "良辰欣見百五日，冠者仍餘五六人。", "冷雨凄風連午夜，飛花流水一年春。", "窺園未阻江東興，陌上應多翠黛顰。"]'),
('284ce8bd-1cd9-447f-ad72-0126b6adadd4','弋陽道中','吳儆','宋','宋诗','song-poetry','','[]','積雨今朝霽，東臯晚日紅。',48,'全唐诗/poet.song.126000.json','["積雨今朝霽，東臯晚日紅。", "人家深蔽樹，野水闊浮空。", "久客仍行役，青春已過中。", "嶺頭凝望處，腸斷白雲東。"]'),
('0e3c5899-7efd-48ae-aafe-b48ba571827c','和劉守韵','吳儆','宋','宋诗','song-poetry','','[]','使君元是一高僧，宿昔詩成自不禁。',64,'全唐诗/poet.song.126000.json','["使君元是一高僧，宿昔詩成自不禁。", "便合元劉論伯仲，豈同郊島費呻吟。", "浮雲出岫本無意，立雪齊腰謾覓心。", "掃灑煙塵須博大，看看九虎下綸音。"]'),
('c21d2a7a-7069-48ea-9045-742c7ad054b6','送張丞歸平江','吳儆','宋','宋诗','song-poetry','','[]','來何遲暮去何忙，不道離人欲斷腸。',64,'全唐诗/poet.song.126000.json','["來何遲暮去何忙，不道離人欲斷腸。", "清節如君誰可繼，遺風他日愈難忘。", "鱸肥酒熟歸時好，水綠山青去興長。", "便恐鵷行須簉羽，藍橋風月兩相忘。"]'),
('2a55a1ac-289c-4086-886a-52eeb8a14a85','次韵李提點雪中登樓之什','吳儆','宋','宋诗','song-poetry','','[]','樓高思遠入天涯，瑶海光中景象賒。',64,'全唐诗/poet.song.126000.json','["樓高思遠入天涯，瑶海光中景象賒。", "未說因風翻柳絮，須看和月上梅花。", "山茶有句真成畫，庭柏無心不受誇。", "人物梁園零落久，一時勝賞屬詩家。"]'),
('bb85d549-d618-4110-ac47-43af9c47336a','番陽道中','吳儆','宋','宋诗','song-poetry','','[]','畫楯朱甍綠靄中，華顛翠岫倚輕風。',32,'全唐诗/poet.song.126000.json','["畫楯朱甍綠靄中，華顛翠岫倚輕風。", "行人腸斷古烏處，猶在雲山東復東。"]'),
('5a8d3745-a1ad-4c62-84dd-9f5619655542','寓郡城客舍熱不可寐與程彥舉坐語達旦','吳儆','宋','宋诗','song-poetry','','[]','淡月微雲對倚樓，無聲河漢自西流。',32,'全唐诗/poet.song.126000.json','["淡月微雲對倚樓，無聲河漢自西流。", "高城忽起梅花弄，散作晴空萬里秋。"]'),
('a0b8949d-fde5-41da-8ebc-3b3dbf80cc68','壬午二月桃方盛開雪積其上光輝紅潤不可形狀以二詩紀之  其一','吳儆','宋','宋诗','song-poetry','','[]','夭桃先已醉春風，青女猶爭造化功。',32,'全唐诗/poet.song.126000.json','["夭桃先已醉春風，青女猶爭造化功。", "應與騷人嫌太赤，故將鉛粉注深紅。"]'),
('30da8362-a5d8-474f-81a6-fcef37a6ebf4','壬午二月桃方盛開雪積其上光輝紅潤不可形狀以二詩紀之  其二','吳儆','宋','宋诗','song-poetry','','[]','粲粲乘鸞萬玉妃，肯將紅豔鬭光輝。',32,'全唐诗/poet.song.126000.json','["粲粲乘鸞萬玉妃，肯將紅豔鬭光輝。", "只應侍宴瑶池罷，猶带天邊醉色歸。"]'),
('3a69d56d-1b7d-48e6-b6e1-e1a5daf58461','偶成','吳儆','宋','宋诗','song-poetry','','[]','晚來一雨破炎蒸，蕉葉葵花照眼明。',32,'全唐诗/poet.song.126000.json','["晚來一雨破炎蒸，蕉葉葵花照眼明。", "稍與燈花尋舊約，却嫌庭樹作秋聲。"]'),
('f48d8d56-ee54-4a62-82ac-21ef6e82228c','趙同叔開軒植竹以自娛樂諸公雖爲賦詩而未嘗有見之者某不日北歸同叔亦爲楚令尹矣詩以餽之  其一','吳儆','宋','宋诗','song-poetry','','[]','手種琅玕翠竹行，幽窗一見自心凉。',32,'全唐诗/poet.song.126000.json','["手種琅玕翠竹行，幽窗一見自心凉。", "君家有此揚州鶴，倦客無由對一觴。"]'),
('72e805c5-fe0f-4513-9585-fcd24420694d','趙同叔開軒植竹以自娛樂諸公雖爲賦詩而未嘗有見之者某不日北歸同叔亦爲楚令尹矣詩以餽之  其二','吳儆','宋','宋诗','song-poetry','','[]','夜來新月已如霜，倚玉縈風別是香。',32,'全唐诗/poet.song.126000.json','["夜來新月已如霜，倚玉縈風別是香。", "說與東君須早計，扁舟早晚下瀟湘。"]'),
('f64f14c0-0196-4aa6-a7a9-986264111465','寓壺源僧舍三絕  其一','吳儆','宋','宋诗','song-poetry','','[]','風簷淅淅褪新青，書展殘燈翳復明。',32,'全唐诗/poet.song.126000.json','["風簷淅淅褪新青，書展殘燈翳復明。", "讀罷離騷還獨坐，此時此夜若爲情。"]'),
('d958d9f1-c8e8-42ed-9159-8bc18f141d90','寓壺源僧舍三絕  其二','吳儆','宋','宋诗','song-poetry','','[]','悶來掩卷已三更，風露涓涓月滿庭。',32,'全唐诗/poet.song.126000.json','["悶來掩卷已三更，風露涓涓月滿庭。", "閒撲流螢衝暗樹，危梢點點墮寒星。"]'),
('7625ba9b-7f5f-434a-afa1-53769e586e5e','寓壺源僧舍三絕  其三','吳儆','宋','宋诗','song-poetry','','[]','歸來閉戶還高枕，窗隙微通月影斜。',32,'全唐诗/poet.song.126000.json','["歸來閉戶還高枕，窗隙微通月影斜。", "風急忽驚烏鵲起，空階蔌蔌墮松花。"]'),
('23c756fc-d634-4be1-b82d-758ae34c56fa','簟送人詩代簡二首  其一','吳儆','宋','宋诗','song-poetry','','[]','一幅冰紈織翠筠，風涵秋水碧鱗鱗。',32,'全唐诗/poet.song.126000.json','["一幅冰紈織翠筠，風涵秋水碧鱗鱗。", "北窗高卧正須此，捲似閑曹吏隠人。"]'),
('387dd9f1-b22e-4b2a-96e8-eef7353fa239','簟送人詩代簡二首  其二','吳儆','宋','宋诗','song-poetry','','[]','幽窗相對小匡牀，藍淺紗輕水麝香。',32,'全唐诗/poet.song.126000.json','["幽窗相對小匡牀，藍淺紗輕水麝香。", "退食歸來高枕處，滿林風雨夢瀟湘。"]'),
('4601147b-b673-4c21-b4c5-b749b508876b','題月巖','吳儆','宋','宋诗','song-poetry','','[]','題詩山寺不勝多，人力爭如造化何。',32,'全唐诗/poet.song.126000.json','["題詩山寺不勝多，人力爭如造化何。", "安得短篷巖下瀨，長看清影照寒波。"]'),
('3919cc39-ef39-4f4c-b001-2d8c3f6810aa','答范石湖牡丹詩','吳儆','宋','宋诗','song-poetry','','[]','滿城桃李已塵埃，麗日稠紅次第開。',32,'全唐诗/poet.song.126000.json','["滿城桃李已塵埃，麗日稠紅次第開。", "竹裏柴扉掩春晝，坐看蜂蝶去還來。"]'),
('aebb5556-3db2-4aeb-8fda-61544528575a','以烏紗巾餉客','吳儆','宋','宋诗','song-poetry','','[]','落托烏紗墊角巾，已將清泚滌京塵。',32,'全唐诗/poet.song.126000.json','["落托烏紗墊角巾，已將清泚滌京塵。", "請君便漉淵明酒，醉後從他雪滿簪。"]'),
('fb6ec1dd-2bd3-4105-9a8c-c38205d8b82b','題劉氏幽香亭','吳儆','宋','宋诗','song-poetry','','[]','雪後園林無限好，松間風月有餘清。',32,'全唐诗/poet.song.126000.json','["雪後園林無限好，松間風月有餘清。", "見他桃李動歸興，想見梅花不勝情。"]'),
('0712826b-2be5-4943-8b1e-1254821b9f9f','和張幹三公亭','吳儆','宋','宋诗','song-poetry','','[]','三公偉績絕前塵，千古凌煙向月明。',32,'全唐诗/poet.song.126000.json','["三公偉績絕前塵，千古凌煙向月明。", "剪盡甘棠殺風景，遺民猶記舊亭名。"]'),
('54d04249-465c-4a99-ae44-ea0b1a2b6e49','說謎三絕  其一','吳儆','宋','宋诗','song-poetry','','[]','滿身珠翠間花鈿，舞到梁州最可憐。',32,'全唐诗/poet.song.126000.json','["滿身珠翠間花鈿，舞到梁州最可憐。", "一捻宮腰如束素，清風明月畫堂前。"]'),
('968a2e20-343e-4e74-8841-dacc9fb4eec1','說謎三絕  其二','吳儆','宋','宋诗','song-poetry','','[]','楚楚衣裳兩頰紅，冠兒斜墜脚兒弓。',32,'全唐诗/poet.song.126000.json','["楚楚衣裳兩頰紅，冠兒斜墜脚兒弓。", "夜來塞上無消息，玉筯偷彈對曉風。"]'),
('18ee2754-4165-415d-ae34-3a17aaba057b','說謎三絕  其三','吳儆','宋','宋诗','song-poetry','','[]','奔波來往一生忙，方寸包藏不可量。',32,'全唐诗/poet.song.126000.json','["奔波來往一生忙，方寸包藏不可量。", "用盡心機還骨立，爲他人作嫁衣裳。"]'),
('bde7f4b6-a1b9-46f7-ad1c-ed82dfdcda83','宴邕守樂語','吳儆','宋','宋诗','song-poetry','','[]','騶馭曾鳴帝里珂，一麾出守古牂牁。',64,'全唐诗/poet.song.126000.json','["騶馭曾鳴帝里珂，一麾出守古牂牁。", "龍媒入貢漢天子，銅柱重聞馬伏波。", "萬里爭傳麒麟像，滿城歡唱舊襦歌。", "著人茉莉花如雪，不醉花前花奈何。"]'),
('4497c2d2-55ee-4b9b-8c62-634ca735d6ae','甲辰春蒙恩召試時年六十  其一','姜特立','宋','宋诗','song-poetry','','[]','霜滿頤間雪滿簪，已甘蕭散卧山林。',32,'全唐诗/poet.song.126000.json','["霜滿頤間雪滿簪，已甘蕭散卧山林。", "如何六十公孫子，尚作當年舉子心。"]'),
('2a048856-44fd-46ea-801c-295f1f8d57ea','甲辰春蒙恩召試時年六十  其二','姜特立','宋','宋诗','song-poetry','','[]','君王初未識相如，誰與慇勤薦子虛。',32,'全唐诗/poet.song.126000.json','["君王初未識相如，誰與慇勤薦子虛。", "莫笑粗官便無用，粗官也解試中書。"]'),
('2fed1a7b-b9ff-440b-b9ed-b6103b89113c','恭和御製玉津園詩','姜特立','宋','宋诗','song-poetry','','[]','輦路雲開雨脚踈，君王游樂萬幾餘。',64,'全唐诗/poet.song.126000.json','["輦路雲開雨脚踈，君王游樂萬幾餘。", "滄波不盡烟中景，清唱忽來江上漁。", "此日丹青須立本，何人詞賦似相如。", "小臣賡載無他語，但詠山河壯帝居。"]'),
('3d9c7546-9018-4879-b275-09e121a4b62b','松石歌壽皇太子殿下','姜特立','宋','宋诗','song-poetry','','[]','萬生總總各殊稟，中間變化通希夷。',252,'全唐诗/poet.song.126000.json','["萬生總總各殊稟，中間變化通希夷。", "大椿一萬八千歲，蟠桃結實千年期。", "雖云閲世最久遠，要自與物同推移。", "不如長松老爲石，仙家舊事尤瓌奇。", "嘗聞道士馬自然，曾見天寶觀前屈鐵枝。", "指云此木三千年，去後合變堅凝姿。", "當時山上五里松，龍拏虎蹲相與蛻化無餘遺。", "六丁夜半奉玉敕，雷公䃸磹轟取之。", "陽侯河伯亦好事，洪濤巨浪移荒陂。", "至今空山斷壑所，遺者一塊未許千金窺。", "壺山柏木不足道，康干節理由人爲。", "何如此石最耐久，萬年千載無成虧。", "上不爲女媧補天闕，下不爲顓皇搘地維。", "直將送似廣成子，日與西母對坐同盤嬉。", "蓬萊海水會清淺，廣成之壽無窮時。"]'),
('0c01567a-c988-41f5-bdbc-bc04b6aebb03','仰和令製臘中三白','姜特立','宋','宋诗','song-poetry','','[]','六花紛委地，隨物賦圓方。',48,'全唐诗/poet.song.126000.json','["六花紛委地，隨物賦圓方。", "未戒土牛候，先呈玉馬祥。", "月孤難耀彩，句妙與爭光。", "不獨誇三白，深宜熟五粱。"]'),
('db9cbb1b-fddd-4213-961f-0bb3ed2d98b0','木犀','姜特立','宋','宋诗','song-poetry','','[]','木芙蓉蕊未經霜，籬畔黄花尚歛房。',64,'全唐诗/poet.song.126000.json','["木芙蓉蕊未經霜，籬畔黄花尚歛房。", "正冷落中才吐艷，不思量處猛聞香。", "釀成雲壑澄清氣，滌盡炎鄉熱惱腸。", "便欲架巢枝上宿，學他徐老愛花狂。"]'),
('22860365-5be9-4123-bb4f-3a8a478be72f','西湖素公愛余泊舟小詩畫爲扇子','姜特立','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老子詩中那有畫，阿師畫裏自兼詩。',64,'全唐诗/poet.song.126000.json','["老子詩中那有畫，阿師畫裏自兼詩。", "我非今世王摩詰，子豈前身李伯時。", "烟月正臨青嶂落，灘聲惟許白鷗知。", "可憐半幅鵝溪絹，寫此寒江一段奇。"]'),
('97eecfd6-1e51-4ce2-9df6-5b54b6f141f8','早朝','姜特立','宋','宋诗','song-poetry','','[]','迷曉逆風飄漏遠，驚秋堕葉響廊深。',32,'全唐诗/poet.song.126000.json','["迷曉逆風飄漏遠，驚秋堕葉響廊深。", "五更又上籃輿去，忘却當年調笑吟。"]'),
('c7fac2fc-4c2b-45b8-8624-6ad5a5253ef0','寄華亭黄用之','姜特立','宋','宋诗','song-poetry','','[]','陸機不聽華亭鶴，張翰還思吳郡鱸。',32,'全唐诗/poet.song.126000.json','["陸機不聽華亭鶴，張翰還思吳郡鱸。", "何似故人無一事，菊花時節獨携壺。"]'),
('ff123842-1720-4075-a732-4ebd9c44048e','謝人惠詩二首  其一','姜特立','宋','宋诗','song-poetry','','[]','鑪鎚鍛鍊不遺力，造化窮鎪無遁情。',32,'全唐诗/poet.song.126000.json','["鑪鎚鍛鍊不遺力，造化窮鎪無遁情。", "每對時人思杜老，不知能事屬先生。"]'),
('228c62d3-c8f0-4731-8abc-5f04da61f875','謝人惠詩二首  其二','姜特立','宋','宋诗','song-poetry','','[]','九攻莫下墨子守，一矢難摧飛衛鋒。',32,'全唐诗/poet.song.126000.json','["九攻莫下墨子守，一矢難摧飛衛鋒。", "始悟從前最高著，向來未肯付渠儂。"]'),
('9910d4fa-ce2f-4efb-9cf1-4deb4dd3f78f','偶題','姜特立','宋','宋诗','song-poetry','','[]','莫恨盧姬嫁得遲，尚能料理舊容儀。',32,'全唐诗/poet.song.126000.json','["莫恨盧姬嫁得遲，尚能料理舊容儀。", "班姑陳后承恩早，衰悴難堪似少時。"]'),
('3d08076f-a57a-4f4e-8541-9690063888e2','歲暮直舍感懷','姜特立','宋','宋诗','song-poetry','','[]','歲暮坐公館，永懷時序遷。',48,'全唐诗/poet.song.126000.json','["歲暮坐公館，永懷時序遷。", "雪消殘臈外，春到蚤梅邊。", "夜色侵烏鵲，年光送管絃。", "無人同晤語，輸寫頼詩篇。"]'),
('53b677af-1b0a-4a5b-9809-4849bb1a2edd','道堂以梅結屏','姜特立','宋','宋诗','song-poetry','','[]','歲寒三友要君知，不比凡花兒女姿。',64,'全唐诗/poet.song.126000.json','["歲寒三友要君知，不比凡花兒女姿。", "頗愛槎枒却高古，正嫌糾結玷幽奇。", "豪夸何用錦爲障，瀟洒須添露作帷。", "可是道人多事在，橫斜請看昔賢詩。"]'),
('5808d551-b746-44e1-b8a5-b59816d81274','偶題','姜特立','宋','宋诗','song-poetry','','[]','花事匆匆一餉空，清和池館轉薰風。',32,'全唐诗/poet.song.126000.json','["花事匆匆一餉空，清和池館轉薰風。", "綠陰似欲專清夏，不許林間見落紅。"]'),
('549603c2-f525-4532-bbfa-7c0ae00760a1','借書戲作','姜特立','宋','宋诗','song-poetry','','[]','無書閲市交何少，有書覓羊趣何卑。',32,'全唐诗/poet.song.126000.json','["無書閲市交何少，有書覓羊趣何卑。", "爭似北鄰兩公子，不嫌俗士笑渠癡。"]'),
('9be13e8c-e0fc-4e95-89b2-ac19f9615369','借庵  其一','姜特立','宋','宋诗','song-poetry','','[]','吾師自有庵，何必從人借。',24,'全唐诗/poet.song.126000.json','["吾師自有庵，何必從人借。", "聞道架虛空，大千同一舍。"]'),
('e55ceac0-00be-4b11-bd93-8d80a7a29316','借庵  其二','姜特立','宋','宋诗','song-poetry','','[]','天地即吾廬，胡爲號借居。',24,'全唐诗/poet.song.126000.json','["天地即吾廬，胡爲號借居。", "趙州無住著，不用更還渠。"]'),
('7c9672e1-7036-458c-9db1-29cb1a7fa079','覓龍涎巧石  其一','姜特立','宋','宋诗','song-poetry','','[]','何年雲斧斸煙巒，散在先生燕坐間。',32,'全唐诗/poet.song.126000.json','["何年雲斧斸煙巒，散在先生燕坐間。", "袖裏吾將有東海，憑詩乞與小巑岏。"]'),
('70ae176a-8bf2-4f74-840d-8f8663b1fdb2','覓龍涎巧石  其二','姜特立','宋','宋诗','song-poetry','','[]','甲蠡淺俗棗仍昏，沉水龍涎氣最芬。',32,'全唐诗/poet.song.126000.json','["甲蠡淺俗棗仍昏，沉水龍涎氣最芬。", "敢望凝香如燕寢，竹爐聊欲試氤氳。"]'),
('b256d275-c4a5-449d-a244-a1d2df7af14c','和徐判院見惠詩篇  其一','姜特立','宋','宋诗','song-poetry','','[]','姚魏誰教混草萊，今朝老眼爲君開。',32,'全唐诗/poet.song.126000.json','["姚魏誰教混草萊，今朝老眼爲君開。", "建安自有親衣鉢，知道詩翁不姓梅。"]'),
('50934417-4352-4cd3-8fbf-a6ca1db0aeca','和徐判院見惠詩篇  其二','姜特立','宋','宋诗','song-poetry','','[]','細知詩律析秋毫，况是天然筆力高。',32,'全唐诗/poet.song.126000.json','["細知詩律析秋毫，况是天然筆力高。", "便好鋪張清廟頌，不須追逐楚人騷。"]'),
('cec89c7a-4a8c-42a1-88a6-520ff9289b40','和徐判院見惠詩篇  其三','姜特立','宋','宋诗','song-poetry','','[]','新詩贈我繞朝鞭，敵手相逢一憮然。',32,'全唐诗/poet.song.126000.json','["新詩贈我繞朝鞭，敵手相逢一憮然。", "迦葉見花吾未解，靈均此秘子能傳。"]'),
('a2724a12-e8c5-410c-9257-3de9ae593473','和徐判院見惠詩篇  其四','姜特立','宋','宋诗','song-poetry','','[]','弔徃文高古戰場，麗天星斗射寒芒。',32,'全唐诗/poet.song.126000.json','["弔徃文高古戰場，麗天星斗射寒芒。", "也知深奪曹劉氣，不用濃熏班馬香。"]'),
('80ac6a58-dde4-4998-8a8e-b9542ec5938f','閏七夕','姜特立','宋','宋诗','song-poetry','','[]','此夕從來天上少，斜河休問夜何其。',32,'全唐诗/poet.song.126000.json','["此夕從來天上少，斜河休問夜何其。", "不須更恨歡娛短，已是人間十日期。"]'),
('935b6e6a-0d11-4944-850c-bae013389a41','同官直舍有木犀一株盛開與余脩竹惟隔屏牆爾暇日因共言清香綠陰不妨相過異時亦是一段佳話遂成小詩','姜特立','宋','宋诗','song-poetry','','[]','小山叢桂隔牆陰，曲檻脩篁別作林。',64,'全唐诗/poet.song.126000.json','["小山叢桂隔牆陰，曲檻脩篁別作林。", "芳意不孤符有德，寒梢相近本無心。", "春多得地生何幸，歲晚爲鄰分益深。", "頼有高人發佳致，因成盛事寄微吟。"]'),
('fb4dff38-e481-42b6-ae14-eed47670de71','送陳寺丞得請補外歸鄉','姜特立','宋','宋诗','song-poetry','','[]','京華正是熱官地，公獨胡爲起歸意。',96,'全唐诗/poet.song.126000.json','["京華正是熱官地，公獨胡爲起歸意。", "家傳相業百未施，請佩左符聊一試。", "相君道德人中英，達識早保懸車榮。", "君王屢詔不肯起，祇今父子俱芳馨。", "小春十月壺山尾，橘柚垂黄風日美。", "青衫昔出紫袍歸，拜壽雙親親色喜。"]'),
('577d95a0-977b-4b35-bce0-3614eb26a274','楊誠齋作日屋名小暘谷次其韻','姜特立','宋','宋诗','song-poetry','','[]','旋規暘谷敵霜天，掩映金烏上紫烟。',32,'全唐诗/poet.song.126000.json','["旋規暘谷敵霜天，掩映金烏上紫烟。", "困睡不愁揮甕肘，坐吟無復聳詩肩。"]'),
('eca78d4a-d02c-407c-bed1-367f2501b5e4','和張時可','姜特立','宋','宋诗','song-poetry','','[]','一榻蕭然文字林，閉門十日卧春陰。',64,'全唐诗/poet.song.126000.json','["一榻蕭然文字林，閉門十日卧春陰。", "園林寒重鶑聲寂，風雨時長草色深。", "坐念治聾違社酒，遥知搜句攪春心。", "莫愁鴈鶩分行進，簿領難埋曠士襟。"]'),
('176f0140-584e-4d77-9073-c50536985d1b','黄用之遷居奉寄  其一','姜特立','宋','宋诗','song-poetry','','[]','聞道秋來過別居，秋風應已入琴書。',32,'全唐诗/poet.song.126000.json','["聞道秋來過別居，秋風應已入琴書。", "草玄正要一區宅，入蜀何須駟馬車。"]'),
('e0ca413e-ca92-447d-bfe2-2a03d8553e15','黄用之遷居奉寄  其二','姜特立','宋','宋诗','song-poetry','','[]','盡傾清俸買新居，橐內無金只有書。',32,'全唐诗/poet.song.126000.json','["盡傾清俸買新居，橐內無金只有書。", "不用鄰人借輿馬，已知家具少於車。"]'),
('3ab648b9-0bab-43b7-8b1c-fae94ca4e80c','賦汪先輩昆仲聽雨軒','姜特立','宋','宋诗','song-poetry','','[]','堂堂兩蘇公，秀峙自西蜀。',180,'全唐诗/poet.song.126000.json','["堂堂兩蘇公，秀峙自西蜀。", "一朝入京師，聲價喧寥廓。", "聯翩取膴仕，鳴鳳在阿閣。", "方干赤霄上，忽向青雲落。", "黑風吹紫荆，天涯兩飄泊。", "始感韋郎詩，對床尋舊約。", "篇章屢致意，念此友于樂。", "生死竟乖違，歸來已非昨。", "汪君胡爲此，一官未渠縛。", "兄弟自師友，閉門方苦學。", "便作聽雨謀，無乃計已錯。", "早榮或有悔，晚達亦不惡。", "問學須淵源，文字要追琢。", "歲久道自富，時來功不薄。", "但學蘇公賢，嘲誚且莫莫。"]'),
('8f666372-3ffe-4e1a-a474-7100bb95927e','講官沈大監獻東宮米字回賜筆墨因作小詩以求墨','姜特立','宋','宋诗','song-poetry','','[]','聞道寶書天上去，却携香墨袖中歸。',64,'全唐诗/poet.song.126000.json','["聞道寶書天上去，却携香墨袖中歸。", "安西紙背曾題識，黟餠文房要發揮。", "素篋想藏玄玉炯，晴窗應試翠雲霏。", "先生不作曹瞞吝，分我東齋發易機。"]'),
('f866687a-17a7-4b51-9c67-27d6b14c3f45','題共閒亭五首  其一','姜特立','宋','宋诗','song-poetry','','[]','幾年玉殿領仙班，霜滿烏靴塵滿冠。',32,'全唐诗/poet.song.126000.json','["幾年玉殿領仙班，霜滿烏靴塵滿冠。", "寄語山花與溪鳥，今回莫作故吾看。"]'),
('c785208b-489e-4601-a312-fa14a2efa81a','題共閒亭五首  其二','姜特立','宋','宋诗','song-poetry','','[]','太行日暮車盤處，灧澦波翻舟下時。',32,'全唐诗/poet.song.126000.json','["太行日暮車盤處，灧澦波翻舟下時。", "惟有亭中無一事，坐看忙殺利名兒。"]'),
('f40768f1-0c45-4582-9532-30de90ce6d3f','題共閒亭五首  其三','姜特立','宋','宋诗','song-poetry','','[]','楊葉屢穿非是妙，庖刀未缺更須藏。',32,'全唐诗/poet.song.126000.json','["楊葉屢穿非是妙，庖刀未缺更須藏。", "何人識得閒三昧，袖手急流滋味長。"]'),
('c6437731-3e5a-42e9-88b5-c3c812d7888c','題共閒亭五首  其四','姜特立','宋','宋诗','song-poetry','','[]','花光摇曳猶多事，鳥語軥輈徒自喧。',32,'全唐诗/poet.song.126000.json','["花光摇曳猶多事，鳥語軥輈徒自喧。", "誰是如今愛閒者，請來此地說風幡。"]'),
('fc3bdcbe-5665-48ef-8b58-9b43a3f25d82','題共閒亭五首  其五','姜特立','宋','宋诗','song-poetry','','[]','競前正作螘旋磨，逐物方知鵲失真。',32,'全唐诗/poet.song.126000.json','["競前正作螘旋磨，逐物方知鵲失真。", "安得此身隨杖屨，却來堂上作閒人。"]'),
('ba403e60-f8b0-4faf-b8ac-9041cf558638','訪約齋三絕  其一','姜特立','宋','宋诗','song-poetry','','[]','滿城車馬隘如雲，百萬人家暗市塵。',32,'全唐诗/poet.song.126000.json','["滿城車馬隘如雲，百萬人家暗市塵。", "忽到南湖湖上看，始知物外有高人。"]'),
('21c6e741-16b2-431f-afdd-207ad6585b6c','訪約齋三絕  其二','姜特立','宋','宋诗','song-poetry','','[]','雲鏡亭前水滿陂，渚漚堤上翠成帷。',32,'全唐诗/poet.song.126000.json','["雲鏡亭前水滿陂，渚漚堤上翠成帷。", "煩君爲我買笭箵，去作南湖踏浪兒。"]'),
('8064bad0-7e9b-4183-9244-8a8afae2403e','訪約齋三絕  其三','姜特立','宋','宋诗','song-poetry','','[]','城中不異在郊坰，百畝園池夏木清。',32,'全唐诗/poet.song.126000.json','["城中不異在郊坰，百畝園池夏木清。", "若爲借我三間屋，相伴哦詩過一生。"]'),
('6cd09cd5-20b2-467c-9fc5-84bd262277cc','和張倅湖上十絕  其一','姜特立','宋','宋诗','song-poetry','','[]','曾訪高人舊隠居，詩情平澹宦情踈。',32,'全唐诗/poet.song.126000.json','["曾訪高人舊隠居，詩情平澹宦情踈。", "緹屏今日雖泥軾，芸閣它時合校書。"]'),
('3a055ab1-7563-4661-aebe-36701d0a5dbb','和張倅湖上十絕  其二','姜特立','宋','宋诗','song-poetry','','[]','曠士同游興自濃，那堪霽景上曈矓。',32,'全唐诗/poet.song.126000.json','["曠士同游興自濃，那堪霽景上曈矓。", "忽驚畫手開千嶂，不見愁眉蹙兩峯。"]'),
('a69ad251-082b-4d0e-ae3b-fa9c6eb6e9d2','和張倅湖上十絕  其三','姜特立','宋','宋诗','song-poetry','','[]','湖邊柳色媚清漣，湖上新荷疊綺錢。',32,'全唐诗/poet.song.126000.json','["湖邊柳色媚清漣，湖上新荷疊綺錢。", "料得高人初出郭，眼中風物一醒然。"]'),
('c6488a03-d8a4-4900-9655-e180572e547e','和張倅湖上十絕  其四','姜特立','宋','宋诗','song-poetry','','[]','仙山那許世人來，有底今朝洞戶開。',32,'全唐诗/poet.song.126000.json','["仙山那許世人來，有底今朝洞戶開。", "青鳥想傳佳客至，不須驚汝問莓苔。"]'),
('2fc68939-65c2-4b8f-96ef-49f037fc09cb','和張倅湖上十絕  其五','姜特立','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','休日吟邊引興長，豈容簿領更相妨。',32,'全唐诗/poet.song.126000.json','["休日吟邊引興長，豈容簿領更相妨。", "怪君詩思如河决，曾夢西江水滌腸。"]'),
('d455fb2f-ccc7-4691-9608-e08354184d94','和張倅湖上十絕  其六','姜特立','宋','宋诗','song-poetry','','[]','寶叔祠前落照紅，平湖萬頃碧涵空。',32,'全唐诗/poet.song.126000.json','["寶叔祠前落照紅，平湖萬頃碧涵空。", "箇中有景君能道，添入三賢詩句中。"]'),
('d03223b4-db9b-4fd1-9a7e-52dd9bf39a31','和張倅湖上十絕  其七','姜特立','宋','宋诗','song-poetry','','[]','群彥俱堪議相氈，小詩聊爾出穠纖。',32,'全唐诗/poet.song.126000.json','["群彥俱堪議相氈，小詩聊爾出穠纖。", "梅山老子何多幸，收得連珠歸玉奩。"]'),
('31975954-bd24-4c48-b569-3bd7bc136b3c','和張倅湖上十絕  其八','姜特立','宋','宋诗','song-poetry','','[]','盡將丘壑捲胸中，醉帽歸時御晚風。',32,'全唐诗/poet.song.126000.json','["盡將丘壑捲胸中，醉帽歸時御晚風。", "明日府公催吏牘，可堪騎馬踏香紅。"]'),
('c974d676-62ab-43ce-a158-1a70fa0a776a','和張倅湖上十絕  其九','姜特立','宋','宋诗','song-poetry','','[]','兩山勝處古墳多，多少英賢發詠歌。',32,'全唐诗/poet.song.126000.json','["兩山勝處古墳多，多少英賢發詠歌。", "它日浮家釣清瀨，腰章吾欲換漁蓑。"]'),
('f7fa468d-8a24-40e8-a3a4-72d682914cde','和張倅湖上十絕  其一○','姜特立','宋','宋诗','song-poetry','','[]','夕寒山水閟清暉，歸到華堂月半扉。',32,'全唐诗/poet.song.126000.json','["夕寒山水閟清暉，歸到華堂月半扉。", "傾倒錦囊無賸語，風光那得更相違。"]'),
('c711158c-6e06-4c48-9820-7d009746b704','直舍作小砌','姜特立','宋','宋诗','song-poetry','','[]','直廬迫高墉，隙土止尋丈。',96,'全唐诗/poet.song.126000.json','["直廬迫高墉，隙土止尋丈。", "杇人累殘甓，園叟舁新壤。", "方成一簣積，已覺寸心爽。", "餘芳分禁掖，疎翠眇林莽。", "雖無崑閬趣，便有濠濮想。", "繞吟消永日，靜對延孤賞。", "聊成兒女劇，終契山林往。", "爲語平泉公，經營毋太廣。"]'),
('ca976e28-e773-4ac3-ab14-aa689b3b51d7','續麗人行','姜特立','宋','宋诗','song-poetry','','[]','畫師不作春風面，豈是玉容容易見。',158,'全唐诗/poet.song.126000.json','["畫師不作春風面，豈是玉容容易見。", "動人正在阿堵中，妙處猶須著歌扇。", "沉香亭邊初睡起，鬒髮瓏鬆薄梳理。", "欠伸背面故作妍，半靨牆頭出桃李。", "畫成衆目爭回顧，只欠孫娘折腰步。", "似見不見愁殺人，始是人生腸斷處。", "愁腸易斷可奈何，古往今來此恨多。", "君不見李夫人，不肯回身看漢君。", "又不見楊太真，擁行莫戀屬車塵。", "自古蛾眉多蠹國，玉顔畫就還傷神。"]'),
('89c47929-22a1-41af-b07b-7e7f5544a175','中秋寓直東宮是夕當月蝕雲興不見','姜特立','宋','宋诗','song-poetry','','[]','中秋令節每多陰，况復清居鶴禁深。',64,'全唐诗/poet.song.126000.json','["中秋令節每多陰，况復清居鶴禁深。", "幸免蝦蟆矜毒吻，不妨蟋蟀伴孤吟。", "連旬病腹難容酒，獨夜清眠不愧衾。", "二八孤光應未闕，小樓猶得共登臨。"]'),
('a14a6850-8081-403d-bd46-2d06a9e8124e','謝楊誠齋惠長句','姜特立','宋','宋诗','song-poetry','','[]','平生久矣服時名，况復親聞玉唾聲。',64,'全唐诗/poet.song.126000.json','["平生久矣服時名，况復親聞玉唾聲。", "便擬近師黄太史，不須遠慕白先生。", "巨編固已汗牛積，長句尤能倚馬成。", "今日詩壇誰是主，誠齋詩律正施行。"]'),
('8262ae2a-42d7-4093-970c-e7f05f143788','和答劉慶遠','姜特立','宋','宋诗','song-poetry','','[]','夙昔何嘗卑小官，已將富貴等閒看。',64,'全唐诗/poet.song.126000.json','["夙昔何嘗卑小官，已將富貴等閒看。", "科名不上韓公榜，事業難登漢將壇。", "念舊詎能忘里社，避喧終欲掛朝冠。", "故人不爲吟招隠，更極吹噓借羽翰。"]'),
('d46a5187-cb12-46d2-92ea-4c2c504568b6','人惠酴醿','姜特立','宋','宋诗','song-poetry','','[]','少年著意玩時芳，每愛風枝玉雪揚。',32,'全唐诗/poet.song.126000.json','["少年著意玩時芳，每愛風枝玉雪揚。", "老去此心渾忘却，不堪猶作故時香。"]'),
('e6a05a26-35fc-4cec-bd91-d8fc48f1d30c','使北二首  其一','姜特立','宋','宋诗','song-poetry','','[]','萬里持哀使北荒，偶能成禮報君王。',32,'全唐诗/poet.song.126000.json','["萬里持哀使北荒，偶能成禮報君王。", "中原舊事成新恨，添得歸來兩鬢霜。"]'),
('3a431054-cd4a-4359-81bc-90a734429697','使北二首  其二','姜特立','宋','宋诗','song-poetry','','[]','略無險阻蔽皇居，底事當時醉寐如。',32,'全唐诗/poet.song.126000.json','["略無險阻蔽皇居，底事當時醉寐如。", "若使賈生參國論，便應咽死更無書。"]'),
('b259cfc4-3ec6-4ba5-99bd-27821aa309a1','使北','姜特立','宋','宋诗','song-poetry','','[]','持哀萬里敢辭難，汴泗都歸指顧間。',64,'全唐诗/poet.song.126000.json','["持哀萬里敢辭難，汴泗都歸指顧間。", "車上去程依北斗，馬頭歸夢到南山。", "頗驚魏國山河少，尚覺周家境土慳。", "聖主若圖恢復計，直須神武取榆關。"]'),
('3d3726f3-ecd1-42b4-8735-7c48c4c5230f','渡淮喜而有作','姜特立','宋','宋诗','song-poetry','','[]','船過淮南岸，心如已到家。',48,'全唐诗/poet.song.126000.json','["船過淮南岸，心如已到家。", "何常異風景，正爾辨戎華。", "病體辭深轍，征衣脫舊沙。", "江南即仙國，何必上星槎。"]'),
('cea1653d-6a5d-4c6f-9b95-a3ac10904503','賦張舍人抱嘯堂五首  其一','姜特立','宋','宋诗','song-poetry','','[]','長身踽踽萬夫雄，抵掌燕然立駿功。',32,'全唐诗/poet.song.126000.json','["長身踽踽萬夫雄，抵掌燕然立駿功。", "韜畧故家傳圯上，行藏高志似隆中。"]'),
('ccfbd543-a648-4fab-b2d9-6a832856e50e','賦張舍人抱嘯堂五首  其二','姜特立','宋','宋诗','song-poetry','','[]','自古英雄困里閭，風雲相遇藉吹噓。',32,'全唐诗/poet.song.126000.json','["自古英雄困里閭，風雲相遇藉吹噓。", "何人得似徐元直，說與君王蚤顧廬。"]'),
('e66e291c-7451-49c8-8bf2-a9ca8de0b81b','賦張舍人抱嘯堂五首  其三','姜特立','宋','宋诗','song-poetry','','[]','不擁吳姝與趙姬，不箋爾雅作書癡。',32,'全唐诗/poet.song.126000.json','["不擁吳姝與趙姬，不箋爾雅作書癡。", "只今抱膝緣何事，北望中原有所思。"]'),
('c307229e-f0f5-493c-a33c-db2bd9fb6dfe','賦張舍人抱嘯堂五首  其四','姜特立','宋','宋诗','song-poetry','','[]','餘子紛紛見每卑，鸞凰鷄鶩謾相隨。',32,'全唐诗/poet.song.126000.json','["餘子紛紛見每卑，鸞凰鷄鶩謾相隨。", "當時一笑無人解，此意寧容俗士知。"]'),
('9af1ceaa-75d7-4135-97b9-6e4a354095b4','賦張舍人抱嘯堂五首  其五','姜特立','宋','宋诗','song-poetry','','[]','毛生脫穎請行日，祖逖聞鷄起舞時。',32,'全唐诗/poet.song.126000.json','["毛生脫穎請行日，祖逖聞鷄起舞時。", "何似草廬長嘯罷，從容起立漢家基。"]'),
('791adf8e-fa29-44bc-99c4-fd2f04b21114','禁中聞杜鵑','姜特立','宋','宋诗','song-poetry','','[]','飛叫入仙城，千門夜未扃。',24,'全唐诗/poet.song.126000.json','["飛叫入仙城，千門夜未扃。", "那知清禁裏，却有野人聽。"]'),
('778db4f3-2427-4adb-b5a3-2040b3d8f2e5','苦熱二首  其一','姜特立','宋','宋诗','song-poetry','','[]','天地無情處，青林不動時。',48,'全唐诗/poet.song.126000.json','["天地無情處，青林不動時。", "扇車熱爐鞴，竹簟煖琉璃。", "蟬喘烟生樹，蚊饕汗浹肌。", "不知秋後鬢，留得幾莖絲。"]'),
('c0c1657e-57fb-4a77-83c7-f8dd4c7f11a9','苦熱二首  其二','姜特立','宋','宋诗','song-poetry','','[]','寸炬已如灼，積冰殊未凉。',48,'全唐诗/poet.song.126000.json','["寸炬已如灼，積冰殊未凉。", "禦寒終有具，治熱更無方。", "坐溜午時汗，狂尋子夜漿。", "如何得鄒律，吹下九秋霜。"]'),
('7aac79d1-79fe-4f64-936b-7dd8c18ecf0f','潘德久永嘉佳士也聞其能詩久矣而不我過僕一日以小詩挑之遂携古風見訪次韵奉答','姜特立','宋','宋诗','song-poetry','','[]','聞名渴見面，未合長相思。',120,'全唐诗/poet.song.126000.json','["聞名渴見面，未合長相思。", "紛紛數來人，誰契此心期。", "識公恨不早，委刺方嫌遲。", "正欲我輩人，共此一段奇。", "良賈雖深藏，有寶人得知。", "被褐既懷玉，脫囊可無錐。", "聊將一縷麻，換此五色絲。", "曲意相假借，仁衷恕嘲嗤。", "子懷諒已伸，我慚亦自貽。", "此道久凋喪，相從當在茲。"]'),
('eb76e009-da19-4bc1-a23f-c03932599982','陸嚴州惠劍南集','姜特立','宋','宋诗','song-poetry','','[]','不躡江西籬下跡，遠追李杜與翱翔。',64,'全唐诗/poet.song.126000.json','["不躡江西籬下跡，遠追李杜與翱翔。", "流傳何止三千首，開闔無疑萬丈光。", "句到桐江賸深穩，氣含玉壘舊飄揚。", "未須料理林間計，蚤晚明堂要雅章。"]'),
('c3cb3738-6ae0-4635-96e1-8b105c9f05a5','送宇文尚書歸蜀之官遂寧','姜特立','宋','宋诗','song-poetry','','[]','吾聞峨眉秀絕幾千古，下有人才紛可數。',146,'全唐诗/poet.song.126000.json','["吾聞峨眉秀絕幾千古，下有人才紛可數。", "長公少公兩玉人，一以爲龍一爲虎。", "先生晚出躡其後，萬里東來謁明主。", "青衫羸馬百官底，一紀重經啟封土。", "要將馮翊試長材，故向蓬溪開督府。", "當時三鱣張講肆，今日雙麾趨郡所。", "白頭老父來挽舟，朱組門生爭負弩。", "莫辭迢遞溯夔峽，便見奔騰下牛渚。", "西川東國一陶鈞，盡灑沙堤丞相雨。"]'),
('a94fa163-cc06-4df0-b608-bb95b30003d4','送米與人','姜特立','宋','宋诗','song-poetry','','[]','乞米未傷廉，送米豈爲辱。',48,'全唐诗/poet.song.126000.json','["乞米未傷廉，送米豈爲辱。", "且炊子美飯，試慁伯夷腹。", "雖無乳烝豚，便可蔬當肉。", "料得賢孟光，舉案懽自足。"]'),
('51f08181-561b-4342-a927-2c77eebf59d3','和劉建昌除夕有欠我飲屠蘇之句','姜特立','宋','宋诗','song-poetry','','[]','閒愁客底費驅除，可復先生得自娛。',64,'全唐诗/poet.song.126000.json','["閒愁客底費驅除，可復先生得自娛。", "商陸火添人獨坐，沉檀香冷歲還徂。", "望家年甲那堪數，祭酒詩神合少蘇。", "來歲黄堂當此夕，不知能解寄詩無。"]'),
('7efcd8cd-14d6-4688-8303-491fb7ab8196','扈駕青城呈劉建昌','姜特立','宋','宋诗','song-poetry','','[]','閶闔門開紫禁通，金梔千炬蠟花紅。',64,'全唐诗/poet.song.126000.json','["閶闔門開紫禁通，金梔千炬蠟花紅。", "胡爲白水漁竿客，也在黄幡豹尾中。", "三徑只今荒未了，一尊何日屬相同。", "寒儒不恨遭逢晚，猶勝書窗老蠹蟲。"]'),
('5b28dcc2-3e3f-44b0-96ba-402b05a0263b','和劉建昌都下立春','姜特立','宋','宋诗','song-poetry','','[]','岧嶢天闕五雲飛，日上觚稜曉影移。',64,'全唐诗/poet.song.126000.json','["岧嶢天闕五雲飛，日上觚稜曉影移。", "合殿侍臣頒綵樹，誰家纖手送青絲。", "寒禁粉蕊香猶淺，煖入陳根綠尚遲。", "從此江山春意動，使君拚費幾多詩。"]'),
('0d7bd135-c378-409e-bf2d-58982b429011','賦桐廬陳守瑞粟圖','姜特立','宋','宋诗','song-poetry','','[]','仲尼不瑞麟，周公旅命禾。',247,'全唐诗/poet.song.126000.json','["仲尼不瑞麟，周公旅命禾。", "兩聖本一道，胡爲有殊差。", "麟固首四靈，可賀亦可嗟。", "或云一角獸，莫能辨真訛。", "鶡雀奏天子，朱鴈興樂歌。", "文士頌連理，野夫獻嘉瓜。", "羽毛草木異，皆物之精華。", "於事竟無補，徒然務矜誇。", "食乃民之天，有一皆可嘉。", "君不見豐年樂歲人鼓腹，凶年死人如亂麻。", "以此較得失，周孔道不頗。", "桐廬陳使君，理道蠲煩苛。", "蠱敝既振飭，刑罰從寬科。", "民生樂其業，自足致時和。", "有農獻嘉粟，累累來山阿。", "數穗至八九，紛然一何多。", "圖狀競傳玩，誌牒爭編摩。", "使君政將成，爲祥理則那。", "促歸不待滿，合上金鑾坡。", "嘉禾闕補亡，精筆非君何。"]'),
('7fcfc1cd-a856-431f-a21f-daac98c54ea9','早朝','姜特立','宋','宋诗','song-poetry','','[]','欹眠側耳數寒更，欲起未起心不平。',32,'全唐诗/poet.song.126000.json','["欹眠側耳數寒更，欲起未起心不平。", "何似山間渾睡足，卧看紅日上窗明。"]'),
('96ef7bc5-de48-4d47-8aed-72064913436e','蛺蝶二首  其一','姜特立','宋','宋诗','song-poetry','','[]','水上蜻蜓木上蟬，醯鷄飛舞甕中天。',32,'全唐诗/poet.song.126000.json','["水上蜻蜓木上蟬，醯鷄飛舞甕中天。", "如何爾獨多情思，結得千花百卉緣。"]'),
('f04674e5-cca2-4ac7-862a-85e5477d8753','蛺蝶二首  其二','姜特立','宋','宋诗','song-poetry','','[]','園林五月綠漫漫，雨後輕狂尚作團。',32,'全唐诗/poet.song.126000.json','["園林五月綠漫漫，雨後輕狂尚作團。", "夏老不知花事退，猶疑春色在欄干。"]'),
('9ce5c177-1633-4ca5-b21f-7b813ee8195f','和陸郎中放翁韵','姜特立','宋','宋诗','song-poetry','','[]','遥知三徑長荒苔，解組東歸亦快哉。',64,'全唐诗/poet.song.126000.json','["遥知三徑長荒苔，解組東歸亦快哉。", "津岸紛紛群吏去，船頭衮衮好山來。", "平時佳客應相過，勝日清尊想屢開。", "若許詩篇數還往，直須共挽古風回。"]'),
('87edf736-4bd9-4724-a4b3-de9d659377bc','得句','姜特立','宋','宋诗','song-poetry','','[]','得句勝於得好官，平生事業蠹魚間。',32,'全唐诗/poet.song.126000.json','["得句勝於得好官，平生事業蠹魚間。", "近來世味尤如蠟，唯有吟詩不奈閒。"]'),
('fb81b781-62f7-4bb9-bd97-1be75ce940e1','偶成','姜特立','宋','宋诗','song-poetry','','[]','盥面知新瘦，看書覺近昏。',24,'全唐诗/poet.song.126000.json','["盥面知新瘦，看書覺近昏。", "風霜不相貸，老意與誰論。"]'),
('3dd4487a-d760-4acf-a626-a4188809870c','聖駕幸東宮','姜特立','宋','宋诗','song-poetry','','[]','仙仗天臨下五雲，承華氣象一時新。',64,'全唐诗/poet.song.126000.json','["仙仗天臨下五雲，承華氣象一時新。", "薰風澹蕩飄黄繖，瑞腦紛紜點翠裀。", "綵服戲時天一笑，寶巵捧處日重輪。", "從今家國同休慶，且壽雙親一萬春。"]'),
('d48ecda2-7438-42bb-b278-0c440f128041','海棠','姜特立','宋','宋诗','song-poetry','','[]','絢麗繁霞綵，熒煌瑞錦堆。',24,'全唐诗/poet.song.126000.json','["絢麗繁霞綵，熒煌瑞錦堆。", "夜深疑睡去，日暖怕慵來。"]'),
('b1e9d760-827a-4009-879e-e5643aafde74','柳絮','姜特立','宋','宋诗','song-poetry','','[]','隨風弄日碎春雲，撲戶穿帷惱殺人。',32,'全唐诗/poet.song.126000.json','["隨風弄日碎春雲，撲戶穿帷惱殺人。", "底事飄揚少拘束，愛將豪縱去酬春。"]'),
('547e7fd2-2fca-49c0-8103-f3ed63a9cd48','丁未九日青宮侍飲','姜特立','宋','宋诗','song-poetry','','[]','重陽開燕侍清躬，次第携壺到菊叢。',32,'全唐诗/poet.song.126000.json','["重陽開燕侍清躬，次第携壺到菊叢。", "仙手撚花親泛酒，此時榮遇少人同。"]'),
('b224215d-0d97-415b-9f83-fd4b7e95c817','次韵木犀','姜特立','宋','宋诗','song-poetry','','[]','老火西馳燒鄧林，此花孤絕更清深。',64,'全唐诗/poet.song.126000.json','["老火西馳燒鄧林，此花孤絕更清深。", "犀紋隠隠通肌骨，羽葆層層間彩金。", "殘蕊尚堪然古鼎，生香長得汎秋砧。", "形容盡入詩人筆，不爲唐賢歎陸沉。"]'),
('4b4744e6-d7d8-4cd3-9e4f-a07e4991e68e','石盆水窠','姜特立','宋','宋诗','song-poetry','','[]','數葉玉簪敷翠，一拳水石含秋。',28,'全唐诗/poet.song.126000.json','["數葉玉簪敷翠，一拳水石含秋。", "何須坐我濠濮，自覺心清境幽。"]'),
('6693a7e8-9781-41a3-99d1-574780be5207','賦海檜','姜特立','宋','宋诗','song-poetry','','[]','孤根從何來，遠自滄海植。',72,'全唐诗/poet.song.126000.json','["孤根從何來，遠自滄海植。", "轉移失生意，刔剔費人力。", "攣拳蛇蚓結，沮喪丈夫直。", "餘妍撐孤翠，枯理上微液。", "僅供盆盎玩，竟閼參天色。", "安得拉風雷，一夜拔千尺。"]'),
('6e7cccab-2824-4341-99a7-0fb60f4edd58','偶成','姜特立','宋','宋诗','song-poetry','','[]','僻習難施日用間，老人拗事更相關。',32,'全唐诗/poet.song.126000.json','["僻習難施日用間，老人拗事更相關。", "愁來得句翻成樂，忙裏尋詩却是閒。"]'),
('68a66067-7c10-46f4-8241-9da97afa2538','聞常伯韓公下世感賦  其一','姜特立','宋','宋诗','song-poetry','','[]','逸軌高標不可扳，風流人物晉唐還。',64,'全唐诗/poet.song.126000.json','["逸軌高標不可扳，風流人物晉唐還。", "胸襟磊落塵埃外，尊酒淋漓筆硯間。", "英氣一朝歸碧落，高文千古映青山。", "繐帷莫奠知音淚，極目樓邊有愧顔。"]'),
('0aee5360-f0c9-4e2f-9088-c679c91f23e8','聞常伯韓公下世感賦  其二','姜特立','宋','宋诗','song-poetry','','[]','六義湮淪吾道東，敢將見處與人同。',64,'全唐诗/poet.song.126000.json','["六義湮淪吾道東，敢將見處與人同。", "後生不遇東坡老，前輩今無南澗翁。", "四偈真能垂具眼，瓣香端欲嗣宗風。", "遺編一見如生面，悵望新阡恨不窮。"]'),
('72b6cdcf-92d5-439d-8b25-e5bd4f894acd','出使過嘉禾城外','姜特立','宋','宋诗','song-poetry','','[]','江南清絕處，此地數經過。',48,'全唐诗/poet.song.126000.json','["江南清絕處，此地數經過。", "疎柳依秋浦，歸船亂晚波。", "王侯幾蟻穴，天地一漁簑。", "安得玄真子，同編唱和歌。"]'),
('92a7ec3e-a6fc-44dd-bebf-d81b2972b9a4','送徐撫幹二首  其一','姜特立','宋','宋诗','song-poetry','','[]','便便滿腹貯詩書，狗監何人薦子虛。',64,'全唐诗/poet.song.126000.json','["便便滿腹貯詩書，狗監何人薦子虛。", "半世一官供偃蹇，羣公極力藉吹噓。", "莫辭去佐芙蓉幕，猶勝閒乘觳觫車。", "文雅風流府中望，它時合在玉堂居。"]'),
('a929ade6-9883-4445-99d5-565e7b79bd03','送徐撫幹二首  其二','姜特立','宋','宋诗','song-poetry','','[]','莫嗟骨相未封侯，媺惡窮通本不侔。',64,'全唐诗/poet.song.126000.json','["莫嗟骨相未封侯，媺惡窮通本不侔。", "文似陳琳須草檄，賦如王粲好登樓。", "時平上幕宜多暇，酒賤清歡亦易謀。", "荔子丹時簪末利，可能無句寄中州。"]'),
('74aa25f9-20d6-4263-a906-cf5478a39ca0','人送雙鴈','姜特立','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','卑栖籠檻尚成雙，莫嘆凋零未著行。',32,'全唐诗/poet.song.126000.json','["卑栖籠檻尚成雙，莫嘆凋零未著行。", "猶勝孤飛千萬里，洞庭波上冷吳霜。"]'),
('813bf70d-d5a8-43a5-a396-fbf4bf1dded8','次韵秋日五首  其一','姜特立','宋','宋诗','song-poetry','','[]','四山秋色冷銀牀，燕坐高齋興味長。',32,'全唐诗/poet.song.126000.json','["四山秋色冷銀牀，燕坐高齋興味長。", "何物與公堪比德，寒花晚節最馨香。"]'),
('a2026caf-8782-4c50-8c18-6c0daa4d8e06','次韵秋日五首  其二','姜特立','宋','宋诗','song-poetry','','[]','冉冉寒雲滃曉扉，涓涓墜露滴秋衣。',32,'全唐诗/poet.song.126000.json','["冉冉寒雲滃曉扉，涓涓墜露滴秋衣。", "興來倚杖看蒼石，無限空山木葉飛。"]'),
('df156412-db8b-4d1e-86f9-a373755f2783','次韵秋日五首  其三','姜特立','宋','宋诗','song-poetry','','[]','振衣雲岫一襟風，送目霜天萬里鴻。',32,'全唐诗/poet.song.126000.json','["振衣雲岫一襟風，送目霜天萬里鴻。", "好賦遠遊揮八極，知公胸次小區中。"]'),
('a2bde1f0-d02d-49a3-9029-28325eea9d24','次韵秋日五首  其四','姜特立','宋','宋诗','song-poetry','','[]','木落山寒境更幽，世間萬事入搔頭。',32,'全唐诗/poet.song.126000.json','["木落山寒境更幽，世間萬事入搔頭。", "何人爲廣秋聲賦，我欲歸田蚤晚休。"]'),
('b853d345-59b4-41eb-b8a4-9dd3c0d2c7a1','次韵秋日五首  其五','姜特立','宋','宋诗','song-poetry','','[]','不須樂府說無愁，不用尊前著杜秋。',32,'全唐诗/poet.song.126000.json','["不須樂府說無愁，不用尊前著杜秋。", "已把宦情同嚼蠟，更將世事等藏鈎。"]'),
('5e43cb96-829f-4c11-8ea8-c8ae00108d8f','次人韻思弟','姜特立','宋','宋诗','song-poetry','','[]','二陸雙飛共一班，士龍何事別長安。',64,'全唐诗/poet.song.126000.json','["二陸雙飛共一班，士龍何事別長安。", "故園花鳥應無恙，勝日樽罍且自寬。", "春草夢回詩思好，暮荆風急客衣寒。", "苕溪一水蒼茫外，無限相思入倚欄。"]'),
('0667aaf6-a521-40bb-84c5-7f38a26543f8','喜陸少監入京','姜特立','宋','宋诗','song-poetry','','[]','昔人思李杜，長恨不相隨。',48,'全唐诗/poet.song.126000.json','["昔人思李杜，長恨不相隨。", "遥寄有劉白，同吟惟陸皮。", "物睽終必合，句妙却難追。", "試問長安陌，何如灞岸時。"]'),
('7f3520b9-5009-44bf-bb51-aa3546cce980','范大參入覲頗愛鄙作以詩謝之','姜特立','宋','宋诗','song-poetry','','[]','問句石湖老，如將月指標。',48,'全唐诗/poet.song.126000.json','["問句石湖老，如將月指標。", "枯中說滋潤，高處戒虛憍。", "頗許唐音近，寧論漢道遥。", "正聲今在耳，萬樂聽簫韶。"]'),
('2e5d9bd1-6bf6-46d3-933a-658924446abc','特立夜直讀荆公客至當飲酒篇感而有賦','姜特立','宋','宋诗','song-poetry','','[]','客至當飲酒，客去合如何。',216,'全唐诗/poet.song.126000.json','["客至當飲酒，客去合如何。", "人生無根蔕，何必客經過。", "有客固當飲，無客飲自歌。", "有客與無客，頹然同一科。", "昔人秉燭游，正爾畏蹉跎。", "粵余生多艱，一官劇奔波。", "讀書四十年，鐵硯空研磨。", "糲食豈有肉，菜羹或無鹺。", "一衣遞單夾，摺製屢舛訛。", "六十始小遇，鬢毛已雙皤。", "屈指從心年，光陰苦無多。", "酒雖非所嗜，不飲意不佳。", "一醆助朝氣，三杯養天和。", "放浪風月夕，留連四時花。", "以此畢吾生，無愧亦無嗟。", "尋思百歲後，有酒如傾河。", "一滴不入唇，誰見此顔酡。", "作詩廣前賢，聞者且勿呵。"]'),
('52f821ba-3dea-407a-a49c-e57c09e491f9','戊申除夕','姜特立','宋','宋诗','song-poetry','','[]','禁宿遇除夕，孤懷還自憐。',48,'全唐诗/poet.song.126000.json','["禁宿遇除夕，孤懷還自憐。", "浮生俱畏老，造物暗凋年。", "性斧何勞伐，心灰自不然。", "好將閒日月，送老白鷗邊。"]'),
('4e3f803f-9ea1-4c10-a3d0-76d6a73a5b43','友人招飲適雲氣大作雨意甚凉','姜特立','宋','宋诗','song-poetry','','[]','永日南薰入舜琴，故人邀我共披襟。',32,'全唐诗/poet.song.126000.json','["永日南薰入舜琴，故人邀我共披襟。", "歌姬可是能留客，故遏行雲作午陰。"]'),
('c932eac4-9eab-4bce-a061-3e3d695992f1','出西湖至天竺','姜特立','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寶叔山前翠打圍，湧金門外水漣漪。',32,'全唐诗/poet.song.126000.json','["寶叔山前翠打圍，湧金門外水漣漪。", "出關便有漁謳起，底事公卿都不知。"]'),
('36676c05-8418-4b03-9f93-f6205a680642','跳珠軒','姜特立','宋','宋诗','song-poetry','','[]','激溜跳珠盡日間，却疑造物不曾閒。',32,'全唐诗/poet.song.126000.json','["激溜跳珠盡日間，却疑造物不曾閒。", "何如收取連雲筧，水自水流山自山。"]'),
('44188ca2-f1f7-4fde-a004-8f5afafa1f47','戲張時可','姜特立','宋','宋诗','song-poetry','','[]','南湖堂上著彭宣，結得襄王夢裏緣。',32,'全唐诗/poet.song.126000.json','["南湖堂上著彭宣，結得襄王夢裏緣。", "試問傍人鷗與鷺，何如隨步小嬋娟。"]'),
('9673153e-2777-42e0-bfe3-7840ed304f56','和陸郎中送出關  其一','姜特立','宋','宋诗','song-poetry','','[]','得失乘除誰使然，茲行猶作赤城仙。',32,'全唐诗/poet.song.126000.json','["得失乘除誰使然，茲行猶作赤城仙。", "支風給雨元無禁，借竹判花不費錢。"]'),
('dfaea484-c8c1-4103-9ad0-cc81b29cc9d6','和陸郎中送出關  其二','姜特立','宋','宋诗','song-poetry','','[]','黄塵烏帽六年間，心跡何嘗一日閒。',32,'全唐诗/poet.song.126000.json','["黄塵烏帽六年間，心跡何嘗一日閒。", "今日船頭忽東轉，始知有味是家山。"]'),
('b7ca1891-e4e1-47fd-a102-bdb5395f1210','出關','姜特立','宋','宋诗','song-poetry','','[]','宦路崎嶇閲歲華，更無佳思發詩葩。',32,'全唐诗/poet.song.126000.json','["宦路崎嶇閲歲華，更無佳思發詩葩。", "出關便有山林興，續稿從今漸有涯。"]'),
('7414f348-219d-4f90-8dee-0735790437ab','賦赤松金宣義十月牡丹  其一','姜特立','宋','宋诗','song-poetry','','[]','牡丹十月發春叢，半倚微陽半怯風。',32,'全唐诗/poet.song.126000.json','["牡丹十月發春叢，半倚微陽半怯風。", "渾似若耶溪上女，嬌愁初入館娃宮。"]'),
('5f883273-e691-4b95-b1b2-c2b158ca285e','賦赤松金宣義十月牡丹  其二','姜特立','宋','宋诗','song-poetry','','[]','赤松元是神仙窟，公獨能開韓令花。',32,'全唐诗/poet.song.126000.json','["赤松元是神仙窟，公獨能開韓令花。", "若使雒陽耆舊見，定應擁褐過君家。"]'),
('d718ec34-cf25-41ec-bb53-a42f23912623','過釣臺','姜特立','宋','宋诗','song-poetry','','[]','兩山夾青蒼，月照江茫茫。',48,'全唐诗/poet.song.126000.json','["兩山夾青蒼，月照江茫茫。", "一杯酌老婦，孤興發滄浪。", "賢哉羊裘公，不肯仕漢光。", "冥鴻已高翔，弋者應相忘。"]'),
('12bf9113-b51e-4a91-9103-88460c49e66b','乍還里舍','姜特立','宋','宋诗','song-poetry','','[]','十載彈冠始一歸，暗驚草露濕征衣。',32,'全唐诗/poet.song.126000.json','["十載彈冠始一歸，暗驚草露濕征衣。", "自憐猶勝遼東鶴，故舊相逢未盡非。"]'),
('9c7c89af-b196-4cb2-846f-d6d037e03fa8','和陸郎中','姜特立','宋','宋诗','song-poetry','','[]','午庭風雨撼高槐，一洗城頭十丈埃。',64,'全唐诗/poet.song.126000.json','["午庭風雨撼高槐，一洗城頭十丈埃。", "老子坐間尋句去，故人門外寄詩來。", "勁鋒久服穿楊妙，鈍思深慚擊鉢催。", "請佩左符君未可，要聽吟思發春雷。"]'),
('7f8f8bf0-b025-4f14-9037-900a32fe97f2','再和','姜特立','宋','宋诗','song-poetry','','[]','合居瑣闥蔭庭槐，底事康衢走俗埃。',64,'全唐诗/poet.song.126000.json','["合居瑣闥蔭庭槐，底事康衢走俗埃。", "莫買漁舟便歸去，好提鴻筆記方來。", "湖山剩有詩神助，事業寧須官鬼催。", "知道經綸未施用，出屯行矣掃雲雷。"]'),
('843e22ab-65ed-4532-b46b-cdca42f163d2','邸報改元得雪','姜特立','宋','宋诗','song-poetry','','[]','天意陰晴凍未分，忽驚璧璐散紛紜。',64,'全唐诗/poet.song.126000.json','["天意陰晴凍未分，忽驚璧璐散紛紜。", "梅花露白難誇客，麥本藏青預策勳。", "野水斷流魚入槮，江雲垂地鴈迷羣。", "太平天子新鴻號，感召端由叶氣薰。"]'),
('adff90e9-f2bc-4392-929c-b947cae3eb70','八詠樓','姜特立','宋','宋诗','song-poetry','','[]','隠侯故事許誰傳，領略江山付謫仙。',64,'全唐诗/poet.song.126000.json','["隠侯故事許誰傳，領略江山付謫仙。", "虹抱子城增面勢，翬飛傑棟跨風烟。", "舊題壓倒三千首，壯觀追還七百年。", "我老登臨無好語，倚欄終日愧前賢。"]'),
('04ea5570-9773-4aec-9233-7cf9b64b49b5','送邦達邦操弟同恪赴省','姜特立','宋','宋诗','song-poetry','','[]','二陸平時譽望長，近來小阮亦文章。',64,'全唐诗/poet.song.126000.json','["二陸平時譽望長，近來小阮亦文章。", "共排雲路升天府，穩坐仙舟入帝鄉。", "去日漸驚梅萼破，歸時同带桂枝香。", "老夫已辦酒千斛，細斫菖蒲作賀觴。"]'),
('369a4930-80f1-4ea4-98df-231a0a8901c5','二月道傍梅花','姜特立','宋','宋诗','song-poetry','','[]','臘底春前探物華，一枝初發競相誇。',32,'全唐诗/poet.song.126000.json','["臘底春前探物華，一枝初發競相誇。", "如今千樹離披後，却愛遲開三兩花。"]'),
('ec1664ab-ec79-4518-bf61-2d81c034aead','恭和令製感秋','姜特立','宋','宋诗','song-poetry','','[]','金虎肅秋氣，屬茲摇落時。',120,'全唐诗/poet.song.126000.json','["金虎肅秋氣，屬茲摇落時。", "淅瀝暮蟬澁，嘹唳征鴻悲。", "遥巘雲冒絮，平林露成帷。", "黄凋菡萏盤，紅墜芙蓉枝。", "濕葉填斷塹，寒藤蔓荒籬。", "東儲感物變，西陸占星移。", "清風已預戒，秋陽豈難知。", "偶爾嘆憭慄，卓然吐新奇。", "想象酒方酣，浩蕩思無涯。", "不學楚人賦，載賡豳土詩。"]'),
('6d6458bd-a070-4764-86b3-3217dfd7e018','雨霽立門外見萬山葱翠如染頗自喜得獨占山居之勝因得亂道一聯遂足成篇兼懷曲湖居士','姜特立','宋','宋诗','song-poetry','','[]','吾廬何處是，野色滿方壺。',48,'全唐诗/poet.song.126000.json','["吾廬何處是，野色滿方壺。", "一水長來繞，千峰不用呼。", "偶然成擇勝，幸爾慰歸愚。", "問訊曲湖老，何時訪老夫。"]'),
('b12c868b-9be5-4182-8ee7-08bc6c579770','自和','姜特立','宋','宋诗','song-poetry','','[]','喜報紆芳軫，深期辦酒壺。',48,'全唐诗/poet.song.126000.json','["喜報紆芳軫，深期辦酒壺。", "興來更唱和，耳熱自歌呼。", "正可談風月，何須較智愚。", "吾今方息駕，無復問征夫。"]'),
('81505b9a-9f29-4028-b84b-5709e224a2a9','重午和鞏教授韻','姜特立','宋','宋诗','song-poetry','','[]','屈子沈淵日，年年舊俗忙。',48,'全唐诗/poet.song.126000.json','["屈子沈淵日，年年舊俗忙。", "佳人誇綵縷，稚子競新裳。", "鐃皷喧漁步，杯盤列象床。", "山翁獨無事，燕坐只焚香。"]'),
('7e4fa9b2-b605-4cb4-82a3-f00f3eea5fc3','醉後苦熱狂吟','姜特立','宋','宋诗','song-poetry','','[]','休說唐裝與晉裝，一絲不掛謾風狂。',132,'全唐诗/poet.song.126000.json','["休說唐裝與晉裝，一絲不掛謾風狂。", "登枝解衵不快意，脫帽露頂猶尋常。", "我生憚暑老益甚，束縛冠屨如以桎梏置我旁。", "安得天風吹上雪山頂，憑陵大叫呼彼蒼。", "下臣塵世熱欲死，願借三冬塞空之白雪，十月隕物之繁霜。", "陰崖已凍裂復裂，草木禽獸顛且僵。", "此時天上天下無暑氣，姜子夜半獨立方清凉。"]'),
('7c161cc4-9a41-4d0f-b4aa-877313cd3d5e','閒詠二首  其一','姜特立','宋','宋诗','song-poetry','','[]','手植山松二十年，只今翠色已藏烟。',32,'全唐诗/poet.song.126000.json','["手植山松二十年，只今翠色已藏烟。", "百年未盡終當見，霧鬣風髯上拂天。"]'),
('669d6b50-d3ef-4e92-9ff2-d0687e4d7aa0','閒詠二首  其二','姜特立','宋','宋诗','song-poetry','','[]','翠麓青秧带小川，無營門巷自蕭然。',32,'全唐诗/poet.song.126000.json','["翠麓青秧带小川，無營門巷自蕭然。", "中間至樂何人解，只在藤牀拄杖前。"]'),
('aa41bca5-2cff-4162-a1e0-2c0eb006e92c','寄鞏丈哭孫','姜特立','宋','宋诗','song-poetry','','[]','情愛難纏曠士襟，俗緣那似道緣深。',32,'全唐诗/poet.song.126000.json','["情愛難纏曠士襟，俗緣那似道緣深。", "已知達識空諸幻，萬事從頭付醉吟。"]'),
('153eb76e-e4e3-42af-93a7-5ad907c936b9','雙桃寄鞏經略三首  其一','姜特立','宋','宋诗','song-poetry','','[]','只說瓜蓮並蒂生，幾曾仙實見雙成。',32,'全唐诗/poet.song.126000.json','["只說瓜蓮並蒂生，幾曾仙實見雙成。", "却疑西母猶多事，戲作人間兒女情。"]'),
('b8f291fd-827a-4bd4-87ab-047e40b1a29f','雙桃寄鞏經略三首  其二','姜特立','宋','宋诗','song-poetry','','[]','世間固有無情物，天上寧無有慾仙。',32,'全唐诗/poet.song.126000.json','["世間固有無情物，天上寧無有慾仙。", "想得武陵人去後，精神交感此因緣。"]'),
('b1e64872-987b-4b7c-8448-20b0822a578a','雙桃寄鞏經略三首  其三','姜特立','宋','宋诗','song-poetry','','[]','忽見雙桃入眼新，捧看驚動坐間賓。',32,'全唐诗/poet.song.126000.json','["忽見雙桃入眼新，捧看驚動坐間賓。", "老夫得此渾無爲，持壽高堂兩玉人。"]'),
('13845b23-b446-46ee-8c35-3789375dd04e','題陳朝幹山亭二首 翠微','姜特立','宋','宋诗','song-poetry','','[]','高蹈烟霞遠世塵，翠微深處一綸巾。',32,'全唐诗/poet.song.126000.json','["高蹈烟霞遠世塵，翠微深處一綸巾。", "若非嚴瀨垂竿客，即是桃源避世人。"]'),
('e29a52cf-e67c-4059-a1a7-45334a59d8a5','題陳朝幹山亭二首 綠野','姜特立','宋','宋诗','song-poetry','','[]','豐草茂林皆綠野，不論韋弁與貂蟬。',32,'全唐诗/poet.song.126000.json','["豐草茂林皆綠野，不論韋弁與貂蟬。", "但能真得箇中趣，何必功名如昔賢。"]'),
('a971e103-6e40-4107-90fa-acec0dc9fc02','次楊丈喜雨','姜特立','宋','宋诗','song-poetry','','[]','銀竹森森度翠林，惰龍不用血蹄涔。',32,'全唐诗/poet.song.126000.json','["銀竹森森度翠林，惰龍不用血蹄涔。", "倉箱且爲農夫慶，敢說祠官俸有金。"]'),
('f8461f30-509e-4418-9188-abf80301722b','謁塋','姜特立','宋','宋诗','song-poetry','','[]','新晴衝曉謁先塋，頗愛山行竹樹清。',32,'全唐诗/poet.song.126000.json','["新晴衝曉謁先塋，頗愛山行竹樹清。", "日午未須回俗駕，且留趺坐聽松聲。"]'),
('2876dbac-9bf6-4939-a2a1-614b60e0dbd2','呈楊方叔','姜特立','宋','宋诗','song-poetry','','[]','老醜慵看鏡，清狂愛作詩。',24,'全唐诗/poet.song.126000.json','["老醜慵看鏡，清狂愛作詩。", "唱酬真得侶，衰白亦相宜。"]'),
('299fa478-bc37-4afa-91c1-e0e2a696079a','和方叔中秋','姜特立','宋','宋诗','song-poetry','','[]','待月徘徊東澗濱，一天風露浄無塵。',64,'全唐诗/poet.song.126000.json','["待月徘徊東澗濱，一天風露浄無塵。", "老人歡意年年減，佳節清光夜夜新。", "悼往難傳雲外信，舉杯那復眼中人。", "飄然遥想騎鯨興，更覺高歌有鬼神。"]'),
('c0e92e5d-59e3-449c-92d1-93587c833586','賦鞏丈鸚鵡三首  其一','姜特立','宋','宋诗','song-poetry','','[]','隴汧歸路渺漫漫，且向金籠刷羽翰。',32,'全唐诗/poet.song.126000.json','["隴汧歸路渺漫漫，且向金籠刷羽翰。", "院靜日長頻送語，時時圖得主翁看。"]'),
('3daa657b-a4b8-47f4-986f-a65915e00988','賦鞏丈鸚鵡三首  其二','姜特立','宋','宋诗','song-poetry','','[]','紫燕黄鸝亦言語，或依簾幕或穿花。',32,'全唐诗/poet.song.126000.json','["紫燕黄鸝亦言語，或依簾幕或穿花。", "較量愛重無如汝，合在華堂富貴家。"]'),
('c6c0c5b1-2f45-44c7-8a73-8bb2a223e69c','賦鞏丈鸚鵡三首  其三','姜特立','宋','宋诗','song-poetry','','[]','翠衿紅觜嬌唇舌，羽族於中最性靈。',32,'全唐诗/poet.song.126000.json','["翠衿紅觜嬌唇舌，羽族於中最性靈。", "巧護狸狌莫驚嚇，好留相伴誦心經。"]'),
('19377349-64ad-4bd1-b66c-57b1d4426e18','五日不出戶','姜特立','宋','宋诗','song-poetry','','[]','五日不出戶，門前楓葉丹。',48,'全唐诗/poet.song.126000.json','["五日不出戶，門前楓葉丹。", "清芬餘橘柚，老色半林巒。", "社燕知時去，昏鴉取勢盤。", "秋深多物色，應接未能安。"]'),
('ee741549-f3b3-45f6-beaa-b084d67a0bd8','次韻仲志荷珠','姜特立','宋','宋诗','song-poetry','','[]','觀彼雨中荷，跳珠自涓滴。',132,'全唐诗/poet.song.126000.json','["觀彼雨中荷，跳珠自涓滴。", "初集尚端停，稍多還倚側。", "虛明是本體，不受世鑽刻。", "初疑鮫人泣，淚向盤中擲。", "又疑石筍街，拋灑天不惜。", "但見漾玻瓈，詎容登几格。", "高低相依映，傾瀉才咫尺。", "瀏灕丹砂汞，晃蕩摩尼色。", "照乘儻見收，價恐千金直。", "日乾風勢定，泯若無留迹。", "固知造化巧，又似兒女劇。"]'),
('05455368-1e34-4550-a06d-851d0a40d9ef','寄題時氏小飛來三首  其一','姜特立','宋','宋诗','song-poetry','','[]','依約峯巒似竺乾，崟崎岩洞老雲烟。',32,'全唐诗/poet.song.126000.json','["依約峯巒似竺乾，崟崎岩洞老雲烟。", "有時風雨無人夜，疑有猿聲到枕邊。"]'),
('e89d3669-4ded-4d5f-9217-df9c7d20e5fe','寄題時氏小飛來三首  其二','姜特立','宋','宋诗','song-poetry','','[]','曠士無時不愛山，却嫌庭戶少巑岏。',32,'全唐诗/poet.song.126000.json','["曠士無時不愛山，却嫌庭戶少巑岏。", "何年劫火留遺斷，便作北高峯下看。"]'),
('d9c0ee38-4071-4053-be63-afce35eb79bc','寄題時氏小飛來三首  其三','姜特立','宋','宋诗','song-poetry','','[]','須彌納芥不爲誇，曾向壺中貯九華。',32,'全唐诗/poet.song.126000.json','["須彌納芥不爲誇，曾向壺中貯九華。", "靈隠寺前天竺後，好峯都落在君家。"]'),
('19467aa9-5b88-41ad-adee-47a59347a79f','和鞏教授訪別二首  其一','姜特立','宋','宋诗','song-poetry','','[]','君來別我還歸去，君去重來定幾時。',32,'全唐诗/poet.song.126000.json','["君來別我還歸去，君去重來定幾時。", "此後相思無可寄，相思欲寄莫如詩。"]'),
('c22aae04-77e7-410e-b7ce-1c5ac3b7b841','和鞏教授訪別二首  其二','姜特立','宋','宋诗','song-poetry','','[]','酒醨情惡不成醺，况復匆匆欲語分。',32,'全唐诗/poet.song.126000.json','["酒醨情惡不成醺，况復匆匆欲語分。", "留客恨輪無四角，供庖歎鼈少雙裙。"]'),
('95ea3b3b-2919-4a88-98bd-6b3853eca7fb','寄鞏大監','姜特立','宋','宋诗','song-poetry','','[]','十里兼旬信不通，每看金阜想高風。',32,'全唐诗/poet.song.126000.json','["十里兼旬信不通，每看金阜想高風。", "已知憚暑難迎客，不敢將詩更惱公。"]'),
('3382c09e-4ad5-4f6c-ab6d-8bb5d4734aa5','謾興','姜特立','宋','宋诗','song-poetry','','[]','烏藤黄葛一山癯，萬事從人笑闊迂。',32,'全唐诗/poet.song.126000.json','["烏藤黄葛一山癯，萬事從人笑闊迂。", "作計尚餘詩氣習，遣閒須著睡工夫。"]'),
('2a91915d-7641-438b-b1a6-f14323e1c2ed','和鞏教授趨朝','姜特立','宋','宋诗','song-poetry','','[]','昨夢中宵拾夜光，曉驚新句墮書旁。',64,'全唐诗/poet.song.126000.json','["昨夢中宵拾夜光，曉驚新句墮書旁。", "英游只合陪青瑣，偉論何須列皂囊。", "溪上林巒新紫翠，船頭橙橘半青黄。", "茲行好語須頻寄，只恐空踈窘報章。"]'),
('a9363f26-793c-4f41-8164-39e67d53e0b4','應令水墨素馨扇面二首  其一','姜特立','宋','宋诗','song-poetry','','[]','清似山梔馥似蘭，何人淡墨試毫端。',32,'全唐诗/poet.song.126000.json','["清似山梔馥似蘭，何人淡墨試毫端。", "若無密葉相遮映，全作江梅春曉看。"]'),
('193e629b-397c-4ed2-9956-3484f1054257','應令水墨素馨扇面二首  其二','姜特立','宋','宋诗','song-poetry','','[]','玉質生從瘴海傍，輕綃淡墨寫微茫。',32,'全唐诗/poet.song.126000.json','["玉質生從瘴海傍，輕綃淡墨寫微茫。", "疎花賸作江梅瘦，手底風頭只欠香。"]'),
('8c6aeb3f-90e3-45a7-815f-7b2698cbf300','閏七夕呈譙內知舍人','姜特立','宋','宋诗','song-poetry','','[]','佳期有盡情無盡，一再相逢意若何。',32,'全唐诗/poet.song.126000.json','["佳期有盡情無盡，一再相逢意若何。", "正使長年成會合，臨分依舊黯情多。"]'),
('8c681725-cbcb-46fb-befe-88be48d898bc','閒興','姜特立','宋','宋诗','song-poetry','','[]','數點青峯照夕暉，一灣寒碧带踈籬。',32,'全唐诗/poet.song.126000.json','["數點青峯照夕暉，一灣寒碧带踈籬。", "興來倚杖閒臨眺，巾影欹風似阿誰。"]'),
('9af187ef-b63e-4ba0-bac2-e52e88310aa7','偶題','姜特立','宋','宋诗','song-poetry','','[]','露葉明朝彩，雲峯吐夕嵐。',24,'全唐诗/poet.song.126000.json','["露葉明朝彩，雲峯吐夕嵐。", "山中無限景，詩力不相參。"]'),
('63902a64-6100-46e1-b65f-54b5f6c47480','臘中感春','姜特立','宋','宋诗','song-poetry','','[]','小雨濕紅蕤，輕颸動碧池。',24,'全唐诗/poet.song.126000.json','["小雨濕紅蕤，輕颸動碧池。", "東君送消息，預作探春詩。"]'),
('76c2cd78-8d42-4de2-aace-ea10a7b7e8d9','屋角丹楓','姜特立','宋','宋诗','song-poetry','','[]','金行肅物欲功成，一夜江楓點翠屏。',32,'全唐诗/poet.song.126000.json','["金行肅物欲功成，一夜江楓點翠屏。", "不是天公愛紅葉，要驅小隠入丹青。"]'),
('fb5ed9de-e233-4a7f-a1f6-abeda8a42070','辛亥夏余將廣舊廬偶讀欒城李方叔新宅詩篇是時子由方治第有余年七十無住著屋成可作十年客之句感而賦之','姜特立','宋','宋诗','song-poetry','','[]','潁濱七十無住著，我室初成四十七。',96,'全唐诗/poet.song.126000.json','["潁濱七十無住著，我室初成四十七。", "前賢蚤達尚如斯，我已多公五千日。", "屋成作客可十年，此老八十終斯言。", "我今追公尚一紀，來日盈縮猶茫然。", "製衣起屋俱犯戒，無屋無衣兩爲大。", "世間萬事且隨緣，運海巢枝俱一快。"]'),
('23f06ed3-c6e6-4510-b467-46e66a75ea24','辛亥春夜雪忽積竹松欹折過半','姜特立','宋','宋诗','song-poetry','','[]','夜來雪積不可料，晨起壓盡庭前花。',64,'全唐诗/poet.song.126000.json','["夜來雪積不可料，晨起壓盡庭前花。", "道松俯僂若揖客，江竹離披如倒戈。", "沙頭寒重鴈不起，門外日高人未過。", "此時薪米不易得，晨突有烟能幾家。"]'),
('b7a6c9d9-2460-4575-bb3d-b93ea981b472','夏日奉天台祠祿','姜特立','宋','宋诗','song-poetry','','[]','青衣揮箑卧藤牀，翠袖携壺過酒漿。',64,'全唐诗/poet.song.126000.json','["青衣揮箑卧藤牀，翠袖携壺過酒漿。", "蝟腹出波烹芡實，褭蹄和露擘蓮房。", "相呼時入雞豚社，獨坐曾無鴈鶩行。", "便是赤城真隠吏，不須劉阮更相將。"]'),
('1d19b2ac-cadf-4509-ba62-84eaf79bbacf','青奴','姜特立','宋','宋诗','song-poetry','','[]','正堪休手足，好事降爲奴。',48,'全唐诗/poet.song.126000.json','["正堪休手足，好事降爲奴。", "具眼感君惠，無心真我徒。", "耐寒曾得友，蒙恥恐非夫。", "却羨木居士，盤鳩賜策扶。"]'),
('6e6c9c09-c239-40f0-9ed7-746b98de5e6b','秋園謾賦呈方叔','姜特立','宋','宋诗','song-poetry','','[]','嫋嫋鮮飈動遠林，亭亭暮靄占遥岑。',64,'全唐诗/poet.song.126000.json','["嫋嫋鮮飈動遠林，亭亭暮靄占遥岑。", "淵明松菊秋容澹，仲蔚蓬蒿露氣深。", "莫笑四携亭未具，且環十皷坐同斟。", "更須少待桂花發，林下舂容把臂吟。"]'),
('91bca1e7-f902-4658-9cd0-f64dee875f2b','和答鞏提幹見賀浙東總戎','姜特立','宋','宋诗','song-poetry','','[]','黜陟何嘗到耳邊，旋栽花木學平泉。',64,'全唐诗/poet.song.126000.json','["黜陟何嘗到耳邊，旋栽花木學平泉。", "二年竊食祠官冷，一日頒恩寶篆鮮。", "閫寄暫居油幕副，朋從遥憶竹林賢。", "詩筒從此長來往，應有人編唱和篇。"]'),
('4e571f4f-8416-4e13-b4d9-e5e6024330d2','送楊方叔還山二首  其一','姜特立','宋','宋诗','song-poetry','','[]','一語何嘗及世氛，若非說劍即論文。',32,'全唐诗/poet.song.126000.json','["一語何嘗及世氛，若非說劍即論文。", "有時伴我松岡上，閒看南山萬塢雲。"]'),
('a75334d4-485b-492c-90d1-87526c098bff','送楊方叔還山二首  其二','姜特立','宋','宋诗','song-poetry','','[]','可人自是難招喚，此去相從定幾時。',32,'全唐诗/poet.song.126000.json','["可人自是難招喚，此去相從定幾時。", "來歲春風暖行色，隠侯樓上要題詩。"]'),
('bfd83b5b-98b5-4a82-9383-41028e3f4eb8','和李崧卿九日','姜特立','宋','宋诗','song-poetry','','[]','重陽無菊悶書空，心似淵明興不同。',64,'全唐诗/poet.song.126000.json','["重陽無菊悶書空，心似淵明興不同。", "聊且携壺上東嶺，不妨欹帽對西風。", "百年盡付無何外，三逕誰如阿堵中。", "十月黄花方爛熳，莫辭聯騎訪山翁。"]'),
('77b9f365-5bbd-4597-941e-27455f8d59f5','送棗陽軍使劉似之兼棗陽令  其一','姜特立','宋','宋诗','song-poetry','','[]','四方男子志，當在壯年時。',48,'全唐诗/poet.song.126000.json','["四方男子志，當在壯年時。", "民社非輕畀，才猷且小施。", "附庸今列邑，大國古稱隨。", "莫謂朝廷遠，行看召驛馳。"]'),
('97a1fa7b-2e2d-4d88-870c-861be6a7ad91','送棗陽軍使劉似之兼棗陽令  其二','姜特立','宋','宋诗','song-poetry','','[]','去去檣烏遠，何時到漢東。',48,'全唐诗/poet.song.126000.json','["去去檣烏遠，何時到漢東。", "官期應歲臘，客路尚秋風。", "大楚風聲混，三苗土壤通。", "邊頭有新句，莫惜寄飛鴻。"]'),
('2c88be34-666e-4a32-863d-1d9e3b27f4d6','之官婺州','姜特立','宋','宋诗','song-poetry','','[]','一夕霜風掃翠微，宦情何似客情悲。',64,'全唐诗/poet.song.126000.json','["一夕霜風掃翠微，宦情何似客情悲。", "留連祖帳臨分日，徙倚家園欲去時。", "三載奉祠心似水，一番挈累鬢成絲。", "高飛深泳慙魚鳥，臨水看雲有所思。"]'),
('80846d6a-85a1-4145-83d7-98df3a961858','送客','姜特立','宋','宋诗','song-poetry','','[]','今日出郊送客，明朝肩輿入州。',28,'全唐诗/poet.song.126000.json','["今日出郊送客，明朝肩輿入州。", "六十年前伎倆，白頭也合歸休。"]'),
('89fd3142-d75b-42df-872f-5f12eab013f6','六十七守歲','姜特立','宋','宋诗','song-poetry','','[]','少時守歲喜蹁躚，老境衰頹只益眠。',32,'全唐诗/poet.song.126000.json','["少時守歲喜蹁躚，老境衰頹只益眠。", "明日未應添白髮，怕人問處是增年。"]'),
('ee6e3cca-e59c-4284-be8f-2ee63061204c','除草篇','姜特立','宋','宋诗','song-poetry','','[]','有客勸除草，草去眼中浄。',192,'全唐诗/poet.song.126000.json','["有客勸除草，草去眼中浄。", "梵志反著襪，一國皆通病。", "頰上著三毛，精神乃殊勝。", "微雲點太虛，不礙天宇瑩。", "芳草有佳色，難與俗士訂。", "曾著騷人經，屢勤才子詠。", "因依仲蔚門，繚繞淵明逕。", "不入膏粱觀，唯契山林性。", "吾家北窗下，曠土勿畦町。", "花草隨意生，紅綠同一盛。", "晨露共明蠲，夕烟相掩映。", "既傍竹陰清，又連苔色靜。", "微薰入衣屨，餘潤侵筑磬。", "終日坐其間，心清神氣定。", "詩酒頗相關，世事不足聽。", "從渠笑吾癡，此意未易竟。"]'),
('6242dd29-601a-4572-bbfd-4d924215ba8b','賦婺州察推廳悠然樓二首  其一','姜特立','宋','宋诗','song-poetry','','[]','着眼看山不見山，徒勞終日對孱顔。',32,'全唐诗/poet.song.126000.json','["着眼看山不見山，徒勞終日對孱顔。", "偶然境意相迎處，只在尋常俯仰間。"]'),
('936fce3b-7a54-48de-aef7-4ff3383d1ce6','賦婺州察推廳悠然樓二首  其二','姜特立','宋','宋诗','song-poetry','','[]','爲秫求官興頗深，忽懷松菊便投簪。',32,'全唐诗/poet.song.126000.json','["爲秫求官興頗深，忽懷松菊便投簪。", "先生萬事皆如此，何獨悠然見碧岑。"]'),
('31857188-25b6-44cb-acd4-fc000fa47cdb','游葉丞相園有感  其一','姜特立','宋','宋诗','song-poetry','','[]','費盡心靈用盡功，林間臺榭巧玲瓏。',32,'全唐诗/poet.song.126000.json','["費盡心靈用盡功，林間臺榭巧玲瓏。", "可憐花木無愁思，不見主人依舊紅。"]'),
('f5d5d1e4-bd6a-406a-b3b1-aef38cc34aa7','游葉丞相園有感  其二','姜特立','宋','宋诗','song-poetry','','[]','功成三徑欲歸休，結束池亭處處幽。',32,'全唐诗/poet.song.126000.json','["功成三徑欲歸休，結束池亭處處幽。", "花木成時春更好，如何不作百年留。"]'),
('16cdf9ba-3647-49ef-90f8-295fb154a7b9','楊方叔過訪送行','姜特立','宋','宋诗','song-poetry','','[]','遥傳軒蓋度西岡，亟返柴車喜欲狂。',64,'全唐诗/poet.song.126000.json','["遥傳軒蓋度西岡，亟返柴車喜欲狂。", "不憚除堂十夫費，且謀解榻半窗凉。", "歸途送目雲千疊，別夜尋詩月一方。", "何日重來慰牢落，梅山花發待傳觴。"]'),
('cacf3de8-b526-491d-9460-7ebb9114167a','壬子歲送方叔','姜特立','宋','宋诗','song-poetry','','[]','經年懷抱幾曾開，面上康衢一寸埃。',32,'全唐诗/poet.song.126000.json','["經年懷抱幾曾開，面上康衢一寸埃。", "已向西偏營小築，高懸一榻待公來。"]'),
('bd3f1189-fb3c-46eb-8a74-cce41c0c4d3a','滿公臨老種松志可尚也梅山老人爲說小偈','姜特立','宋','宋诗','song-poetry','','[]','滿公種松何太癡，急景尚作千年期。',36,'全唐诗/poet.song.126000.json','["滿公種松何太癡，急景尚作千年期。", "安得雷風一夜拔千尺，與汝同看龍蛇舞月時。"]'),
('7623cafa-5235-4a1b-b138-4b040f2fa69d','感事','姜特立','宋','宋诗','song-poetry','','[]','昔人廳下纔旋馬，今代公卿甲第高。',32,'全唐诗/poet.song.126000.json','["昔人廳下纔旋馬，今代公卿甲第高。", "大屋脩椽當日事，拾遺故宅轉蕭騷。"]'),
('7b87d098-626e-4c5d-9eb9-afc2bc8274c4','晚步阡陌見水珠逡逡上沿苗葉月華露彩相映清發倘非真在田間孰知此趣因賦  其一','姜特立','宋','宋诗','song-poetry','','[]','水珠捲苗葉，夕氣轉陰機。',48,'全唐诗/poet.song.126000.json','["水珠捲苗葉，夕氣轉陰機。", "浩露添璀璨，明蟾坐發揮。", "靜窺關物理，行拂上人衣。", "除却長沮伴，能知此意稀。"]'),
('e22770bb-7b5c-4f8f-a6ce-4bb3b7ac0706','晚步阡陌見水珠逡逡上沿苗葉月華露彩相映清發倘非真在田間孰知此趣因賦  其二','姜特立','宋','宋诗','song-poetry','','[]','月璧上遥巘，水珠生晚苗。',48,'全唐诗/poet.song.126000.json','["月璧上遥巘，水珠生晚苗。", "田家足清曠，野步自超摇。", "有叟談耕鑿，無人說市朝。", "却憐膏火地，車馬客塵囂。"]'),
('b3172cde-bf03-46b9-a40d-2ed6e1522c2b','歸故園述懷呈唐伯憲  其一','姜特立','宋','宋诗','song-poetry','','[]','度柳依橋瞰淥波，緩尋花徑上松坡。',64,'全唐诗/poet.song.126000.json','["度柳依橋瞰淥波，緩尋花徑上松坡。", "莫嫌去國謀身拙，却是歸田得計多。", "舉世眩名甘汩沒，幾人聞健得婆娑。", "便須和取歸來曲，收拾餘年老薜蘿。"]'),
('e51edd3d-ed95-4c68-a8e4-3bce802271f3','歸故園述懷呈唐伯憲  其二','姜特立','宋','宋诗','song-poetry','','[]','三徑元須近，吾廬亦庶幾。',108,'全唐诗/poet.song.126000.json','["三徑元須近，吾廬亦庶幾。", "稍晴頻縱步，遇雨不愁歸。", "夕暗兒篝火，晨饑婦餉炊。", "棧羊遠可炙，櫪馬不須鞿。", "引路犬先到，慣人禽嬾飛。", "有時携曠士，把酒更論詩。", "松露滴行帳，山風吹舞衣。", "吾生身外足，此樂里中稀。", "歎息游嵩館，前賢意重違。"]'),
('ccb2c1b0-84fc-485f-b0ea-188f32adf5e3','晚晴','姜特立','宋','宋诗','song-poetry','','[]','晚晴返照射高櫨，不覺煩襟氣一蘇。',32,'全唐诗/poet.song.126000.json','["晚晴返照射高櫨，不覺煩襟氣一蘇。", "欲問明朝天色好，請看空際兩浮圖。"]'),
('218f4a29-e2cd-43e8-860a-5fdd2aa0f5b5','山園四詠 雅志堂','姜特立','宋','宋诗','song-poetry','','[]','謝公有雅志，頗愛東山游。',156,'全唐诗/poet.song.126000.json','["謝公有雅志，頗愛東山游。", "坡仙得其心，妙語寄清謳。", "蒼生事未了，已了還即休。", "彭澤小邑宰，其事固不侔。", "等閒一墨組，未死誰肯投。", "况此大功業，聲名天壤流。", "始末終不渝，盛事古鮮儔。", "信知山林樂，不貴公與侯。", "岩壑有廊廟，搢紳或戈矛。", "而况此老軀，日月不少留。", "汲汲尚不足，豈容復悠悠。", "揭榜慕前賢，駑馬睎驊騮。", "死者如可作，把酒起相酬。"]'),
('66e7b3cf-f1c0-442c-bd57-126f7f381a6e','山園四詠 風露亭','姜特立','宋','宋诗','song-poetry','','[]','萬物冒春暉，紅紫競芳節。',108,'全唐诗/poet.song.126000.json','["萬物冒春暉，紅紫競芳節。", "唯此玉井蓮，迥與衆品別。", "雅受冷風吹，復愛露華潔。", "亭亭立波上，晚意頗愁絕。", "疑是姑射仙，半夜集瑶闕。", "清虛不染塵，瀟洒更宜月。", "我慙窮陋質，對此冰與雪。", "安得謫仙人，超遥俯清澈。", "把酒一高吟，玉色相映發。"]'),
('3698cd0d-be7b-4f09-ae99-0335f12d4759','山園四詠 烟壑','姜特立','宋','宋诗','song-poetry','','[]','蒼然者爲烟，呀然者成壑。',132,'全唐诗/poet.song.126000.json','["蒼然者爲烟，呀然者成壑。", "頼此十八公，與之相領略。", "中間製小亭，面勢巧安著。", "千山攢脩眉，一水環青玉。", "勃圖映高標，觚棱翼飛角。", "夜深或沈沈，月澹還漠漠。", "趺坐者誰子，草衣復芒屩。", "素髮照晴昊，飄蕭如野鶴。", "儻非違世者，何以有此樂。", "向夕下坡陀，清興寄寥廓。", "此境真可畫，此意終難貌。"]'),
('400c523d-389e-44fb-9ce0-36e523ab9ab0','山園四詠 醒心亭','姜特立','宋','宋诗','song-poetry','','[]','昔人醒心處，唯恐玉山頹。',120,'全唐诗/poet.song.126000.json','["昔人醒心處，唯恐玉山頹。", "我今醒心亭，正與醉爲媒。", "醒心非醒酒，所醒遺形骸。", "如病得大丹，如夢忽驚回。", "如闇秉巨燭，如蟄發春雷。", "有時酩酊中，蘧蘧自形開。", "下視名利場，昏曉走塵埃。", "醒處元不醒，醉時良可哀。", "嗟哉我何人，顛倒有至懷。", "不求醉中醒，却醉醒中杯。"]'),
('bc606663-9248-4241-a148-11b3ab86f180','寄里中諸友賞菊二首  其一','姜特立','宋','宋诗','song-poetry','','[]','問訊故園今若何，不堪歸計尚蹉跎。',32,'全唐诗/poet.song.126000.json','["問訊故園今若何，不堪歸計尚蹉跎。", "祇應庭下千叢菊，今歲雨勻花更多。"]'),
('62028cca-ce08-4ca6-a1ea-50281b6da1e2','寄里中諸友賞菊二首  其二','姜特立','宋','宋诗','song-poetry','','[]','夢寐家園百里間，秋來青蕊想班班。',32,'全唐诗/poet.song.126000.json','["夢寐家園百里間，秋來青蕊想班班。", "但得諸公爲臨賞，也如老子對南山。"]'),
('b9baa30f-7f8c-4462-a447-33c96bedf06f','老去','姜特立','宋','宋诗','song-poetry','','[]','老去光陰日日慳，更無大藥駐朱顔。',32,'全唐诗/poet.song.126000.json','["老去光陰日日慳，更無大藥駐朱顔。", "近來學得長生訣，十二時中總放閒。"]'),
('95bf25eb-ea58-458b-87f9-199040e17d6e','佛桑花','姜特立','宋','宋诗','song-poetry','','[]','東方聞有扶桑木，南土今開朱槿花。',32,'全唐诗/poet.song.126000.json','["東方聞有扶桑木，南土今開朱槿花。", "想得分根自暘谷，至今猶带日精華。"]'),
('b498e9a0-5fc5-4564-b9bd-a62ab9ca29ef','送潘叔昌主教清湘','姜特立','宋','宋诗','song-poetry','','[]','醖藉金閨客，風流粉署郎。',48,'全唐诗/poet.song.126000.json','["醖藉金閨客，風流粉署郎。", "文嘗追屈賈，身合到瀟湘。", "經術東萊學，才名上國光。", "遐方豈淹泊，雲路看騰驤。"]'),
('8cdc7f39-36c3-4285-9671-d9b0c20dd187','雙林益老養直之後入都見朝貴覓詩','姜特立','宋','宋诗','song-poetry','','[]','正平有詩孫，蘇氏代不乏。',48,'全唐诗/poet.song.126000.json','["正平有詩孫，蘇氏代不乏。", "來傳大士印，去說宰官法。", "霜令方清高，行色待明發。", "蚤賦歸來篇，莫負碧雲合。"]'),
('0cc3c021-db3a-49ea-8b5d-9715c587c428','寄方叔游法輪寺三首  其一','姜特立','宋','宋诗','song-poetry','','[]','山中境最靜，靜極恐關情。',24,'全唐诗/poet.song.126000.json','["山中境最靜，靜極恐關情。", "莫聽流鶑語，應懷求友聲。"]'),
('6f6602ef-ad18-4f60-815c-9317bdebdb5c','寄方叔游法輪寺三首  其二','姜特立','宋','宋诗','song-poetry','','[]','一別三四日，已懷千萬情。',24,'全唐诗/poet.song.126000.json','["一別三四日，已懷千萬情。", "醒心亭下水，先作夜吟聲。"]'),
('a2b357b9-6529-4cde-9176-4eaba45ab355','寄方叔游法輪寺三首  其三','姜特立','宋','宋诗','song-poetry','','[]','境靜約心兵，無由起妄情。',24,'全唐诗/poet.song.126000.json','["境靜約心兵，無由起妄情。", "擬將笙笛耳，同聽夜泉聲。"]'),
('275ce461-b945-4d23-ae4f-40696df898c7','廢桑畦種花  其一','姜特立','宋','宋诗','song-poetry','','[]','課僕斸桑窠，從頭盡種花。',24,'全唐诗/poet.song.126000.json','["課僕斸桑窠，從頭盡種花。", "莫教聶子見，怪我不栽禾。"]'),
('e598a81c-5c0e-45f7-a619-132a2c1e988d','廢桑畦種花  其二','姜特立','宋','宋诗','song-poetry','','[]','種花真濩落，曾不救號寒。',24,'全唐诗/poet.song.126000.json','["種花真濩落，曾不救號寒。", "我自金芍藥，從渠黑牡丹。"]'),
('f661838c-a560-458e-9b0c-42b3378ab039','脩竹爲王俊卿國正賦所居也','姜特立','宋','宋诗','song-poetry','','[]','入門見脩竹，茲士已可人。',48,'全唐诗/poet.song.126000.json','["入門見脩竹，茲士已可人。", "不必問寒溫，便可飲清醇。", "此興諒不淺，此意亦已真。", "安得王子猷，相與共卜鄰。"]'),
('65c40016-86ce-4fcd-97b9-22d50606c6d4','閒詠三首  其一','姜特立','宋','宋诗','song-poetry','','[]','莫笑歸耕計未然，我今得計是歸田。',32,'全唐诗/poet.song.126000.json','["莫笑歸耕計未然，我今得計是歸田。", "天公若也憐衰晚，更乞閒身二十年。"]'),
('26c0d5f0-0abd-45b1-b14b-521b59747a41','閒詠三首  其二','姜特立','宋','宋诗','song-poetry','','[]','銅山鼓鑄成何用，金谷榮華畢竟空。',32,'全唐诗/poet.song.126000.json','["銅山鼓鑄成何用，金谷榮華畢竟空。", "老子百年無長物，只留明月與清風。"]'),
('30508d04-18d3-4222-aded-1a9dfe1d04bd','閒詠三首  其三','姜特立','宋','宋诗','song-poetry','','[]','醒心亭下弄潺湲，雅志堂前擁髻鬟。',32,'全唐诗/poet.song.126000.json','["醒心亭下弄潺湲，雅志堂前擁髻鬟。", "除却華山陳處士，祇今誰似此翁閒。"]'),
('777a3c48-a9c0-45fa-8e19-71229eeaa1b8','寄陸郎中','姜特立','宋','宋诗','song-poetry','','[]','整整平頭七十春，兩翁可是太陳陳。',32,'全唐诗/poet.song.126000.json','["整整平頭七十春，兩翁可是太陳陳。", "世間過眼無非故，唯有詩情老更新。"]'),
('0c588a9e-5dee-46b0-beef-abf964f5504c','李仲永墨梅','姜特立','宋','宋诗','song-poetry','','[]','寫竹如草書，患俗不患清。',170,'全唐诗/poet.song.126000.json','["寫竹如草書，患俗不患清。", "畫梅如相馬，以骨不以形。", "墨君曩有文夫子，蟬腹蛇跗具生意。", "當時一派屬蘇公，雨葉風枝畧相似。", "花光道人執天機，信手掃出孤山姿。", "陳玄幻却西子面，此妙俗士那能知。", "近時賞愛楊補之，補之嫵媚不足奇。", "李生於梅却有得，高處自與前人敵。", "倒暈踈花出古心，暝雲暗谷藏春色。", "我一見之三歎息，意足不暇形模索。", "君若欲求之點畫，胡不去看江頭千樹白。"]'),
('2c4ba402-3b7e-45ec-ab46-213a12e75c78','和趙太中覓詩','姜特立','宋','宋诗','song-poetry','','[]','每嘆學詩如學仙，未能換骨謾成篇。',64,'全唐诗/poet.song.126000.json','["每嘆學詩如學仙，未能換骨謾成篇。", "翰林萬丈光常在，著作三都賦蚤傳。", "半世無成負便腹，終年有味聳吟肩。", "明珠何事輕彈雀，多謝高情未棄捐。"]'),
('549a6c63-adbb-4380-958f-42f10229e3d3','說詩','姜特立','宋','宋诗','song-poetry','','[]','作者固已難，讀者亦未易。',168,'全唐诗/poet.song.126000.json','["作者固已難，讀者亦未易。", "有寶斯識寶，至寶况難值。", "三家寠人子，豈辨瑚璉器。", "鼠璞將見珍，周鼎或斡棄。", "詩道誠難言，大要該六義。", "其高出蒼天，其深潛厚地。", "枯中發穠華，淡處有餘味。", "似拙乃藏巧，借鈍以宣利。", "開闊要波瀾，組織須經緯。", "或險而莫親，或平而足貴。", "圓轉各隨形，悟入非力至。", "不止事吟哦，先須存興寄。", "變態千萬端，勝處同一致。", "以此而讀詩，庶得古人意。"]'),
('2cc81e4e-a288-4766-9bbd-05a0c7b06d28','寄恪','姜特立','宋','宋诗','song-poetry','','[]','忽得平安信，新知進學功。',48,'全唐诗/poet.song.126000.json','["忽得平安信，新知進學功。", "慮深心更苦，趣靜句仍工。", "所貴身無玷，何憂祿未豐。", "望雲休作念，正要爾移忠。"]'),
('531a0b24-2e8a-4b6e-8d36-745d67e8d78d','歸故園二首  其一','姜特立','宋','宋诗','song-poetry','','[]','坐叨厚廩傍吾家，此去吾家百里賒。',32,'全唐诗/poet.song.126000.json','["坐叨厚廩傍吾家，此去吾家百里賒。", "聖主恩深難報處，四時得看故園花。"]'),
('9760e79b-76d0-4ca0-8b35-f793ff66a816','歸故園二首  其二','姜特立','宋','宋诗','song-poetry','','[]','一去丹墀六換春，已將柴柵等簪紳。',32,'全唐诗/poet.song.126000.json','["一去丹墀六換春，已將柴柵等簪紳。", "雖無名節高當世，也是羊裘一故人。"]'),
('7a6b19da-789b-46b1-bfce-8f4956125748','退語','姜特立','宋','宋诗','song-poetry','','[]','灧澦堆邊百丈絕，宋都六鷁風逆折。',42,'全唐诗/poet.song.126000.json','["灧澦堆邊百丈絕，宋都六鷁風逆折。", "曹公燒船烟燄徹，苻秦百萬走流血，未若姜子之退最勇决。"]'),
('e784178c-f240-4346-b7cf-ec8e1ee2bab2','送邦直弟歸鄉','姜特立','宋','宋诗','song-poetry','','[]','有弟自吾里，相從兩月餘。',48,'全唐诗/poet.song.126000.json','["有弟自吾里，相從兩月餘。", "老來歸日少，別去見時踈。", "魚隊猶前日，鴒原尚故居。", "不知風雨夕，相憶更何如。"]'),
('a5028e36-d435-4303-a885-b0f993a952f2','同官游赤松二首  其一','姜特立','宋','宋诗','song-poetry','','[]','今朝乘興出林坰，商略天公未肯晴。',32,'全唐诗/poet.song.126000.json','["今朝乘興出林坰，商略天公未肯晴。", "日色忽收梅氣潤，山光便挾麥風清。"]'),
('790bd6d4-3353-4fe6-9672-bbfc0cbe97f6','同官游赤松二首  其二','姜特立','宋','宋诗','song-poetry','','[]','山輿翠蓋出華顛，白㲲衣衫皂作緣。',32,'全唐诗/poet.song.126000.json','["山輿翠蓋出華顛，白㲲衣衫皂作緣。", "我輩自應三洞主，傍人喚作五通仙。"]'),
('322c3cc8-90aa-40b0-bff3-b07c0ddeaf94','呈方叔','姜特立','宋','宋诗','song-poetry','','[]','聱牙落魄一閒官，職事何嘗見一斑。',64,'全唐诗/poet.song.126000.json','["聱牙落魄一閒官，職事何嘗見一斑。", "不是論松須說劍，若非尋壑即觀山。", "閒看落葉隨風去，冷笑奔雲送雨還。", "更有劉巖楊處士，伴渠癡坐老花間。"]'),
('230afe26-f9ce-4348-b335-1ad397db626f','歸故園二首  其一','姜特立','宋','宋诗','song-poetry','','[]','向來叨趁內朝班，宮漏雞聲曉夢間。',32,'全唐诗/poet.song.126000.json','["向來叨趁內朝班，宮漏雞聲曉夢間。", "今日身閒無一事，五年睡債一時還。"]'),
('84c29d9c-c4a3-4c4c-98ee-9aa98155d121','歸故園二首  其二','姜特立','宋','宋诗','song-poetry','','[]','桃李歸來已半空，不堪春事去匆匆。',32,'全唐诗/poet.song.126000.json','["桃李歸來已半空，不堪春事去匆匆。", "落紅猶自留連客，故向尊前舞晚風。"]'),
('255386c0-335f-4e2a-b049-a87d34586e5c','送雙林益老','姜特立','宋','宋诗','song-poetry','','[]','老鶴精神不受羈，今朝何事又孤飛。',64,'全唐诗/poet.song.126000.json','["老鶴精神不受羈，今朝何事又孤飛。", "不依大士雙林住，却向東峯小隠歸。", "野色草堂開泱漭，晨光日觀接熹微。", "此時四脚棋盤上，坐斷人間第一機。"]'),
('db5b3f67-3ca0-41ec-92e0-66d9b6de6698','迓木詹事','姜特立','宋','宋诗','song-poetry','','[]','出郭轉蕭瑟，寒溪生素波。',48,'全唐诗/poet.song.126000.json','["出郭轉蕭瑟，寒溪生素波。", "茅簷迎日暖，楓岫占秋多。", "從宦嗟吾嬾，流年奈爾何。", "念歸應不遠，新菊已緣坡。"]'),
('2942c064-85bf-4f0a-a134-edab1a216f83','扃岫爲張支使作二首  其一','姜特立','宋','宋诗','song-poetry','','[]','士衡招隠翠幄，長統卜居露幃。',28,'全唐诗/poet.song.126000.json','["士衡招隠翠幄，長統卜居露幃。", "未若君家扃岫，千峯盡鎖雙扉。"]'),
('8a95c603-fbd6-4482-881f-9c4c314f8de5','扃岫爲張支使作二首  其二','姜特立','宋','宋诗','song-poetry','','[]','老去林泉屬我，時來軒冕輸君。',28,'全唐诗/poet.song.126000.json','["老去林泉屬我，時來軒冕輸君。", "正好南冥運翼，未用北山移文。"]'),
('78d77db0-44e3-4e73-9a5d-62db8bf5d957','次韻陸郎中','姜特立','宋','宋诗','song-poetry','','[]','亟報門前寄好音，炯然書札照家林。',64,'全唐诗/poet.song.126000.json','["亟報門前寄好音，炯然書札照家林。", "興來自說宦情薄，詩到方知秋思深。", "臨老讀書因教子，閉門捫蝨爲搜吟。", "當今大筆如君少，未用深藏嘆陸沈。"]'),
('5fd164e8-163f-4f95-ba7f-16bf81b324a9','重題八詠樓','姜特立','宋','宋诗','song-poetry','','[]','每到樓中憶沈郎，碑間文字爛生光。',64,'全唐诗/poet.song.126000.json','["每到樓中憶沈郎，碑間文字爛生光。", "四時山色藏烟雨，兩派波光下夕陽。", "湛輩僅能登峴首，召南元自愛甘棠。", "英游已遠空追想，附驥猶堪託短章。"]'),
('6ebc185b-3db4-49d5-8cb4-739d526bf26b','戲呈趙舜臣覓酒二首  其一','姜特立','宋','宋诗','song-poetry','','[]','畢君甕下幾成縛，屈子江邊又獨醒。',32,'全唐诗/poet.song.126000.json','["畢君甕下幾成縛，屈子江邊又獨醒。", "頼有東陽賢府主，不嫌馳騎送寒廳。"]'),
('f7e52be8-56bc-4e50-b0dc-94bbfb307c69','戲呈趙舜臣覓酒二首  其二','姜特立','宋','宋诗','song-poetry','','[]','兵厨釀乏吻生烟，阮校如今作贅員。',32,'全唐诗/poet.song.126000.json','["兵厨釀乏吻生烟，阮校如今作贅員。", "却怪淵明便歸去，酒材猶自有圭田。"]'),
('c77420ca-34a0-40eb-8d57-00fecbc09458','感夢','姜特立','宋','宋诗','song-poetry','','[]','前後升沈二十年，向來孤冷偶同然。',32,'全唐诗/poet.song.126000.json','["前後升沈二十年，向來孤冷偶同然。", "夢中許我傳衣鉢，敢望功名却比肩。"]'),
('e5876964-ad39-4f39-a304-83648063bdd9','游赤松小桃源','姜特立','宋','宋诗','song-poetry','','[]','仙山千疊擁雲屏，行到桃源境更清。',32,'全唐诗/poet.song.126000.json','["仙山千疊擁雲屏，行到桃源境更清。", "坐久令人思謝傅，欠渠低唱兩三聲。"]'),
('154b3687-17f9-4114-b254-efd5516d27e0','和唐戶古律三首  其一','姜特立','宋','宋诗','song-poetry','','[]','世事每多違，苦心終眷眷。',48,'全唐诗/poet.song.126000.json','["世事每多違，苦心終眷眷。", "功名等摶沙，歲月如奔電。", "古人竟何許，厚祿良難戀。", "冥鴻已高翔，歸翼方知倦。"]'),
('0d9e522f-9209-427d-94e8-4b95d829d183','和唐戶古律三首  其二','姜特立','宋','宋诗','song-poetry','','[]','我來雙溪上，正值黄花秋。',48,'全唐诗/poet.song.126000.json','["我來雙溪上，正值黄花秋。", "方爲逆旅計，未辦佳賓留。", "絕憐北鄰阮，不厭東家丘。", "詩盟今幾人，肯著老子不。"]'),
('4e71cdcb-a6f9-4275-9254-1bde36189e2a','和唐戶古律三首  其三','姜特立','宋','宋诗','song-poetry','','[]','雋譽早知畏，佳篇今見蒙。',48,'全唐诗/poet.song.126000.json','["雋譽早知畏，佳篇今見蒙。", "幺響去寂寂，正聲日隆隆。", "愛君甘苦外，與我嗜好同。", "不妨時袖句，共作聖賢中。"]'),
('40f1ecfb-8120-4ed4-8359-b11b5a7aed84','歲暮月下有懷','姜特立','宋','宋诗','song-poetry','','[]','春事侵紅蕊，年光入白髭。',48,'全唐诗/poet.song.126000.json','["春事侵紅蕊，年光入白髭。", "暖雲籠月夜，斜照放燈時。", "羈宦元無味，清愁只有詩。", "故山無百里，夢寐數歸期。"]'),
('ff94a01b-89be-41ed-89cf-5779cea1889a','和唐伯憲二首  其一','姜特立','宋','宋诗','song-poetry','','[]','倦翼投深樾，驚鱗憶故川。',48,'全唐诗/poet.song.126000.json','["倦翼投深樾，驚鱗憶故川。", "淵明松有逕，楊惲豆宜田。", "窮達安微分，行藏媿昔賢。", "此心誰盡了，達此固怡然。"]'),
('dd728a12-799e-4bc6-a3aa-0383c82254a6','和唐伯憲二首  其二','姜特立','宋','宋诗','song-poetry','','[]','卜鄰初識面，把臂便論詩。',48,'全唐诗/poet.song.126000.json','["卜鄰初識面，把臂便論詩。", "摸索曹劉耦，憑陵漢魏時。", "新章專雅潔，古隸更清奇。", "若比江西派，無人說具茨。"]'),
('4ba311e7-97c0-4212-ad38-ee993f7cf421','唐伯憲赴括蒼戶掾','姜特立','宋','宋诗','song-poetry','','[]','吾州刺史宅，上冠靈鰲顛。',144,'全唐诗/poet.song.126000.json','["吾州刺史宅，上冠靈鰲顛。", "千嶂翠合沓，一水清潺湲。", "北指烟雨近，西睇鶑花連。", "積李雪縞夜，崇桃霞覆川。", "羣材聚仙境，上幕開中天。", "宜有唐景輩，參與鄒枚聯。", "戶掾吾故人，學問自家傳。", "隸法既奇古，詩句仍清圓。", "想當吟哦時，攬勝筆如椽。", "坐使冰雪腸，沉浸含芳鮮。", "試諗吾邦人，世豈有此賢。", "勿歎官尚卑，行矣當騰騫。"]'),
('b980f4b6-fb35-49e0-a1fc-d46ce436db55','再賦醒心亭','姜特立','宋','宋诗','song-poetry','','[]','小橋枕滄灣，一水繞清激。',132,'全唐诗/poet.song.126000.json','["小橋枕滄灣，一水繞清激。", "橫來莫知源，委去無尋迹。", "戲魚時度淺，好鳥忽鳴寂。", "堂坳隠空谾，竹樹閟寒碧。", "朝霏溢朱栱，倒影汎瑶席。", "仰窺一逕上，始覺藏深僻。", "尚憶客中行，盤嶠倦登陟。", "峯回路忽下，溪館曾休息。", "高低相掩映，景趣無終極。", "朅來坐忘疲，欲去或窮夕。", "安得青霞人，共此白雲適。"]'),
('1d1cbb4c-d03f-4178-85a3-926de387551b','送方叔二首  其一','姜特立','宋','宋诗','song-poetry','','[]','我走塵埃君入山，須知靜躁不相關。',32,'全唐诗/poet.song.126000.json','["我走塵埃君入山，須知靜躁不相關。", "何時賓主俱無事，雅志堂前一解顔。"]'),
('779e3c97-ff10-450a-b5a3-980b7db2cae0','送方叔二首  其二','姜特立','宋','宋诗','song-poetry','','[]','海鸞天外絕虞羅，偶爾來游澗谷阿。',32,'全唐诗/poet.song.126000.json','["海鸞天外絕虞羅，偶爾來游澗谷阿。", "世上稻粱留不得，翩然還戀玉山禾。"]'),
('53decd3c-24da-40bc-be32-debadf58a65a','次韵巖桂','姜特立','宋','宋诗','song-poetry','','[]','濃香透徹泥丸頂，更惱詩腸卒未休。',32,'全唐诗/poet.song.126000.json','["濃香透徹泥丸頂，更惱詩腸卒未休。", "安得此花長不老，盡回四序作清秋。"]'),
('8d8a3137-f3ef-4dac-ada5-c98279a5fdd1','和荆公二首  其一','姜特立','宋','宋诗','song-poetry','','[]','老去生涯華子岡，年來得失一繩床。',32,'全唐诗/poet.song.126000.json','["老去生涯華子岡，年來得失一繩床。", "是非堯桀何須較，身世於今更兩忘。"]'),
('a5d5ddba-a53b-483f-be8c-96632fb6a054','和荆公二首  其二','姜特立','宋','宋诗','song-poetry','','[]','子房不願蕭曹位，底事穰侯畏客來。',32,'全唐诗/poet.song.126000.json','["子房不願蕭曹位，底事穰侯畏客來。", "得一老兵皆可飲，何須車馬便驚猜。"]'),
('9bff9dd6-5ec4-42fd-b0f7-4eaf10c960fe','閒詠','姜特立','宋','宋诗','song-poetry','','[]','坐叨厚廩飲醇醪，不挾文書不坐曹。',64,'全唐诗/poet.song.126000.json','["坐叨厚廩飲醇醪，不挾文書不坐曹。", "檢校園花爲日課，裒尋詩草計年勞。", "仍將書冊供慵卧，時喚杯盤佐老饕。", "感激大恩何以報，唯祈聖壽等天高。"]'),
('f1e72c7f-79f1-4543-9d8a-9fd53ce34585','吳煥章送行','姜特立','宋','宋诗','song-poetry','','[]','素行躬韋布，長材轢搢紳。',144,'全唐诗/poet.song.126000.json','["素行躬韋布，長材轢搢紳。", "老成吾甚畏，競爽爾誰鄰。", "半刺人稱屈，全牛技未伸。", "難兄曾託契，薄宦偶同寅。", "和韵長愁險，開樽屢飲醇。", "高談烘白晝，妙舞艷青春。", "方幸交情密，還欣道義親。", "到家才旦暮，回首遽參辰。", "越榜驚行速，吳牋荷寄頻。", "施松從此始，折柳竟無因。", "指日騰夷路，茲時記故人。", "聊憑五字句，千里話慇懃。"]'),
('b5128f57-2bb9-4dd7-a0db-08312ce99003','和鞏宰送牡丹三首  其一','姜特立','宋','宋诗','song-poetry','','[]','香泥筠籠遠擎來，曾向河陽縣裏開。',32,'全唐诗/poet.song.126000.json','["香泥筠籠遠擎來，曾向河陽縣裏開。", "堪笑杜陵何短拙，却憑蕭八覓桃栽。"]'),
('ed572324-01cf-4f79-933f-6fbe3ac1c5c7','和鞏宰送牡丹三首  其二','姜特立','宋','宋诗','song-poetry','','[]','唐世花名寖顯時，才如韓白尚無詩。',32,'全唐诗/poet.song.126000.json','["唐世花名寖顯時，才如韓白尚無詩。", "本朝盛賞唯西雒，萬幄千庖泣玉脂。"]'),
('5343b015-e418-427d-a191-fe52446e63cb','和鞏宰送牡丹三首  其三','姜特立','宋','宋诗','song-poetry','','[]','品格高低各自春，大如玉斗滿如輪。',32,'全唐诗/poet.song.126000.json','["品格高低各自春，大如玉斗滿如輪。", "前賢曾譜花王說，唯有姚黄始是真。"]'),
('99b4d6df-f298-41f4-a92c-a62091656a03','田文','姜特立','宋','宋诗','song-poetry','','[]','田文養士天下無，撞鍾列鼎傾金珠。',48,'全唐诗/poet.song.126000.json','["田文養士天下無，撞鍾列鼎傾金珠。", "入關幾作秦囚拘，當時貴客如橛株。", "倉皇脫死託小夫，嗟哉所養非所需。"]'),
('3639034a-9423-48dd-8d8b-95e400df3a21','劉致政壽藏歸庵','姜特立','宋','宋诗','song-poetry','','[]','我愛青溪山，峰巒秀如刻。',48,'全唐诗/poet.song.126000.json','["我愛青溪山，峰巒秀如刻。", "作庵賢主人，只恐歸未得。", "且住三千秋，游戲人間客。", "遺蛻何足論，西乾有真宅。"]'),
('85c15c8e-2946-4705-95b7-8fa0292e53af','應致遠謁放翁','姜特立','宋','宋诗','song-poetry','','[]','雙溪雪消水生波，有客袖句來相過。',160,'全唐诗/poet.song.126000.json','["雙溪雪消水生波，有客袖句來相過。", "自言平生有詩僻，擺落世故工吟哦。", "不願垂腰連六印，不願爰田封萬戶。", "唯於前輩識蘇黄，却向古人窺李杜。", "嗚呼斷絃誰續髓，風雅道喪騷人死。", "三山先生真若人，獨將詩壇壁孤壘。", "此翁筆力回萬牛，淡處有味枯中膏。", "有時奇險不可迫，劍門石角錢塘濤。", "源流不嗣江西祖，自有正宗傳法乳。", "請君去直箭鋒機，歸來聽我禾山皷。"]'),
('5a2074b5-7f98-4823-9f50-d8ac187954cc','野步','姜特立','宋','宋诗','song-poetry','','[]','江山客思滿，雲水稻田空。',24,'全唐诗/poet.song.126000.json','["江山客思滿，雲水稻田空。", "日塢懸秋實，霜林墜晚紅。"]'),
('3884433c-e583-4d07-8995-5599219d1282','王方叔喪耦','姜特立','宋','宋诗','song-poetry','','[]','人生大患身爲累，火宅啼號更累身。',32,'全唐诗/poet.song.126000.json','["人生大患身爲累，火宅啼號更累身。", "聞道中郎唯有女，不妨半世作閒人。"]'),
('1f2b6ffc-f962-4d2f-bdf2-5ca7f2856ee4','余壯歲嘗假居塔山寺後三十年重到賦二絕  其一','姜特立','宋','宋诗','song-poetry','','[]','故山重到思依依，不見霜眉雪頂師。',32,'全唐诗/poet.song.126000.json','["故山重到思依依，不見霜眉雪頂師。", "三十年間真一夢，夜檠猶記讀書時。"]'),
('3f0316d0-d653-452b-8c93-61f1aeca563b','余壯歲嘗假居塔山寺後三十年重到賦二絕  其二','姜特立','宋','宋诗','song-poetry','','[]','一堕紅塵六載餘，黄金不染白髭鬚。',32,'全唐诗/poet.song.126000.json','["一堕紅塵六載餘，黄金不染白髭鬚。", "向來猿鶴應相問，瑠合犀缾無恙無。"]'),
('d79c7044-6930-4ec9-8c35-54c538ce5319','兩生','姜特立','宋','宋诗','song-poetry','','[]','齊魯云何兩大臣，初無名字掛朝紳。',32,'全唐诗/poet.song.126000.json','["齊魯云何兩大臣，初無名字掛朝紳。", "若將出處評高致，更是夔龍以上人。"]'),
('82212a64-e165-4a55-ad66-ecb44a696d74','感懷效淵明體','姜特立','宋','宋诗','song-poetry','','[]','人生百年中，長爲子孫憂。',108,'全唐诗/poet.song.126000.json','["人生百年中，長爲子孫憂。", "人生百年後，死生兩悠悠。", "流傳至曾玄，恩愛竟何許。", "孤墳千萬禩，莫適誰爲主。", "嗟哉世間人，小黠而大癡。", "惜衣仍忍寒，省口仍忍饑。", "一朝大化盡，未免世俗嗤。", "存者且偷生，逝者歸無期。", "眼前一樽酒，勸君且重持。"]'),
('5b424acd-bedd-4700-8928-59da1a54f841','客至','姜特立','宋','宋诗','song-poetry','','[]','凍雲垂地寒崢嶸，故人訪我邀晨烹。',32,'全唐诗/poet.song.126000.json','["凍雲垂地寒崢嶸，故人訪我邀晨烹。", "旋燒姜子金絲酒，却試蘇公玉糝羹。"]'),
('5f0be73a-a9a7-4b9d-9649-963d597417bf','出處','姜特立','宋','宋诗','song-poetry','','[]','士貴重其身，出處各有道。',48,'全唐诗/poet.song.126000.json','["士貴重其身，出處各有道。", "一爲己私蔽，喪却千金寶。", "我非真勇者，歸意良草草。", "逵路方多岐，幾人能辨早。"]'),
('62a5341d-83b4-4ff5-b1a4-8394a5383427','送盧漕','姜特立','宋','宋诗','song-poetry','','[]','昔忝二三子，今俱七十翁。',48,'全唐诗/poet.song.126000.json','["昔忝二三子，今俱七十翁。", "西州十年別，南部一尊同。", "我已三徑具，君還雙鬢蓬。", "便須輕世事，留眼送飛鴻。"]'),
('5f4eed76-afa6-4a9a-a8f8-217cd399c48f','偶成','姜特立','宋','宋诗','song-poetry','','[]','蜨因變化多膠網，魚爲飛升却曝鱗。',32,'全唐诗/poet.song.126000.json','["蜨因變化多膠網，魚爲飛升却曝鱗。", "唯有冥鴻無羨慕，世間矰弋莫相親。"]'),
('edaba69e-cdde-4bbb-bb88-8a8af853f4d5','古風送鄭路鈐','姜特立','宋','宋诗','song-poetry','','[]','故人訪我雙溪邊，袖中明月五筰連。',128,'全唐诗/poet.song.126000.json','["故人訪我雙溪邊，袖中明月五筰連。", "一笑傾倒秋風前，復憶鷺序同聯翩。", "君今半老我皤然，功名富貴空中烟。", "南柯蟻穴醯雞天，鶴長鳬短誰虧全。", "我今日月箭脫弦，夜行不止真可憐。", "不如歸釣清泠淵，日高未起醉即眠。", "心和氣定養壽年，世間萬事姑隨緣。", "交情儻或未棄捐，不妨時寄相思篇。"]'),
('ef4dfac1-ce61-4425-a7e7-a556c4159689','公館','姜特立','宋','宋诗','song-poetry','','[]','公館當清夜，移樽近北墉。',24,'全唐诗/poet.song.126000.json','["公館當清夜，移樽近北墉。", "秋聲連蟋蟀，月色淡芙蓉。"]'),
('69a8ce45-0594-437c-bb2c-26567f206adb','次楊元會白蓮二首  其一','姜特立','宋','宋诗','song-poetry','','[]','月爲精彩雪爲膚，翠蓋迎風漾綠珠。',32,'全唐诗/poet.song.126000.json','["月爲精彩雪爲膚，翠蓋迎風漾綠珠。", "我欲褰裳賒一顧，能回玉面向人無。"]'),
('e78be6b9-b4f3-4181-ab8e-1cf31135ed3a','次楊元會白蓮二首  其二','姜特立','宋','宋诗','song-poetry','','[]','不御鉛華似洛妃，清虛全與道相宜。',32,'全唐诗/poet.song.126000.json','["不御鉛華似洛妃，清虛全與道相宜。", "月明何處回仙駕，獨立沙頭爾許時。"]'),
('b695cd61-9627-4e14-85d9-2ae60898e4c3','郡中朔旦朝拜聖祖','姜特立','宋','宋诗','song-poetry','','[]','巍像儼明庭，衣冠盡夙興。',48,'全唐诗/poet.song.126000.json','["巍像儼明庭，衣冠盡夙興。", "曙光摇斗極，雲氣掣觚稜。", "嘗記朝天日，君王玉座升。", "璇霄烏萬點，飛舞最高層。"]'),
('d5c2751c-9f6c-4d2f-87e2-d276ccafd3b5','方叔元振元老同令姪舍人見訪','姜特立','宋','宋诗','song-poetry','','[]','聯翩三鳳接華裀，小阮驅車復後塵。',32,'全唐诗/poet.song.126000.json','["聯翩三鳳接華裀，小阮驅車復後塵。", "嵇呂相思千古事，後來命駕更無人。"]'),
('3017cd7f-8bdc-4a15-98d9-0890ae5390b4','九日寄楊方叔','姜特立','宋','宋诗','song-poetry','','[]','安穩楊夫子，秋來闕寄音。',48,'全唐诗/poet.song.126000.json','["安穩楊夫子，秋來闕寄音。", "遥憐好兄弟，相伴老山林。", "菊是故園色，人無舊賞心。", "雲萍兩漂泊，西望一長吟。"]'),
('4cb74ca0-d0c6-4120-bb4e-7d3c62cf6644','右寄此詩後忽得簡云兒曹亦寄五言用韵皆同殆一段佳話遂再賦長句','姜特立','宋','宋诗','song-poetry','','[]','天性固自同，學問亦有源。',108,'全唐诗/poet.song.126000.json','["天性固自同，學問亦有源。", "胡爲兩章句，韵韵皆蟬聯。", "有如五音作，琴瑟隨宮懸。", "排比不亂行，又似貫珠然。", "竊意予父子，與公有世緣。", "精神所交感，默契難言詮。", "書來亟報我，故事前無傳。", "欲將此段奇，竟入佳話編。", "况復惠新句，律呂遞相宣。"]'),
('68f4c402-d693-41f0-90a4-3352942fa3db','子陵','姜特立','宋','宋诗','song-poetry','','[]','不爲故人屈，清名日月高。',48,'全唐诗/poet.song.126000.json','["不爲故人屈，清名日月高。", "當時若相漢，不過比元侯。", "元侯功易歇，子陵名不滅。", "所以想孤風，猶如隔前日。"]'),
('7b90415a-551a-48ec-bdc5-69244ba3903a','欲雪','姜特立','宋','宋诗','song-poetry','','[]','嘯侶饑鳶愁古木，啅羣凍雀聚踈籬。',32,'全唐诗/poet.song.126000.json','["嘯侶饑鳶愁古木，啅羣凍雀聚踈籬。", "一庭寒意沉沉靜，正是江天欲雪時。"]'),
('be5229c0-1a56-49f0-b589-81a6a549e66b','冬至','姜特立','宋','宋诗','song-poetry','','[]','老來心緒怯年光，又見春來報一陽。',32,'全唐诗/poet.song.126000.json','["老來心緒怯年光，又見春來報一陽。", "未必暗添宮線永，只應先引鬢絲長。"]'),
('438d7e70-887a-4c53-9866-99d485bb12b9','鵬鷃問答','姜特立','宋','宋诗','song-poetry','','[]','吾聞北冥鵬，翼若垂天雲。',180,'全唐诗/poet.song.126000.json','["吾聞北冥鵬，翼若垂天雲。", "矯首扶桑汜，投趾崑崙垠。", "渴飲黄河流，饑食紫淵鱗。", "長翮盈千車，短羽重萬鈞。", "去以六月息，棲止良苦辛。", "黑風忽翻海，未易容其身。", "偶與斥鷃遇，問鷃有何樂。", "鷃云我幺禽，豈暇議寥廓。", "爲生誠甚微，爲計亦易足。", "吸以棘針露，分以鷦鷯粟。", "决起槍榆間，却向蓬蒿落。", "不睎九萬程，只願一枝託。", "鵬聽鷃所云，似若生羨慕。", "彼小乃有餘，我大適爲苦。", "呼鷃問所安，鷃笑而不語。"]'),
('d2253727-5904-4f7c-bd36-e5bd86ce048d','送墨魚鞏大監','姜特立','宋','宋诗','song-poetry','','[]','底事呼爲海裏羊，陀尼爲背錦爲裳。',32,'全唐诗/poet.song.126000.json','["底事呼爲海裏羊，陀尼爲背錦爲裳。", "慇懃送似曲湖老，要薦君家玳瑁觴。"]'),
('31398adb-ca77-4a54-a586-d56b2aabfa60','脩謁','姜特立','宋','宋诗','song-poetry','','[]','偶爾事脩謁，籃輿經近村。',24,'全唐诗/poet.song.126000.json','["偶爾事脩謁，籃輿經近村。", "田夫不避客，袖手立衡門。"]'),
('b99686b4-13ff-449d-bead-66100931572a','野薔薇','姜特立','宋','宋诗','song-poetry','','[]','擬花無品格，在野有光輝。',48,'全唐诗/poet.song.126000.json','["擬花無品格，在野有光輝。", "香薄當初夏，陰濃蔽夕暉。", "籬根堆素錦，樹杪掛明璣。", "萬物生天地，時來無細微。"]'),
('65cda5d2-1feb-4855-a8a1-66301ba1a4cb','寄方叔黄草道服','姜特立','宋','宋诗','song-poetry','','[]','非蕉非苧復非絺，不是山人木葉衣。',32,'全唐诗/poet.song.126000.json','["非蕉非苧復非絺，不是山人木葉衣。", "寄與詩翁莫嫌陋，看山長袖白雲歸。"]'),
('49ab3c25-566a-4c8a-9f4c-39ffbef02de8','北檻','姜特立','宋','宋诗','song-poetry','','[]','北檻近中堂，緣階物自芳。',48,'全唐诗/poet.song.126000.json','["北檻近中堂，緣階物自芳。", "晨清花拱露，地僻蘚侵廊。", "坐久時開卷，吟餘或炷香。", "終朝無客至，一枕到羲皇。"]'),
('4d9f3eed-38da-470a-8b3a-03a8e53da7fe','負暄','姜特立','宋','宋诗','song-poetry','','[]','不是羲和德澤流，寒鄉何處覓溫柔。',64,'全唐诗/poet.song.126000.json','["不是羲和德澤流，寒鄉何處覓溫柔。", "絕憐天上黄綿襖，大勝人間紫綺裘。", "旋挾胡麻隨景轉，更携書卷與閒謀。", "天和妙處誰能會，欲獻君王却自羞。"]'),
('436b2f8a-25e0-4a56-b18d-587c872ec201','小孫納婦','姜特立','宋','宋诗','song-poetry','','[]','慶事集朋親，孫枝喜氣新。',48,'全唐诗/poet.song.126000.json','["慶事集朋親，孫枝喜氣新。", "歌雲停碧落，舞雪眩青春。", "暖日花君子，清樽酒聖人。", "一春行樂地，不負牡丹辰。"]'),
('852d20a7-906b-46cb-b6a8-e62c4d5a151f','同方叔自郡城歸故園','姜特立','宋','宋诗','song-poetry','','[]','吏隠豈無名，東南一客星。',48,'全唐诗/poet.song.126000.json','["吏隠豈無名，東南一客星。", "松關今有主，岫幌不須扃。", "無夢妨清睡，唯閒伴獨醒。", "着鞭吾已晚，先媿一鴻冥。"]'),
('188a1fa6-c237-41ab-8b92-6404335eef81','癸卯冬解官三山歸雙溪自南而北路傍梅花經月不絕久欲作數語未就乙巳仲春書於鳳山僧舍','姜特立','宋','宋诗','song-poetry','','[]','路出南州向北來，吳山梅冷粵山開。',32,'全唐诗/poet.song.126000.json','["路出南州向北來，吳山梅冷粵山開。", "陽和次第隨程到，一月吹香管客回。"]'),
('e68fb6b5-2e1b-4fa6-a8dc-72c6f9062273','煩劉公達甃園中小池以詩謝之','姜特立','宋','宋诗','song-poetry','','[]','感君巧思葺芳塘，石甃無痕細著行。',32,'全唐诗/poet.song.126000.json','["感君巧思葺芳塘，石甃無痕細著行。", "更擬中間添小嶼，藕花深處著鴛鴦。"]'),
('a5f254bb-978a-47dc-a422-5726b0345ce7','辛亥上塚','姜特立','宋','宋诗','song-poetry','','[]','寒閨守節少年時，志凜冰霜不可移。',64,'全唐诗/poet.song.126000.json','["寒閨守節少年時，志凜冰霜不可移。", "追遠積成千古恨，報恩寬作十年期。", "此生不愧先君死，後世應傳寡婦碑。", "蘭若棲神安穩在，遺言今日九原知。"]'),
('6fb8f807-298f-42b2-a2a7-20c230d0b5ea','詩送譙知閤','姜特立','宋','宋诗','song-poetry','','[]','一去丹墀六換春，追尋舊事晃如新。',64,'全唐诗/poet.song.126000.json','["一去丹墀六換春，追尋舊事晃如新。", "屢煩携酒來青邸，相伴同班上紫宸。", "自分此生成死別，豈知今日更情親。", "飛騰已向風雲會，得意應須記故人。"]'),
('2f463b2b-a484-406b-9931-f603a2a691c8','余卜居偶得山水之勝喜而賦之','姜特立','宋','宋诗','song-poetry','','[]','寒士把茆聊盖頭，豈假山水尋清幽。',64,'全唐诗/poet.song.126000.json','["寒士把茆聊盖頭，豈假山水尋清幽。", "偶然駐足得勝地，造物所賦非人謀。", "有山無水清暉減，有水無山爽致卑。", "流水青山屋上下，此妙唯許坡公知。"]'),
('315c3768-15a4-4dd5-ae94-6f8a2d33bb0a','歸山間舟中寄黄正言','姜特立','宋','宋诗','song-poetry','','[]','黑風吹雨亂雲奔，一舸浮家過別邨。',64,'全唐诗/poet.song.126000.json','["黑風吹雨亂雲奔，一舸浮家過別邨。", "便有新凉生竹樹，更添清興集槃樽。", "打篷點點催詩思，著面蕭蕭冷醉魂。", "來日小溪山水活，一波盡是使君恩。"]'),
('b6d1f5a2-4674-4cda-9e5a-2ea144daf7e9','黄正言爲邑宰累罷郡送行','姜特立','宋','宋诗','song-poetry','','[]','人生皆有別，此別良不同。',144,'全唐诗/poet.song.126000.json','["人生皆有別，此別良不同。", "不作兒女戀，慘然見顔容。", "郭奕追叔子，后山逐蘇公。", "二賢間世士，二客有古風。", "不畏簡書誚，越境遠相從。", "上下數百載，凜然兩相望。", "我亦何爲者，偶在寮寀中。", "荷公以禮遇，詎敢忘敬恭。", "公才自超卓，落落澗底松。", "我老無所用，颯然一衰蓬。", "相送三十里，已復媿前蹤。", "願言養宏博，吾道終當通。"]'),
('bd4b2f55-6236-4646-b511-c4b14dfae68d','贈染髭宋道人','姜特立','宋','宋诗','song-poetry','','[]','道人染髭鬚，返老作年少。',36,'全唐诗/poet.song.126000.json','["道人染髭鬚，返老作年少。", "雖得陸公憐，却被呂公笑。", "道人爾休癡，百年終漏逗。"]'),
('c4a0e4a6-8526-419d-a9c5-ba8026b1982b','司馬倅解組送行','姜特立','宋','宋诗','song-poetry','','[]','雙溪梅水飛洪瀾，風掣五兩爭檣竿。',96,'全唐诗/poet.song.126000.json','["雙溪梅水飛洪瀾，風掣五兩爭檣竿。", "有美人兮彼何官，東陽別駕司馬孫。", "兩攝郡紱私不干，二年解組知歲寒。", "五規三戒投天關，經筵賜讀帝意懽。", "此行定合陪清班，發揚祖德仍追攀。", "勸君一杯勿留殘，轉首咫尺過前灘。"]'),
('de23691a-781d-443c-b34e-0eceb171a14a','王俊卿所居甚隘而看山亭依浮圖之址卓然孤起誠偉觀也','姜特立','宋','宋诗','song-poetry','','[]','吾憐廛市人，偪仄烟火隘。',96,'全唐诗/poet.song.126000.json','["吾憐廛市人，偪仄烟火隘。", "六月圍炎蒸，引吭思大噫。", "誰知蜂螘聚，却躡鯨鼇背。", "近山羅前簷，遠岫落天外。", "浮圖卓孤標，如大舶航海。", "蓬萊與方丈，便覺咫尺在。", "酒酣揮八極，醉眼聊一快。", "更須約安期，萬里弄澎湃。"]'),
('a755e55b-e8be-4937-83b4-b9928ee50e0c','赤松三詠 赤松山','姜特立','宋','宋诗','song-poetry','','[]','仙山名字幾千秋，勇退曾聞漢故侯。',32,'全唐诗/poet.song.126000.json','["仙山名字幾千秋，勇退曾聞漢故侯。", "自笑功名無尺寸，歸來也作赤松游。"]'),
('e0623b17-2661-4684-bbfe-48b0dccd5951','赤松三詠 小桃源','姜特立','宋','宋诗','song-poetry','','[]','四山古木老烟雲，流水桃花幾換春。',32,'全唐诗/poet.song.126000.json','["四山古木老烟雲，流水桃花幾換春。", "舉世但誇羊化石，那知不有武陵人。"]'),
('cbd8a21a-27a3-4b9a-9408-8069c66ab7d2','赤松三詠 二仙廟','姜特立','宋','宋诗','song-poetry','','[]','自從兄弟得神仙，一去空山竟杳然。',32,'全唐诗/poet.song.126000.json','["自從兄弟得神仙，一去空山竟杳然。", "唯有華陰舒道士，好詩長與此山傳。"]'),
('a52ce30c-6205-4805-ae65-a6fc41b2f5b9','賦婺州之錄參廳明遠樓爲李中甫董奇卿作也','姜特立','宋','宋诗','song-poetry','','[]','脚蹴南樓咫尺間，手摩八詠境全慳。',64,'全唐诗/poet.song.126000.json','["脚蹴南樓咫尺間，手摩八詠境全慳。", "東西合抱兩溪水，遠近平分千里山。", "但見孤鴻渺天際，更無野馬隘人寰。", "一時從事先名實，豈有能誣雀鼠姦。"]'),
('4ef0726b-8e7d-44da-838d-0cfe31cfbee9','偶題','姜特立','宋','宋诗','song-poetry','','[]','霜降水自落，春濃花欲迷。',24,'全唐诗/poet.song.126000.json','["霜降水自落，春濃花欲迷。", "道心因老進，狂態逐時低。"]'),
('b0ae9835-3e48-4f61-a141-f5cccfa0cbd8','永日','姜特立','宋','宋诗','song-poetry','','[]','永日靜無聊，空庭散欝陶。',24,'全唐诗/poet.song.126000.json','["永日靜無聊，空庭散欝陶。", "憩禽猜落果，乳雀趁飛毛。"]'),
('196f5603-0891-466d-86df-877002e121d3','賞花醉吟','姜特立','宋','宋诗','song-poetry','','[]','七十衰翁雙鬢槁，每遇花時拚醉倒。',64,'全唐诗/poet.song.126000.json','["七十衰翁雙鬢槁，每遇花時拚醉倒。", "今年只是去年花，故吾何似今吾老。", "空中日月籠中鳥，萬古賢愚塵一窖。", "尋思世事總浮雲，斷送一生唯有酒。"]'),
('a585b78f-921a-455d-b3c8-55cb7c02c260','和黄正言勸農','姜特立','宋','宋诗','song-poetry','','[]','雙溪溪上綠初勻，曉日曈矓霽景新。',64,'全唐诗/poet.song.126000.json','["雙溪溪上綠初勻，曉日曈矓霽景新。", "五馬先聲才出郭，九農和氣已生春。", "教條頒布人心悅，父老醺酣德意親。", "從此惰民俱力穡，會看優最上嚴宸。"]'),
('33287adc-c62a-4db3-ac66-2a7cc8cbebe0','失駿子','姜特立','宋','宋诗','song-poetry','','[]','舐犢情何限，亡羊意易迷。',48,'全唐诗/poet.song.126000.json','["舐犢情何限，亡羊意易迷。", "聊爲暮景玩，遽與小年齊。", "漲乳空宵哺，深閨失曉啼。", "已知真幻泡，感至一悲悽。"]'),
('1e7e2d45-315c-44fa-b7dc-f4c2b287872a','乙卯春自郡歸賞牡丹適有故竟回唯魏紫略放二頭  其一','姜特立','宋','宋诗','song-poetry','','[]','歸早開遲兩寂寥，經年不見董妖嬈。',32,'全唐诗/poet.song.126000.json','["歸早開遲兩寂寥，經年不見董妖嬈。", "芳心未展緣何事，半是閒愁半是嬌。"]'),
('c009b959-eb98-48de-bb51-c90f1795738c','乙卯春自郡歸賞牡丹適有故竟回唯魏紫略放二頭  其二','姜特立','宋','宋诗','song-poetry','','[]','夢想看花歸意濃，歸來底事別花忙。',32,'全唐诗/poet.song.126000.json','["夢想看花歸意濃，歸來底事別花忙。", "魏家姊妹知人意，先試春風半面粧。"]'),
('a0c02ffa-752b-427b-86d7-3f85c324e12c','和司馬倅喜雪','姜特立','宋','宋诗','song-poetry','','[]','寒意沉沉雲氣深，老來病骨冷難禁。',64,'全唐诗/poet.song.126000.json','["寒意沉沉雲氣深，老來病骨冷難禁。", "巢禽一出不知下，籠鶴乍飛無處尋。", "便欲騎馿洛陽市，不妨放棹越山陰。", "天公已作豐年瑞，更仗風威掃滯淫。"]'),
('9b0b3ebb-7ef7-4982-a69d-557b5c9c4391','歲在紹熙甲寅浙東西大旱旁連江淮至秋暴雨水發天目漂民廬浸禾稼而蘇常大歉小人趨利爭運衢婺穀粟順流而下日夜不止又去冬歲暮多雨連綿至春半未有晴意人情憂悶聊書數語以備采謠者至辭之工拙固所不計也乙卯仲春作','姜特立','宋','宋诗','song-poetry','','[]','去年數州旱，秋雨漂民廬。',192,'全唐诗/poet.song.126000.json','["去年數州旱，秋雨漂民廬。", "今年復春霖，赤子憂爲魚。", "不見日月旋，但見霰雪俱。", "處者絕營爲，出者困泥塗。", "近山不可樵，平地不得鉏。", "有壤莫糞田，有火莫燒畬。", "花木淡慘慘，麥苗冷踈踈。", "張王階下苔，寒酸井邊蔬。", "上天胡不仁，蒼生一何辜。", "傳聞常潤間，流殍滿路衢。", "鄞江禍尤酷，越山復何如。", "米鄉已無積，山郡豈有餘。", "小人急眼前，負販日夜趨。", "只知利一己，豈暇卹里閭。", "屈指至秋成，未可保無虞。", "堯湯備先具，庶冀收桑榆。"]'),
('f2403316-9786-4266-a475-5418dae3ad10','喜楊方叔見訪','姜特立','宋','宋诗','song-poetry','','[]','憶別西風首重回，今朝相見笑顔開。',64,'全唐诗/poet.song.126000.json','["憶別西風首重回，今朝相見笑顔開。", "梅花臘底思君語，桃葉春前望客來。", "足健尚堪凌𠿕𧇠，詩工未許繼堆豗。", "山園近日新成趣，正要相携把酒杯。"]'),
('1d7648a3-9a5d-4926-956b-c0d755b9c00d','讀漢史','姜特立','宋','宋诗','song-poetry','','[]','萬石躬行不讀書，公孫張禹號名儒。',32,'全唐诗/poet.song.126000.json','["萬石躬行不讀書，公孫張禹號名儒。", "詩書何罪工發冢，自是諸生愛頷珠。"]'),
('a808fd71-9ec0-4285-b33b-7cf1d16a55fd','乙卯元宵多雨  其一','姜特立','宋','宋诗','song-poetry','','[]','臘前雨勢已翻盆，臘後淋漓到上元。',64,'全唐诗/poet.song.126000.json','["臘前雨勢已翻盆，臘後淋漓到上元。", "燈火不張蟾彩暗，笙簫有禁霤聲喧。", "麥田聞道水盈尺，里巷想應泥沒門。", "悶坐孤吟無好况，三杯冷落對黄昏。"]'),
('77b37ba3-054f-4445-8c11-d2cbbc53e04b','乙卯元宵多雨  其二','姜特立','宋','宋诗','song-poetry','','[]','連年旱氣民愁食，及至春來又雨霖。',64,'全唐诗/poet.song.126000.json','["連年旱氣民愁食，及至春來又雨霖。", "濕麥卧泥難辨草，寒蔬入市貴如金。", "燈輝不到愁人眼，節物空驚老者心。", "且喜今朝日光出，更須風力掃重陰。"]'),
('9e27e883-032a-4b20-a8db-7726ac44339b','種桃','姜特立','宋','宋诗','song-poetry','','[]','種桃三百樹，隨處有開花。',24,'全唐诗/poet.song.126000.json','["種桃三百樹，隨處有開花。", "來年三二月，便是武陵家。"]'),
('a3a42099-48bb-4589-b1a4-9a1abcee6d9b','聞衍孫恪得舉','姜特立','宋','宋诗','song-poetry','','[]','慶事聯翩走四鄰，吾家門戶一番新。',32,'全唐诗/poet.song.126000.json','["慶事聯翩走四鄰，吾家門戶一番新。", "明年雙上青雲去，爲汝山園作主人。"]'),
('4b469d97-1f7a-42af-bf05-06ba83dcc81b','陳德承致政一子中舍選次子中漕臺與余二息同牓賀之','姜特立','宋','宋诗','song-poetry','','[]','皇朝網英材，三歲設科目。',48,'全唐诗/poet.song.126000.json','["皇朝網英材，三歲設科目。", "四海一飛龍，兩家雙中鵠。", "得非詩禮效，且喜箕裘續。", "二老亦牽連，明年書小錄。"]'),
('78eb8225-554b-4703-90d2-ff835cb7516d','陳德承致政病後得詩且以見賀','姜特立','宋','宋诗','song-poetry','','[]','上恩鼎至愧叨逾，退省何嘗有碩膚。',64,'全唐诗/poet.song.126000.json','["上恩鼎至愧叨逾，退省何嘗有碩膚。", "甘作一麾山吏部，不爲三敗管夷吾。", "相思夢想江湖隔，熟誦篇章錦繡鋪。", "無妄疾來終易愈，豈容醫砭值庸夫。"]'),
('922835f4-76af-4d75-bb78-6d35386bc921','烘被詩','姜特立','宋','宋诗','song-poetry','','[]','烘被龜藏六，焞焞梨棗春。',48,'全唐诗/poet.song.126000.json','["烘被龜藏六，焞焞梨棗春。", "不唯勻踵息，且以煖腰身。", "捫蝨閒尋句，聽雞怕及晨。", "是中有真味，不羨北窗人。"]'),
('f68a8ef1-0df4-4efa-af3b-a04b329ee2b0','夏月山中聞鶑','姜特立','宋','宋诗','song-poetry','','[]','深山五六月，猶自有鶑簧。',24,'全唐诗/poet.song.126000.json','["深山五六月，猶自有鶑簧。", "只滿幽人聽，何如入建章。"]'),
('97c43265-005a-4e64-9a78-a2aeeb81193c','鶑答','姜特立','宋','宋诗','song-poetry','','[]','自是山禽侶，徒因語得新。',24,'全唐诗/poet.song.126000.json','["自是山禽侶，徒因語得新。", "不堪供貴玩，却作李山人。"]'),
('f03ee726-8d86-4071-a28c-60020b207ae2','菜羹二首  其一','姜特立','宋','宋诗','song-poetry','','[]','擬續冰壺傳，嘗賡玉糝詩。',24,'全唐诗/poet.song.126000.json','["擬續冰壺傳，嘗賡玉糝詩。", "蒸豚貴公子，却莫遣渠知。"]'),
('24404d44-53c0-49a3-adfc-8b5cab8b54b1','菜羹二首  其二','姜特立','宋','宋诗','song-poetry','','[]','一自入金門，屢蒙分玉食。',24,'全唐诗/poet.song.126000.json','["一自入金門，屢蒙分玉食。", "今朝苜蓿盤，猶疑照初日。"]'),
('a305cf35-36bf-496c-8b6c-db0492dbb55c','因見市人以瓦缶蒔花屋上有感','姜特立','宋','宋诗','song-poetry','','[]','城中寸土如寸金，屋上蒔花亦良苦。',112,'全唐诗/poet.song.126000.json','["城中寸土如寸金，屋上蒔花亦良苦。", "因思離宮與別館，南至九嵕北鄠杜。", "東西延袤八百里，橋梁褭空七百柱。", "傷哉好大荒主心，豈識世間蓬篳趣。", "一邱一壑吾輩事，隨分園池何用許。", "我今度地山一隅，栽柳栽花已無數。", "大雖不足小有餘，便可終身爲老圃。"]'),
('1b2274ff-fed4-4872-98b4-6e71feb1a5f8','秋暑','姜特立','宋','宋诗','song-poetry','','[]','吾性仍忍寒，不受秋暑悶。',84,'全唐诗/poet.song.126000.json','["吾性仍忍寒，不受秋暑悶。", "既抱相如渴，復喘平叔汗。", "疥疾亦相乘，爬搔擾軀幹。", "平生懶揮箑，况復蚊蚋亂。", "忽聞隠雷聲，引頸若鵝鸛。", "雨意竟蕭條，依然坐深爨。", "安得天公仁，霜令從此換。"]'),
('26e5d374-06a5-450c-a8b9-99863e6601c7','中秋追和李方叔詠舞者','姜特立','宋','宋诗','song-poetry','','[]','樂聲催遍上華裀，回雪光中不見塵。',32,'全唐诗/poet.song.126000.json','["樂聲催遍上華裀，回雪光中不見塵。", "今日山間易惆悵，當筵踏月更何人。"]'),
('c543e90e-6e53-476a-8553-b482b69165ae','葉仲脩令其子携所作求詩','姜特立','宋','宋诗','song-poetry','','[]','雅道去已久，挽回良獨難。',48,'全唐诗/poet.song.126000.json','["雅道去已久，挽回良獨難。", "須求正知見，莫學小波瀾。", "父子專詩律，風騷逼將壇。", "如今寄佳句，那復阿蒙看。"]'),
('95322a07-f9e9-4a1b-97e1-a1290fe0533c','秋霽','姜特立','宋','宋诗','song-poetry','','[]','清秋初過雨，濕葉閃晴暉。',24,'全唐诗/poet.song.126000.json','["清秋初過雨，濕葉閃晴暉。", "數冊文書靜，一庭人事稀。"]'),
('e7d5ab4b-03e3-4095-ad0d-8dc25618f5fe','送枕屏竹爐與劉公達致政道室','姜特立','宋','宋诗','song-poetry','','[]','不畫椒房百子圖，銷金帳下擁流蘇。',32,'全唐诗/poet.song.126000.json','["不畫椒房百子圖，銷金帳下擁流蘇。", "聊將鷗鷺滄洲趣，伴送江西古竹爐。"]'),
('916933f1-280f-4290-a8b6-54e8a9aacc58','出門','姜特立','宋','宋诗','song-poetry','','[]','出門誰與游，顧影惻我情。',24,'全唐诗/poet.song.126000.json','["出門誰與游，顧影惻我情。", "頼有木居士，作伴山中行。"]'),
('ed909ce0-8a08-4de6-bbf5-73787ee7b147','吾家','姜特立','宋','宋诗','song-poetry','','[]','吾家何處住，一嶂獨成圍。',24,'全唐诗/poet.song.126000.json','["吾家何處住，一嶂獨成圍。", "莫遣通樵斧，應嫌減翠微。"]'),
('5446cf0c-b1ed-436d-b67c-0e540191005a','畏途','姜特立','宋','宋诗','song-poetry','','[]','畏途謝排斥，造物遂初志。',108,'全唐诗/poet.song.126000.json','["畏途謝排斥，造物遂初志。", "彼雖快其私，我獨佩嘉惠。", "愛憎有回牙，恩怨或倒置。", "得馬豈君福，鑿渠真我利。", "向使老班行，茲事恐遂廢。", "三逕幸足樂，一瓢聊自寄。", "興來或歌呼，客至任醺醉。", "以此終百年，何用一品貴。", "猶勝白首歸，流光忽西墜。"]'),
('ab813b85-7746-4c9c-b76f-6ea244d5adc0','趨郡回','姜特立','宋','宋诗','song-poetry','','[]','老去猶趨府，往來添客愁。',24,'全唐诗/poet.song.126000.json','["老去猶趨府，往來添客愁。", "丹楓漁舍晚，花麥野田秋。"]'),
('22d81ce7-c920-4e03-a9bc-6b9be8486209','新居覓竹栽  其一','姜特立','宋','宋诗','song-poetry','','[]','闢疇事廬井，物色費經營。',48,'全唐诗/poet.song.126000.json','["闢疇事廬井，物色費經營。", "正擬一廛足，便懷三徑情。", "吾居恐全俗，君圃有餘清。", "急欲就佳趣，哦詩乞翠莖。"]'),
('110181e4-fd70-4b22-96c7-fca6d222107d','新居覓竹栽  其二','姜特立','宋','宋诗','song-poetry','','[]','覓橙曾有句，乞竹可無詩。',48,'全唐诗/poet.song.126000.json','["覓橙曾有句，乞竹可無詩。", "好輟東南幹，同爲風月期。", "根豐宜地力，萌達趁春時。", "他日如相過，清陰滿酒巵。"]'),
('db995984-bb06-45c4-b92a-dad3cbd8a02a','子陵祠堂後兩崖對起可高百丈或者指爲釣臺','姜特立','宋','宋诗','song-poetry','','[]','壁立雙臺百丈餘，如何竿綫擲空虛。',32,'全唐诗/poet.song.126000.json','["壁立雙臺百丈餘，如何竿綫擲空虛。", "時人不會先生意，只釣清名不釣魚。"]'),
('dc7c3727-5e5f-44be-95a2-d51caaedc9b2','閒賦','姜特立','宋','宋诗','song-poetry','','[]','樓臺百萬裝成，花木四時羅列。',28,'全唐诗/poet.song.126000.json','["樓臺百萬裝成，花木四時羅列。", "從渠眼底江山，欠我詩中風月。"]'),
('c9ca5287-86f4-4dc5-9246-77714144ba63','側金盞','姜特立','宋','宋诗','song-poetry','','[]','淺淺嬌黄向日開，枝頭斜掛幾金杯。',32,'全唐诗/poet.song.126000.json','["淺淺嬌黄向日開，枝頭斜掛幾金杯。", "細詳名字并花意，不醉花間不得回。"]'),
('d2a74dde-cdad-4e67-b1dc-1d57c5754632','小橋','姜特立','宋','宋诗','song-poetry','','[]','小橋橫野澗，物色自孤清。',24,'全唐诗/poet.song.126000.json','["小橋橫野澗，物色自孤清。", "終日相晤語，松聲與水聲。"]'),
('2672c8f0-9a14-4212-9c71-91766decb2fc','庭草  其一','姜特立','宋','宋诗','song-poetry','','[]','一簇牆陰綠正繁，不依朱戶傍雕欄。',32,'全唐诗/poet.song.126000.json','["一簇牆陰綠正繁，不依朱戶傍雕欄。", "竹光苔色深相映，只許閒人靜處看。"]'),
('83d1cf20-05cc-423a-a505-03cbf3c750f8','庭草  其二','姜特立','宋','宋诗','song-poetry','','[]','幽幽庭下草，悟悅有禪味。',24,'全唐诗/poet.song.126000.json','["幽幽庭下草，悟悅有禪味。", "君看紅紫場，紛紜亂人意。"]'),
('e92b9bdd-49c0-49e9-ad46-032560eb4e33','繭庵 初營','姜特立','宋','宋诗','song-poetry','','[]','萬物有終始，吾生如幻泡。',48,'全唐诗/poet.song.126000.json','["萬物有終始，吾生如幻泡。", "辛勤蠶作繭，來往燕成巢。", "不作虆梩掩，寧須馬革包。", "劉伶行带鍤，未免達人嘲。"]'),
('bbd2d528-2a77-4cc6-a559-f066c25a04e7','繭庵 落成','姜特立','宋','宋诗','song-poetry','','[]','繭庵吾自名，所喜以吾息。',144,'全唐诗/poet.song.126000.json','["繭庵吾自名，所喜以吾息。", "一絲出巧心，口眼費經畫。", "無畏亦無累，豐儉隨人力。", "時時携妻子，杯酒縱酣適。", "家人獻歌舞，賓友雜嘲劇。", "此意少人解，此庇無終極。", "曹瞞西陵前，作伎竟何益。", "劉伶墳上土，誰與酒澆滴。", "高堂豈不好，要自非吾宅。", "王侯與氓隸，萬古一枯腊。", "自營自落之，詎敢當達識。", "有酒更頻來，寬作十年客。"]'),
('86003485-a7cb-4a62-9d2d-06348f9164dd','六言','姜特立','宋','宋诗','song-poetry','','[]','康樂尋山伐木，子猷愛竹叩門。',28,'全唐诗/poet.song.126000.json','["康樂尋山伐木，子猷愛竹叩門。", "我已烟霞痼疾，每逢佳處開樽。"]'),
('3b393e5b-26e9-405e-aecf-a12845c0a71d','禍福','姜特立','宋','宋诗','song-poetry','','[]','君子多短拙，動或福隨之。',48,'全唐诗/poet.song.126000.json','["君子多短拙，動或福隨之。", "小人最狡獪，往往觸禍機。", "巧者極人力，拙者無所爲。", "巧拙不必問，天道自平夷。"]'),
('0c7bcc58-28d6-4587-86be-7da1931f85ef','秋旱驟雨','姜特立','宋','宋诗','song-poetry','','[]','滂沱一雨洗清秋，千里郊原旱氣收。',32,'全唐诗/poet.song.126000.json','["滂沱一雨洗清秋，千里郊原旱氣收。", "急遣奚奴洗觥醆，醒心亭上看溪流。"]'),
('5a7c435a-2c47-40c4-ad81-ce153a4c2dd0','買烏薪戲題','姜特立','宋','宋诗','song-poetry','','[]','雨雪冬春無了時，烏薪斷續惱衰羸。',32,'全唐诗/poet.song.126000.json','["雨雪冬春無了時，烏薪斷續惱衰羸。", "偶然買得婆歡喜，且免山翁曉皺眉。"]'),
('e81de83f-821a-4b1e-b10a-6cfb95106075','晨起出門','姜特立','宋','宋诗','song-poetry','','[]','水繞芳堤雲繞山，數椽茅屋住中間。',32,'全唐诗/poet.song.126000.json','["水繞芳堤雲繞山，數椽茅屋住中間。", "神仙更自足官府，世上誰如此老閒。"]'),
('f6801b3d-70c6-4b57-ae0a-74f35c0be55a','山堂鞏先生輓詩三首  其一','姜特立','宋','宋诗','song-poetry','','[]','源流簡公出，名字魯山宗。',48,'全唐诗/poet.song.126000.json','["源流簡公出，名字魯山宗。", "避地江之左，驚人易以東。", "機雲千載裏，歆向一門中。", "敬止山堂老，才名是至公。"]'),
('2ad9bc8d-c97f-4070-9f48-a116e599ddd5','山堂鞏先生輓詩三首  其二','姜特立','宋','宋诗','song-poetry','','[]','風采儒林虎，波瀾學海鯨。',48,'全唐诗/poet.song.126000.json','["風采儒林虎，波瀾學海鯨。", "公家五進士，此地半諸生。", "勾漏丹俄就，中牟政亦成。", "如何賈太傅，位不至公卿。"]'),
('5fb268a7-174b-43cd-be08-fe99214d673b','山堂鞏先生輓詩三首  其三','姜特立','宋','宋诗','song-poetry','','[]','綰章南北異，轉首死生分。',48,'全唐诗/poet.song.126000.json','["綰章南北異，轉首死生分。", "手澤空遺墨，書籖冷舊芸。", "行須潘岳誄，碑已蔡邕文。", "身後無儋石，玄成似子雲。"]'),
('bbf7cadd-d23a-47f5-9979-15123b7bd79a','和元亨出示山扉詩','姜特立','宋','宋诗','song-poetry','','[]','手自葺柴荆，山扉亦自扃。',48,'全唐诗/poet.song.126000.json','["手自葺柴荆，山扉亦自扃。", "莫辭蓬篳陋，要護草堂靈。", "忙爲幽人啟，閒無俗士經。", "不妨老赤脚，應戶代奴星。"]'),
('1f2e8670-b45d-4e4a-a155-ee168b8c0172','寄方叔','姜特立','宋','宋诗','song-poetry','','[]','落葉滿滄灣，墜露濕踈柳。',48,'全唐诗/poet.song.126000.json','["落葉滿滄灣，墜露濕踈柳。", "幽人曉無事，杖策經林阜。", "忽焉若有省，懷此山中友。", "便欲借風翰，翩翩插雙肘。"]'),
('20a3c696-6f3c-4d9a-8787-ab9501d0aeb0','古風送行陳省元','姜特立','宋','宋诗','song-poetry','','[]','梅山老人頭雪白，摸索曹劉還認得。',160,'全唐诗/poet.song.126000.json','["梅山老人頭雪白，摸索曹劉還認得。", "平生鹿鹿視餘子，誰是詩中真巨擘。", "踵門忽得天下士，慕我虛聲遠相覓。", "袖中磊磈出奇語，和璧隨珠暗相射。", "對之坐久神氣定，言下分明箭鋒直。", "傍觀如堵相駭愕，頗復見我有此客。", "雄篇累日費酬答，但怪筆端飛霹靂。", "君才自是千里駒，鞭影不摇何待策。", "古人妙處應自知，悟解多端難指畫。", "請君更去勘諸方，莫道梅山得消息。"]'),
('1b17eb4f-0797-4090-8f5b-b47d6714d2b6','和潘倅新溪七首  其一','姜特立','宋','宋诗','song-poetry','','[]','山色湖光相接連，千章古木老雲烟。',32,'全唐诗/poet.song.126000.json','["山色湖光相接連，千章古木老雲烟。", "晚來曲港回舟處，如在孤山柳嶼邊。"]'),
('26ed5403-a533-4500-b29c-d88407fc2cda','和潘倅新溪七首  其二','姜特立','宋','宋诗','song-poetry','','[]','平湖瀲灧带垂楊，綠暗長堤五月凉。',32,'全唐诗/poet.song.126000.json','["平湖瀲灧带垂楊，綠暗長堤五月凉。", "綵女移舟蓮浦去，棹歌聲裏水風香。"]'),
('05a94536-fe72-406a-92da-c489a32c9a44','和潘倅新溪七首  其三','姜特立','宋','宋诗','song-poetry','','[]','濃淡燕脂千樹開，崇光香霧襲人來。',32,'全唐诗/poet.song.126000.json','["濃淡燕脂千樹開，崇光香霧襲人來。", "如今不共梅花笑，步繞行吟日幾回。"]'),
('f9e29685-d144-4f6a-b4e7-1935b9254851','和潘倅新溪七首  其四','姜特立','宋','宋诗','song-poetry','','[]','釣月亭邊三兩家，月明無處認蘆花。',32,'全唐诗/poet.song.126000.json','["釣月亭邊三兩家，月明無處認蘆花。", "忽聞鵯鵊相驚起，知有溪禽在淺沙。"]'),
('a507d03c-351f-409d-96da-91b5c8c98218','和潘倅新溪七首  其五','姜特立','宋','宋诗','song-poetry','','[]','溪頭風月四時新，機盡還欣烏鳥親。',32,'全唐诗/poet.song.126000.json','["溪頭風月四時新，機盡還欣烏鳥親。", "沮溺相逢如借問，報言老子自知津。"]'),
('9152b27b-ff62-4778-be46-e9a4ed72e0f2','和潘倅新溪七首  其六','姜特立','宋','宋诗','song-poetry','','[]','如君方此富春秋，未可追尋三逕遊。',32,'全唐诗/poet.song.126000.json','["如君方此富春秋，未可追尋三逕遊。", "且放子真歸谷口，不應馬援困壺頭。"]'),
('ca2e86e4-100d-40ec-975c-1da0b381b87f','和潘倅新溪七首  其七','姜特立','宋','宋诗','song-poetry','','[]','我來久矣了窮通，出處誰能與衆同。',32,'全唐诗/poet.song.126000.json','["我來久矣了窮通，出處誰能與衆同。", "此去便須專一壑，人生何必作三公。"]'),
('b3da78a0-3cdb-42a2-9591-3725f32ae5fc','蝦蟇','姜特立','宋','宋诗','song-poetry','','[]','周公灑灰垂典教，爲爾朋徒多取閙。',32,'全唐诗/poet.song.126000.json','["周公灑灰垂典教，爲爾朋徒多取閙。", "如今大索不相容，省口何如且泥淖。"]'),
('02a311e3-64c9-41da-abb8-c3d3e262fb3b','有感','姜特立','宋','宋诗','song-poetry','','[]','巍峩厦屋起千間，更作朝廷第一官。',32,'全唐诗/poet.song.126000.json','["巍峩厦屋起千間，更作朝廷第一官。", "幾箇得歸仍得老，可憐一世不曾閒。"]'),
('8801ba6e-212b-4f02-9340-3876b0d83806','歸老','姜特立','宋','宋诗','song-poetry','','[]','歸老得閒渾可事，最憐白傅更能詩。',32,'全唐诗/poet.song.126000.json','["歸老得閒渾可事，最憐白傅更能詩。", "舞餘歌罷賓朋去，八節灘頭醉卧時。"]'),
('e4be2340-3c8e-4c94-b32c-421930a392a1','和虞守釣臺四首  其一','姜特立','宋','宋诗','song-poetry','','[]','龍衮羊裘孰重輕，當時俱是一書生。',32,'全唐诗/poet.song.126000.json','["龍衮羊裘孰重輕，當時俱是一書生。", "相忘道術仍忘勢，超出人間萬古情。"]'),
('ccd18c85-1163-4e61-9ca3-5a629aec7583','和虞守釣臺四首  其二','姜特立','宋','宋诗','song-poetry','','[]','七里灘頭歲月增，漢家川谷幾丘陵。',32,'全唐诗/poet.song.126000.json','["七里灘頭歲月增，漢家川谷幾丘陵。", "祠堂只許玄英配，此後寥寥見未曾。"]'),
('ad2fcdcb-ea41-410b-a116-6659552b10a8','和虞守釣臺四首  其三','姜特立','宋','宋诗','song-poetry','','[]','天下清名屬至公，當時四七謾英雄。',32,'全唐诗/poet.song.126000.json','["天下清名屬至公，當時四七謾英雄。", "祠庭千古增輪奐，不見雲臺續畫工。"]'),
('b49c9e72-1743-40c8-9cb9-3cf209d22a71','和虞守釣臺四首  其四','姜特立','宋','宋诗','song-poetry','','[]','先生蟬蛻出塵埃，萬古聲名一草萊。',32,'全唐诗/poet.song.126000.json','["先生蟬蛻出塵埃，萬古聲名一草萊。", "盡道高風激貪懦，何人到此挽舟回。"]'),
('18b8e846-2deb-41b9-b6f5-b68918ecb1c6','胡彥功輓章中間家事少貶遂謝賓客絕饋餉者三十年已而復振','姜特立','宋','宋诗','song-poetry','','[]','祖風文采秀儒林，父德幽遐玉有音。',64,'全唐诗/poet.song.126000.json','["祖風文采秀儒林，父德幽遐玉有音。", "廷尉何妨謝諸客，鴟夷還復致千金。", "門前輿馬多英貴，架上圖書浩古今。", "欲識遺芳傳不朽，伯喈文字在球琳。"]'),
('e4ce81e2-faec-4b37-a3f6-fbfe72ca7eed','贈方叔','姜特立','宋','宋诗','song-poetry','','[]','世間曠士如君少，天下閒人似我稀。',32,'全唐诗/poet.song.126000.json','["世間曠士如君少，天下閒人似我稀。", "一曠一閒無一事，只應鷗鳥共忘機。"]'),
('f3aec877-69cb-4025-98cd-c2d3440f8bb1','誕日戲作亦可以瑞鷓鴣歌之','姜特立','宋','宋诗','song-poetry','','[]','梅山誕日簇觥籌，更挾娉婷共勝游。',32,'全唐诗/poet.song.126000.json','["梅山誕日簇觥籌，更挾娉婷共勝游。", "此去只求閒富貴，人生須是老風流。"]'),
('a1d6d7dc-2baf-4050-be4d-e1d822b1b5e6','拄杖','姜特立','宋','宋诗','song-poetry','','[]','脚力未須扶，時時踏莎逕。',24,'全唐诗/poet.song.126000.json','["脚力未須扶，時時踏莎逕。", "愛君如友生，伴我山行興。"]'),
('0b15d431-8dcb-4108-b528-4f205d4db9d6','門外','姜特立','宋','宋诗','song-poetry','','[]','門外青山列髻螺，園中花木錦成窠。',32,'全唐诗/poet.song.126000.json','["門外青山列髻螺，園中花木錦成窠。", "慚無功業報明主，空占閒居樂事多。"]'),
('606f0b1a-e099-4ee4-8455-981dff173d93','道中小詩呈虞察院','姜特立','宋','宋诗','song-poetry','','[]','歸路指城隅，城樓出畫圖。',48,'全唐诗/poet.song.126000.json','["歸路指城隅，城樓出畫圖。", "水光摇野艇，雲影掠平蕪。", "祇合山林住，胡爲朝市趨。", "丘丹不浪出，五字訪姑蘇。"]'),
('7334effd-95f2-474c-b549-c4d3113e33b9','糟蟹呈虞察院  其一','姜特立','宋','宋诗','song-poetry','','[]','星分井鬼占高躔，瑣細還書食饌編。',64,'全唐诗/poet.song.126000.json','["星分井鬼占高躔，瑣細還書食饌編。", "不作屈原醒到死，却同李白醉登仙。", "濡涎唧唧生泉眼，閟息陶陶樂甕天。", "口腹固知能累德，爲渠風味一軒然。"]'),
('a86a72c9-7444-452e-b31f-f28e81d3e6ac','糟蟹呈虞察院  其二','姜特立','宋','宋诗','song-poetry','','[]','禍成篝火最堪憐，蒯索寒蘆更與編。',64,'全唐诗/poet.song.126000.json','["禍成篝火最堪憐，蒯索寒蘆更與編。", "細剔膏蘇付饞子，却吟醉骨屬詩仙。", "沉冥併作南柯夢，混沌誰開太極天。", "聞道將糖尤躁擾，解蒲投甑想騷然。"]'),
('10c69bbf-25be-48c5-afa9-435d8e3d94e6','虞丈以傷物遂再賦  其一','姜特立','宋','宋诗','song-poetry','','[]','省口須知亦省緣，食經爾雅不勞編。',64,'全唐诗/poet.song.126000.json','["省口須知亦省緣，食經爾雅不勞編。", "山中且縱無腸子，海上長隨踞殻仙。", "凡物身中皆有佛，何人性裏獨無天。", "反騷正得詩人意，讀罷新章爲憮然。"]'),
('75a5b4f8-342d-4461-9127-dc3f281e4e31','虞丈以傷物遂再賦  其二','姜特立','宋','宋诗','song-poetry','','[]','古來儒墨本同源，罪福區區不足編。',64,'全唐诗/poet.song.126000.json','["古來儒墨本同源，罪福區區不足編。", "燕饗正須依孔聖，慈悲何必異金仙。", "靜思有物參元化，俯視含生共一天。", "梁武漢明俱泥佛，得言失旨豈其然。"]'),
('5d779e27-1847-4c23-8ffb-47b74a91a5ab','出郭','姜特立','宋','宋诗','song-poetry','','[]','歲暮偶出郭，斜陽带遠村。',24,'全唐诗/poet.song.126000.json','["歲暮偶出郭，斜陽带遠村。", "雪松含臘意，沙水動春痕。"]'),
('876244fb-71fb-4286-ba10-b0bed1ff056f','春曉','姜特立','宋','宋诗','song-poetry','','[]','春來貪起早，春思還繚繞。',24,'全唐诗/poet.song.126000.json','["春來貪起早，春思還繚繞。", "一語破春愁，黄鸝韵清曉。"]'),
('e829399c-babd-4fcc-9d3b-14b2fa267e4e','有感','姜特立','宋','宋诗','song-poetry','','[]','六年歸老掩柴扉，今日天涯有所思。',32,'全唐诗/poet.song.126000.json','["六年歸老掩柴扉，今日天涯有所思。", "山阻雪深無去路，凄凉只詠四愁詩。"]'),
('437abdee-c742-4ce7-98f9-0a2ae82753aa','菜羹','姜特立','宋','宋诗','song-poetry','','[]','淺下薑鹽細點油，小甘微苦嫩香浮。',32,'全唐诗/poet.song.126000.json','["淺下薑鹽細點油，小甘微苦嫩香浮。", "是中自有天酥味，說與饞兒只掉頭。"]'),
('e56f8ef9-361d-4b50-bbca-41b7038b6dc2','極目亭有懷韓常伯','姜特立','宋','宋诗','song-poetry','','[]','先生種柳已成圍，柳外孤亭但夕暉。',64,'全唐诗/poet.song.126000.json','["先生種柳已成圍，柳外孤亭但夕暉。", "如覺隠侯前日去，不知丁令幾時歸。", "雲帆夜夜沙頭落，風葉年年城上飛。", "弔古登臨仰詞伯，苦吟精思入幽微。"]'),
('41da4f20-d7e0-4280-a219-f20583d106f1','追送虞察院','姜特立','宋','宋诗','song-poetry','','[]','夜半小溪飲，酒深增別情。',48,'全唐诗/poet.song.126000.json','["夜半小溪飲，酒深增別情。", "客隨舟共遠，詩與雪俱清。", "嚴瀨雲木冷，富春烟水平。", "故人相憶處，應過鳳凰城。"]'),
('0e43c80b-af9d-4ac4-80ce-8867611f86aa','秋江柳','姜特立','宋','宋诗','song-poetry','','[]','春暖和烟重，冬寒带雪稀。',24,'全唐诗/poet.song.126000.json','["春暖和烟重，冬寒带雪稀。", "何如秋浦畔，含思獨依依。"]'),
('85810228-fbd2-4931-b00d-da688e8e6392','方叔每歲一相訪送行','姜特立','宋','宋诗','song-poetry','','[]','耐久交情歲月深，今朝何事返家林。',64,'全唐诗/poet.song.126000.json','["耐久交情歲月深，今朝何事返家林。", "北鴻西燕一年別，流水高山千古心。", "何日從公歌舊曲，無人伴我賦清吟。", "若爲雲氣從東野，應繞劉岩紫翠岑。"]'),
('0cf3ed20-3160-4d5b-b015-81653dea98d0','寄方叔','姜特立','宋','宋诗','song-poetry','','[]','懶過醒心亭，無人作伴行。',48,'全唐诗/poet.song.126000.json','["懶過醒心亭，無人作伴行。", "禽魚皆命侶，松竹亦同聲。", "只作留時意，那思別後情。", "連宵懷晤語，心惻未能平。"]'),
('ff76746f-5892-469b-8d62-bc678a958714','去燕','姜特立','宋','宋诗','song-poetry','','[]','去燕忽若失，斷蟬凄復連。',24,'全唐诗/poet.song.126000.json','["去燕忽若失，斷蟬凄復連。", "不唯觀物化，且以感流年。"]'),
('5edf183c-c33c-45d3-b990-b2650a2bf666','曳杖','姜特立','宋','宋诗','song-poetry','','[]','曳杖度林樾，晴光破衰顔。',48,'全唐诗/poet.song.126000.json','["曳杖度林樾，晴光破衰顔。", "好鳥忽相鳴，覺我身世閒。", "身世誰自覺，此妙吾獨觀。", "正以靜得之，樂哉天地寬。"]'),
('bb6f7c02-7a1b-4bbc-a22c-962bc010f7e7','寄題楊先輩霧隠','姜特立','宋','宋诗','song-poetry','','[]','猛虎樹摩痒，更爲蟲所蝕。',120,'全唐诗/poet.song.126000.json','["猛虎樹摩痒，更爲蟲所蝕。", "玄熊擲崖木，正坐勇與力。", "爾豹居其間，而復有二德。", "既不眩文采，亦知身足惜。", "衣錦貴尚褧，桐梓惡戕賊。", "含章大臣體，深居君子識。", "室以霧隠名，茲士有典則。", "韜養日以久，何患不輝赫。", "而况數鉅公，銘詩播金石。", "只恐難久藏，却爲人所即。"]'),
('80f120fe-172c-4d1f-a604-868610fdafa6','對鏡','姜特立','宋','宋诗','song-poetry','','[]','少年鑒止水，自喜顔色好。',72,'全唐诗/poet.song.126000.json','["少年鑒止水，自喜顔色好。", "如今對明鏡，但覺增老醜。", "老醜將奈何，行當就枯朽。", "古來聖與達，閲世誰長久。", "仙藥不可求，紅顔復何有。", "嵇阮真可人，沉冥一杯酒。"]'),
('75f1d48a-8d0a-493d-8bd4-0ec34067f9f5','題許尚書石刻二首  其一','姜特立','宋','宋诗','song-poetry','','[]','烏絲玉軸陀尼表，鬭草搴花錦不如。',32,'全唐诗/poet.song.126000.json','["烏絲玉軸陀尼表，鬭草搴花錦不如。", "不是向來元祐脚，唐人文字晉人書。"]'),
('4b296cff-f680-4cd8-850b-ba5e99aa437d','題許尚書石刻二首  其二','姜特立','宋','宋诗','song-poetry','','[]','先生自是吾所敬，况復曾蒙點化餘。',32,'全唐诗/poet.song.126000.json','["先生自是吾所敬，况復曾蒙點化餘。", "筆妙共推三昧手，尚書安得不中書。"]'),
('ad51930c-2db2-4d13-844d-6db02e4ef1d0','閒吟','姜特立','宋','宋诗','song-poetry','','[]','老去無心思世事，靜中有業愛閒吟。',32,'全唐诗/poet.song.126000.json','["老去無心思世事，靜中有業愛閒吟。", "有時看水看山處，舉世何人會此心。"]'),
('b37162b6-c74c-4f7a-9368-f6576d7610a7','紅蕉二首  其一','姜特立','宋','宋诗','song-poetry','','["\u592a\u6e56"]','一藂綠鳳尾含烟，徑尺紅英曉更鮮。',32,'全唐诗/poet.song.126000.json','["一藂綠鳳尾含烟，徑尺紅英曉更鮮。", "曾見畫歸丹禁裏，太湖石後粉牆前。"]'),
('3541ce3a-11de-4ffd-951b-9e0f15b4b6df','紅蕉二首  其二','姜特立','宋','宋诗','song-poetry','','[]','品格清虛壓衆芳，何年分種自炎方。',32,'全唐诗/poet.song.126000.json','["品格清虛壓衆芳，何年分種自炎方。", "直疑剪破紅羅軸，插向綠綃深處藏。"]'),
('9d0b8773-5ee9-46f8-850e-2e602c26386e','感舊','姜特立','宋','宋诗','song-poetry','','[]','忽見鶑鶑挾兩雛，因人感舊易欷歔。',32,'全唐诗/poet.song.126000.json','["忽見鶑鶑挾兩雛，因人感舊易欷歔。", "佳人例屬沙吒利，春去春來能囀無。"]'),
('a828013f-b949-4b80-9452-c299f5d7ca59','送方叔二首  其一','姜特立','宋','宋诗','song-poetry','','[]','管絃韵勝堪娛客，山水音清好賦詩。',32,'全唐诗/poet.song.126000.json','["管絃韵勝堪娛客，山水音清好賦詩。", "底事翩然欲歸去，尊前風月又相思。"]'),
('9f0b11ac-afb6-42a5-9020-9a8d904c8a6f','送方叔二首  其二','姜特立','宋','宋诗','song-poetry','','[]','梅山近日風光好，桃葉桃根總可人。',32,'全唐诗/poet.song.126000.json','["梅山近日風光好，桃葉桃根總可人。", "自喜暮年多樂事，非君誰與共花茵。"]'),
('a7805e24-b12a-4a40-8e22-3114657db106','旅懷','姜特立','宋','宋诗','song-poetry','','[]','寄迹雙溪上，秋聲動遠林。',48,'全唐诗/poet.song.126000.json','["寄迹雙溪上，秋聲動遠林。", "斷雲流影薄，過雁去痕深。", "舊館生離思，新愁闕寄音。", "到頭俱夢事，俯默一長吟。"]'),
('33e2d75a-3e40-417d-ae5c-2f5aa23273a5','送虞察院','姜特立','宋','宋诗','song-poetry','','[]','岳牧用詞人，古今誠罕有。',252,'全唐诗/poet.song.126000.json','["岳牧用詞人，古今誠罕有。", "君侯東南雋，錦心仍繡口。", "生從謝脁城，日對敬亭阜。", "梅翁丈人行，味古若玄酒。", "君能兼衆作，活法參已久。", "今茲守雙溪，詩思如河剖。", "前追東陽侯，近繼南澗叟。", "璀璨珊瑚鈎，盤屈蛟螭鈕。", "往來互酬贈，覺我殊穢醜。", "砂礫投公筐，珠璣落吾手。", "蘇李隔遥天，王劉同魏圃。", "風騷難並世，道義况有取。", "高篇許編綴，泰華儕部婁。", "不辭附冥鴻，庶以圖不朽。", "君王愛其才，復易吳門守。", "韋郎五字句，寂寞今其耦。", "森㦸尚高門，凝香猶故牖。", "想當吟哦時，妙思出齏臼。", "只恐鳳詔催，去作仙班首。", "載賡清廟頌，千古換星斗。", "得句勿相忘，時寄山中友。"]'),
('096a0b4e-45c9-47eb-98e2-4685649a1f7d','乙卯中秋月色徹曉喜而有賦呈諸親舊','姜特立','宋','宋诗','song-poetry','','[]','客來暮靄尚周遮，客坐乾坤見物華。',64,'全唐诗/poet.song.126000.json','["客來暮靄尚周遮，客坐乾坤見物華。", "萬里更無雲吐葉，一天唯有桂開花。", "肅霜青女令先布，專夜嫦娥意太誇。", "便欲從茲凌汗漫，不知何處上仙槎。"]'),
('e7876d4b-f98e-4bbc-afd4-d6d627ba709c','乙卯種牡丹','姜特立','宋','宋诗','song-poetry','','[]','課僕舁豐壤，辛勤種牡丹。',24,'全唐诗/poet.song.126000.json','["課僕舁豐壤，辛勤種牡丹。", "不知從此去，更得幾春看。"]'),
('35383c2a-e39e-4826-897d-7aa45be65e04','山圃','姜特立','宋','宋诗','song-poetry','','[]','山圃歸來花半空，尊前一別五春風。',32,'全唐诗/poet.song.126000.json','["山圃歸來花半空，尊前一別五春風。", "新松已自高三箠，舊塹還須廣十弓。"]'),
('7151c7a3-872b-4427-9ff5-12799c83aa2a','效樂天體','姜特立','宋','宋诗','song-poetry','','[]','田宅不多終是有，園池雖小勝如無。',32,'全唐诗/poet.song.126000.json','["田宅不多終是有，園池雖小勝如無。", "三平二滿人間少，此樂唯應屬老夫。"]'),
('f861b56f-d04a-469e-be0d-d7803b815324','山中','姜特立','宋','宋诗','song-poetry','','[]','山中有至樂，靜者得其意。',24,'全唐诗/poet.song.126000.json','["山中有至樂，靜者得其意。", "所以入山人，同來不同味。"]'),
('c6541787-bfae-4ebc-843f-81e4ff759001','詩輓樓少陽所生母夫人','姜特立','宋','宋诗','song-poetry','','[]','繼室侯家古有聞，熒煌還得配樞臣。',64,'全唐诗/poet.song.126000.json','["繼室侯家古有聞，熒煌還得配樞臣。", "香嚴童子先成佛，瑣骨仙人後化身。", "共喜伯仁今有母，何妨小德外無親。", "向來已悟空乘法，合作西方會上人。"]'),
('8660f5db-7610-4e80-8d20-db638a28ae3d','詩悼劉夫人','姜特立','宋','宋诗','song-poetry','','[]','淑德生從積慶門，父兄隠耀更全真。',64,'全唐诗/poet.song.126000.json','["淑德生從積慶門，父兄隠耀更全真。", "共推蠟屐亭前女，雅稱玄都觀裏人。", "鸞鏡菱花千葉冷，蟾宮桂樹一枝新。", "人生百歲今才半，會有重封賁後身。"]'),
('b54b7c56-5c09-4194-b447-886c1b2de028','閒賦','姜特立','宋','宋诗','song-poetry','','[]','人生浮脆若風烟，障簏操籌亦可憐。',32,'全唐诗/poet.song.126000.json','["人生浮脆若風烟，障簏操籌亦可憐。", "但得樽中長有酒，不須身後更留錢。"]'),
('35db055c-8cd6-4779-b689-14f13652e60d','賦謝惠醋','姜特立','宋','宋诗','song-poetry','','[]','送酒古來多曠士，乞醯今世少良鄰。',32,'全唐诗/poet.song.126000.json','["送酒古來多曠士，乞醯今世少良鄰。", "庾郎寒腹便鮭菜，助我儒酸不厭頻。"]'),
('f18f73f3-b577-4ed3-8452-8470605bb5b4','晚來','姜特立','宋','宋诗','song-poetry','','[]','晚來山氣冷，松下獨閒行。',24,'全唐诗/poet.song.126000.json','["晚來山氣冷，松下獨閒行。", "野鳥聽人語，山靈警杖聲。"]'),
('4d28cfe8-0245-4ebd-aee8-e2b6958eebcb','立春前有雪','姜特立','宋','宋诗','song-poetry','','[]','春前一寸雪，春後一犂金。',24,'全唐诗/poet.song.126000.json','["春前一寸雪，春後一犂金。", "萬里烟瘴息，九農和氣深。"]'),
('a9c2a8c6-c1a7-4b05-9d35-397d6669c980','余方悼亡適山圃牡丹芍藥盛開賦長句','姜特立','宋','宋诗','song-poetry','','[]','白巾對紅艷，哀樂自不同。',120,'全唐诗/poet.song.126000.json','["白巾對紅艷，哀樂自不同。", "緬彼古之人，拔去禮法中。", "親喪至嘔血，悲涕固無從。", "不哭即飲酒，陶然醉爲鄉。", "吾愛蒙莊子，鼓盆歌慨慷。", "吾笑潘河陽，忍淚賦悼亡。", "自古皆有死，生滅固其常。", "生也根一氣，死焉歸渺茫。", "鍾情雖我輩，達節聖所臧。", "且日飲無何，久久永相忘。"]'),
('450f6229-f274-41d6-b9d3-56ea2d9f6c8c','閒吟','姜特立','宋','宋诗','song-poetry','','[]','富貴懸諸天，禍福人所召。',48,'全唐诗/poet.song.126000.json','["富貴懸諸天，禍福人所召。", "但於平處行，福輕禍亦少。", "貪夫只競前，而不顧其後。", "忽焉一失脚，千佛不可捄。"]'),
('96ab6b1c-8fde-443d-856c-343af2e9abeb','寄方叔','姜特立','宋','宋诗','song-poetry','','[]','二老論交日，真成百歲期。',48,'全唐诗/poet.song.126000.json','["二老論交日，真成百歲期。", "同行雙野鶴，得意一山雌。", "病起憐加飯，書來渴寄詩。", "已添新蠟屐，此興報公知。"]'),
('c8fb4d73-103d-4a86-963e-76505dccd83a','思微時寄食山寺','姜特立','宋','宋诗','song-poetry','','[]','招提憶昔寄孤蹤，曉甑猶塵午未舂。',32,'全唐诗/poet.song.126000.json','["招提憶昔寄孤蹤，曉甑猶塵午未舂。", "地僻讀書無外事，家貧教子有全功。"]'),
('c824fd5a-3c47-4bbd-9ff0-9bff9d1af1a5','出處','姜特立','宋','宋诗','song-poetry','','[]','草木偃時龍入洞，鳥烏噪處虎行岡。',32,'全唐诗/poet.song.126000.json','["草木偃時龍入洞，鳥烏噪處虎行岡。", "大賢出處須驚俗，伊尹如何五就湯。"]'),
('10f31a89-c306-4f9f-b186-2942838d9b0b','賦潘叔玠皆山樓','姜特立','宋','宋诗','song-poetry','','[]','環滁皆名山，正以醉翁重。',96,'全唐诗/poet.song.126000.json','["環滁皆名山，正以醉翁重。", "翁時方在郡，朱墨猶遮擁。", "君今建斯樓，再食祠官俸。", "雅契醉翁心，而無醉翁冗。", "看山應更真，物物皆浄供。", "便尋廬霍期，莫作京洛夢。", "只恐難久閒，移文北山諷。", "願堅仁者守，用靜以觀動。"]'),
('568673b3-2c9c-4b2d-a23b-065205f4eba9','次石魚','姜特立','宋','宋诗','song-poetry','','[]','君不見隴州石魚生地下，中有鰌鯽皆同化。',152,'全唐诗/poet.song.126000.json','["君不見隴州石魚生地下，中有鰌鯽皆同化。", "又不見衡湘石魚生山中，魚身鱗鬣俱如畫。", "世間何獨此石爲魚形，石蛇石蟹皆如生。", "蝦蟇口吻酷肖似，螬蠐蠕動幾能行。", "悠悠荒怪不可考，吾意造物初無情。", "陰陽融結亦偶爾，俗智詎可窺杳冥。", "葉君得此不足惜，君自川嶽儲英靈。", "來春禹浪忽變化，頭角天上看崢嶸。", "此時回首視此石，棄置殆與砂礫并。"]'),
('d7f5c966-1bbc-4ea7-a4e8-0431b0591b76','有感','姜特立','宋','宋诗','song-poetry','','[]','少年如曉行，志意多閒佚。',60,'全唐诗/poet.song.126000.json','["少年如曉行，志意多閒佚。", "老如夜還家，行李自迫怵。", "向來輕寸陰，此去惜餘日。", "已往不可追，未來嗟莫失。", "昔人秉燭游，不爲杯中物。"]'),
('16a7bfaa-de58-4c70-9fdc-3ee2059a0423','縱目','姜特立','宋','宋诗','song-poetry','','[]','縱目郊原亂絮飛，好風嬌葉弄天機。',32,'全唐诗/poet.song.126000.json','["縱目郊原亂絮飛，好風嬌葉弄天機。", "白灘半露溪新瘦，綠樹初圓山正肥。"]'),
('9e6e9854-477a-4249-83fe-5ef160a0508b','和王粹中','姜特立','宋','宋诗','song-poetry','','[]','昔年曾踏軟紅塵，回首修門七換春。',64,'全唐诗/poet.song.126000.json','["昔年曾踏軟紅塵，回首修門七換春。", "官職不多還不欠，交情無舊亦無新。", "有花日日招嘉客，問字時時接近鄰。", "且願梅山新秫熟，許君長作醉歸人。"]'),
('6be4b61d-3a36-44f4-be04-80eec7f68007','王君玉輓章其子遷其母同穴  其一','姜特立','宋','宋诗','song-poetry','','[]','昔與先夫子，親如老弟兄。',48,'全唐诗/poet.song.126000.json','["昔與先夫子，親如老弟兄。", "君能敬父執，我亦感交情。", "放意杯中物，無心世上名。", "佳城今夜月，應伴酒旗明。"]'),
('4b5422f1-87d5-4337-b8d9-afdc9f5392cb','王君玉輓章其子遷其母同穴  其二','姜特立','宋','宋诗','song-poetry','','[]','伉儷存亡隔，孤墳一驛西。',48,'全唐诗/poet.song.126000.json','["伉儷存亡隔，孤墳一驛西。", "忽驚雙劍合，無復隻鸞棲。", "路接先塋近，雲藏塔岫低。", "歸乎了無憾，送騎滿山蹊。"]'),
('201ecaba-420a-41fe-802d-49c7eae9d6a8','鞏大監輓詩','姜特立','宋','宋诗','song-poetry','','[]','列國名卿號衆多，山堂族望最巍峩。',64,'全唐诗/poet.song.126000.json','["列國名卿號衆多，山堂族望最巍峩。", "魏宮賓客推公幹，交趾威名畏伏波。", "老去一麾供坎壈，歸來三逕足婆娑。", "從今詩酒交朋少，悵望新阡淚若何。"]'),
('0fe21071-9cc8-421d-86f6-08b0c64b10d8','悼亡','姜特立','宋','宋诗','song-poetry','','[]','安仁愁思怯春寒，捫淚題詩睫未乾。',32,'全唐诗/poet.song.126000.json','["安仁愁思怯春寒，捫淚題詩睫未乾。", "雙燕歸來如訪舊，不知吾已是孤鸞。"]'),
('356fc437-a9c6-4c0f-ae97-3f194e4d5cdd','蟬','姜特立','宋','宋诗','song-poetry','','[]','自下高升木杪間，風爲呼吸露爲餐。',32,'全唐诗/poet.song.126000.json','["自下高升木杪間，風爲呼吸露爲餐。", "雖云强聒人憎惡，也勝低頭推糞丸。"]'),
('ac1a009b-04e5-456a-ade1-7073b4cc495a','長句贈弟邦達主簿','姜特立','宋','宋诗','song-poetry','','[]','有弟辭我去，明日隔風烟。',132,'全唐诗/poet.song.126000.json','["有弟辭我去，明日隔風烟。", "茭青嶺頭雲，憶別二十年。", "上有古峯巒，下有深澗川。", "我昔去家時，過此涕淚漣。", "汝今復經行，豈不念鴒原。", "人生皆有別，此別有何言。", "我年七十四，去日箭脫弦。", "汝雖後十年，鬢髮已蒼然。", "世味只如此，恩義以爲先。", "會少別良多，杯酒且留連。", "何以壽卯君，贈之新詩篇。"]'),
('3021ed70-4394-4008-9667-2f00a6aed3e9','有客','姜特立','宋','宋诗','song-poetry','','[]','有客訪山間，愁襟一笑寬。',24,'全唐诗/poet.song.126000.json','["有客訪山間，愁襟一笑寬。", "青燈親軟語，薄酒緩清歡。"]'),
('9fd3ab2b-83ab-4876-911b-f91032e40ff6','十月','姜特立','宋','宋诗','song-poetry','','[]','十月氣候變，園林霜葉黄。',24,'全唐诗/poet.song.126000.json','["十月氣候變，園林霜葉黄。", "餘糧栖下畝，宿靄罩寒塘。"]'),
('6e9e013f-9c6e-4b2d-9a48-7917b8474dcc','和虞守感秋二首  其一','姜特立','宋','宋诗','song-poetry','','[]','莫憶鱸魚美，吳天浪正浮。',24,'全唐诗/poet.song.126000.json','["莫憶鱸魚美，吳天浪正浮。", "只應歸夢到，千頃荻花秋。"]'),
('6802fd9a-19b0-49c0-bf64-dd9ae84a1902','和虞守感秋二首  其二','姜特立','宋','宋诗','song-poetry','','[]','家音何用寄，郵置有沉浮。',24,'全唐诗/poet.song.126000.json','["家音何用寄，郵置有沉浮。", "旦夕天邊去，書來一雁秋。"]'),
('63fdba1a-1d92-4839-9c7e-c628985124a5','送方叔','姜特立','宋','宋诗','song-poetry','','[]','九日相携上翠微，安仁悼內不勝悲。',64,'全唐诗/poet.song.126000.json','["九日相携上翠微，安仁悼內不勝悲。", "琴中只弄無絃曲，歌裏聊陳鼓缶辭。", "來歲須爲湯䴵約，今朝空過菊花時。", "君家兄弟如相問，爲報頤間已素絲。"]'),
('ab4bb4fa-4915-4657-8994-9b41cfd166b5','亡婦小祥將至','姜特立','宋','宋诗','song-poetry','','[]','老來遽有閨中戚，歲月飛騰奈爾何。',64,'全唐诗/poet.song.126000.json','["老來遽有閨中戚，歲月飛騰奈爾何。", "八十耄齡能有幾，九三大耋可無歌。", "祥琴合御吾非激，朞樂如聽玷可磨。", "春到有花須痛飲，莫傷歲暮更蹉跎。"]'),
('91d1f4aa-b13a-439a-ae02-630f9fd63340','和楊誠齋題梅山詩卷  其一','姜特立','宋','宋诗','song-poetry','','[]','洋洋海內服詩聲，手决雲章萬象明。',64,'全唐诗/poet.song.126000.json','["洋洋海內服詩聲，手决雲章萬象明。", "千仞覽輝丹穴鳳，三春刷羽上林鶑。", "蕢桴土皷有遺韵，牛鬼蛇神無遁情。", "才大渺瀰如碧海，蹄涔那敢鬭澄泓。"]'),
('945b1c33-2fb4-4f1c-ac94-c473f514165b','和楊誠齋題梅山詩卷  其二','姜特立','宋','宋诗','song-poetry','','[]','接武東朝集鳳鸞，相如亦預賦梁園。',64,'全唐诗/poet.song.126000.json','["接武東朝集鳳鸞，相如亦預賦梁園。", "仆旗我合堅詩壁，授鉞君當坐將壇。", "妙似春風薰草木，深於元氣入脾肝。", "宮牆數仞難窺測，一點曾容豹管看。"]'),
('23521875-1123-4d6a-8837-d34135a7c41f','余年六十始入侍禁庭數月又直春宮','姜特立','宋','宋诗','song-poetry','','[]','新年出小刼，今日直儲宮。',48,'全唐诗/poet.song.126000.json','["新年出小刼，今日直儲宮。", "天道周必復，物情窮則通。", "春叢無寒榮，秋畬得晚豐。", "勿悲夕陽句，猶勝吾家翁。"]'),
('31441e65-1d23-47eb-bffc-dc522cd84839','讀杜子美集','姜特立','宋','宋诗','song-poetry','','[]','巴蜀勞重往，荆湘無定居。',120,'全唐诗/poet.song.126000.json','["巴蜀勞重往，荆湘無定居。", "宦情常造次，行橐屢空虛。", "宮闕烟塵外，江村盜賊餘。", "弟兄蹤跡斷，妻子信音疎。", "生理那堪說，窮愁自掃除。", "千篇比金玉，萬卷是菑畬。", "軒輊齊梁後，憑陵漢魏初。", "嚴公俄旅襯，岳土亦烟墟。", "一世惟漂泊，平生可歎歔。", "高名天所靳，此理復何如。"]'),
('a9af7922-c8e9-4df8-a325-1d5265bc1130','懷故友楊方叔','姜特立','宋','宋诗','song-poetry','','[]','游戲人間世，清虛物外緣。',48,'全唐诗/poet.song.126000.json','["游戲人間世，清虛物外緣。", "皇家雖結網，空谷竟遺賢。", "無恨堪懸劍，傷心有斷絃。", "今年湯餠約，爲爾一凄然。"]'),
('e58d8fc5-65b4-4373-b645-d780baa7679b','漁舍新成','姜特立','宋','宋诗','song-poetry','','[]','旋規漁舍傍溪山，山轉溪迴翠竹間。',64,'全唐诗/poet.song.126000.json','["旋規漁舍傍溪山，山轉溪迴翠竹間。", "閒看羽觴行詰曲，戲拈竿綫弄潺湲。", "浮家不入分風浦，歸棹休尋落照灣。", "謾說五湖烟浪好，幾人險處得心閒。"]'),
('7076d615-d98a-4b99-8d53-d000a363c797','山中','姜特立','宋','宋诗','song-poetry','','[]','籬畔黄花翠竹，雨後青山白雲。',28,'全唐诗/poet.song.126000.json','["籬畔黄花翠竹，雨後青山白雲。", "此是山中活計，莫教俗士知聞。"]'),
('592ba28e-2eac-4974-8fba-36c6e953e4a8','秋來喜雨','姜特立','宋','宋诗','song-poetry','','[]','西風吹雨洗林廬，夜深凉氣生庭除。',96,'全唐诗/poet.song.126000.json','["西風吹雨洗林廬，夜深凉氣生庭除。", "呼童爲我掃籧篨，便欲拂拭紅氍毹。", "冠巾三肅傅頭顱，絺綌輕利體不濡。", "似覺禮法由吾徒，寢甘食美增腹腴。", "牀頭有酒不用沽，更煩黄菊催紅萸。", "一秋辦取三百壺，二三佳友不可無。"]'),
('6a78e99f-9896-4e97-a797-18f35103b670','寄汪尚書','姜特立','宋','宋诗','song-poetry','','[]','五十年間歎闊疎，相忘兩地復江湖。',64,'全唐诗/poet.song.126000.json','["五十年間歎闊疎，相忘兩地復江湖。", "書來筆底驚强健，詩去吟邊想步趨。", "好對青山看歌舞，莫嫌紅粉笑髭鬚。", "鳳毛已有哦松韻，尚記金華舊範模。"]'),
('8251bc15-45a4-4157-8d8d-96901d4fcf86','甲辰歲以詩一編進孝宗聖語且許其清新驟蒙擢用暇日感孟襄陽事聊賦數語','姜特立','宋','宋诗','song-poetry','','[]','襄陽孟浩然，牀下謁至尊。',48,'全唐诗/poet.song.126000.json','["襄陽孟浩然，牀下謁至尊。", "一語不合意，放還歸里門。", "我詩雖不工，騎馬入帝閽。", "飽暖自茲始，永懷明主恩。"]'),
('855a624d-afaf-4ee0-aae9-b7bb42e7abbf','劉公達覓酒','姜特立','宋','宋诗','song-poetry','','[]','作詩覓酒真豪士，况是今年富酒材。',32,'全唐诗/poet.song.126000.json','["作詩覓酒真豪士，况是今年富酒材。", "豈有豪詩不豪酒，請君須飲及時盃。"]'),
('8e8f6068-613d-4200-baf9-7f5a7f6f8036','初夏','姜特立','宋','宋诗','song-poetry','','[]','松花金粉落，荷葉翠鈿浮。',24,'全唐诗/poet.song.126000.json','["松花金粉落，荷葉翠鈿浮。", "啼鵙千山暮，一年春事休。"]'),
('e4ec7651-be35-480c-952f-c573f45a114e','喜仲春有閏','姜特立','宋','宋诗','song-poetry','','[]','仲春閏月天氣佳，天豈有意遲羣葩。',98,'全唐诗/poet.song.126000.json','["仲春閏月天氣佳，天豈有意遲羣葩。", "天公正爲老人設，剩添一月延韶華。", "今春計日百二十，不比嚴霜烈日空增加。", "良辰好景不易得，此日詎可容易過。", "漢家天子賜甲子，所見殆可兒童誇。", "直須爛醉答造物，秉燭列炬驚林鴉。"]'),
('4039bd11-57ec-43dd-99a8-6d05a81158ff','王思叔惠巨竹一竿','姜特立','宋','宋诗','song-poetry','','[]','清晨剪送碧琅玕，想見軒窗六月寒。',32,'全唐诗/poet.song.126000.json','["清晨剪送碧琅玕，想見軒窗六月寒。", "便欲持將釣東海，未知何處可投竿。"]'),
('7dab4498-d6ba-4c99-ae36-cfda90ba54f9','齒脫','姜特立','宋','宋诗','song-poetry','','[]','髮白壯志凋，齒豁生意少。',84,'全唐诗/poet.song.126000.json','["髮白壯志凋，齒豁生意少。", "寒暑幾八旬，咀噍歲月久。", "請君視追蠡，血氣豈長好。", "吾祖仕進初，兩齒僅能有。", "此翁不即人，乃爲人所取。", "退之太崛强，方誇膾鯨手。", "畢竟將何如，人生不堪老。"]'),
('0505026e-a561-44b2-9675-8276f51a1cf9','雪後雙溪城外','姜特立','宋','宋诗','song-poetry','','[]','雪消閒出郭，騎馬踏山橋。',24,'全唐诗/poet.song.126000.json','["雪消閒出郭，騎馬踏山橋。", "池響冰澌落，泥融雁齒消。"]'),
('47ff601e-e6b6-44fd-9b5b-848ad8315055','詠閒','姜特立','宋','宋诗','song-poetry','','[]','一年閒有十年功，十歲如將百歲同。',32,'全唐诗/poet.song.126000.json','["一年閒有十年功，十歲如將百歲同。", "此去得閒猶未已，向前日月盡壺中。"]'),
('7321089b-1ee8-4f04-ab86-665086fa546b','病後負暄','姜特立','宋','宋诗','song-poetry','','[]','陽和被四體，覺我病骨輕。',48,'全唐诗/poet.song.126000.json','["陽和被四體，覺我病骨輕。", "血氣相貫輸，浩浩梨棗生。", "以我身中離，交會丙與丁。", "陰盡命自長，何必求丹經。"]'),
('2ec5acd9-b202-4afc-9b03-84530638a56f','水仙','姜特立','宋','宋诗','song-poetry','','[]','六出玉槃金屈巵，青瑶叢裏出花枝。',32,'全唐诗/poet.song.126000.json','["六出玉槃金屈巵，青瑶叢裏出花枝。", "清香自信高羣品，故與江梅相並時。"]'),
('ded41aef-ff56-4850-9036-330b38d91081','移瑞香','姜特立','宋','宋诗','song-poetry','','[]','少年無酒答羣葩，投老逢春鬢已華。',32,'全唐诗/poet.song.126000.json','["少年無酒答羣葩，投老逢春鬢已華。", "今日對花無意思，花應憐我我憐花。"]'),
('8c95b0f3-cd2b-40b5-812d-c6369e579aa3','飲酒','姜特立','宋','宋诗','song-poetry','','[]','平生嗜酒不耽酒，不愛深斟愛淺斟。',32,'全唐诗/poet.song.126000.json','["平生嗜酒不耽酒，不愛深斟愛淺斟。", "嵇阮詎能知此味，可憐一世只醺沈。"]'),
('7472a9bf-572c-47fc-8cf8-e2c376066957','偶成','姜特立','宋','宋诗','song-poetry','','[]','膩白夭紅漸滿枝，倡條冶葉競紛披。',32,'全唐诗/poet.song.126000.json','["膩白夭紅漸滿枝，倡條冶葉競紛披。", "化工只解呈新巧，惱殺衰翁都不知。"]'),
('f797267c-1505-4f8c-b574-aa739317b676','澗上','姜特立','宋','宋诗','song-poetry','','[]','晴蜻舞幽澗，水鵲立枯槎。',24,'全唐诗/poet.song.126000.json','["晴蜻舞幽澗，水鵲立枯槎。", "予亦坐烟壑，有生俱有涯。"]'),
('14dc4fb7-eea5-4494-ad7b-ef6ad4873a67','春晚戲題','姜特立','宋','宋诗','song-poetry','','[]','歲月飛騰不可回，紅顔去盡老相催。',32,'全唐诗/poet.song.126000.json','["歲月飛騰不可回，紅顔去盡老相催。", "自憐皺面無光彩，頼得春風爲熨開。"]'),
('44a9c19a-26d3-43d5-b596-d9c7ffaa00e0','尋春','姜特立','宋','宋诗','song-poetry','','[]','選勝尋春莫預期，風和日暖即佳時。',32,'全唐诗/poet.song.126000.json','["選勝尋春莫預期，風和日暖即佳時。", "行庖草草何妨事，明日陰晴特未知。"]'),
('493df766-86c5-485c-b642-edc036899a9f','庚申春再得奉祠','姜特立','宋','宋诗','song-poetry','','[]','香火緣深宦意灰，十年蕭散卧蒿萊。',32,'全唐诗/poet.song.126000.json','["香火緣深宦意灰，十年蕭散卧蒿萊。", "龐公從此不入市，只與漁樵相往來。"]'),
('9807582b-418c-4f4e-875f-918ca52a0754','老衰畏寒晨起婢輩熾炭紅焰滿室身心俱泰喜而有賦','姜特立','宋','宋诗','song-poetry','','[]','嚴晨一爐火，愛重如兼金。',48,'全唐诗/poet.song.126000.json','["嚴晨一爐火，愛重如兼金。", "既已暖我軀，且復豫我心。", "因思孟東野，曲身長苦吟。", "何如貴公子，得意椒房深。"]'),
('067dd9b9-8382-4060-8359-b2e62c44a8e7','香菌出括蒼山谷中其味香滑絕妙昔嘗欲獻之壽康終不敢也','姜特立','宋','宋诗','song-poetry','','[]','薰蒸應地德，香滑異園蔬。',48,'全唐诗/poet.song.126000.json','["薰蒸應地德，香滑異園蔬。", "天花非爾倫，金芝恐其餘。", "雅宜齋庖薦，不受羊羹污。", "將欲獻天子，誰爲達區區。"]'),
('fd86b790-b4ba-47c3-ad7c-1aec528a92ec','夜飲','姜特立','宋','宋诗','song-poetry','','[]','風高霜挾月，酒暖夜生春。',24,'全唐诗/poet.song.126000.json','["風高霜挾月，酒暖夜生春。", "一曲清歌罷，華胥有醉人。"]'),
('02f11398-ccf1-41d7-b5e0-dcefdc2b0221','幽事','姜特立','宋','宋诗','song-poetry','','[]','幽事春來早，晨興即啟閽。',48,'全唐诗/poet.song.126000.json','["幽事春來早，晨興即啟閽。", "掃梁延燕子，插楥護龍孫。", "數日招賓友，先期辦酒尊。", "淋漓衣袖濕，不管漬春痕。"]'),
('0c82d442-c489-424a-8a18-ce0d621c33a2','諸葛孔明','姜特立','宋','宋诗','song-poetry','','[]','臨發漢中時，精誠見表辭。',24,'全唐诗/poet.song.126000.json','["臨發漢中時，精誠見表辭。", "此心誰盡了，死後有天知。"]'),
('4cf4f0e0-06ba-4f24-b16b-e8b6317269b7','二月有霜海棠頗瘁','姜特立','宋','宋诗','song-poetry','','[]','青春淑景忽飛霜，餘烈猶能到海棠。',32,'全唐诗/poet.song.126000.json','["青春淑景忽飛霜，餘烈猶能到海棠。", "中山靖王孺子妾，尚書門下主謳娘。"]'),
('1c22ee21-e097-4ab3-bd6b-ad7aa7d7c225','初夏','姜特立','宋','宋诗','song-poetry','','[]','催成新夏荷浮翠，送盡餘春柳褪綿。',32,'全唐诗/poet.song.126000.json','["催成新夏荷浮翠，送盡餘春柳褪綿。", "正是清和好時節，嫩柯嬌葉媚晴天。"]'),
('a74d4b23-8745-41df-8fa0-12c47a37423d','王思叔惠象牙筍','姜特立','宋','宋诗','song-poetry','','[]','魚煮船頭筍煮園，一時風味最甘鮮。',32,'全唐诗/poet.song.126000.json','["魚煮船頭筍煮園，一時風味最甘鮮。", "君家象齒先春發，爲我携鉏斸翠烟。"]'),
('40b27187-9f13-41f9-b70f-51c38931fdce','晚春','姜特立','宋','宋诗','song-poetry','','[]','品物趨時慰寂寥，靜觀玄化自超遥。',32,'全唐诗/poet.song.126000.json','["品物趨時慰寂寥，靜觀玄化自超遥。", "鸚因求友偏饒舌，柳爲含綿嬾折腰。"]'),
('ea66fd82-0783-45f9-b971-3cd59215d3b8','適齋先生續樂天達哉行因繼其後詩雖不工聊抒鄙意而已','姜特立','宋','宋诗','song-poetry','','[]','樂天吾所敬，掛冠方一年。',264,'全唐诗/poet.song.126000.json','["樂天吾所敬，掛冠方一年。", "家事能幾何，處置有後先。", "始賣南坊園，次賣東郭田。", "末乃貨其廬，緡錢可三千。", "不爲子孫計，冀可了目前。", "嗚呼古之人，未易相比肩。", "顔子附郭外，不聞鬻其阡。", "淵明松菊逕，仲蔚蓬萊間。", "闕一尚不可，而况盡棄捐。", "先生果何心，達者未必然。", "適齋賢主人，歸卧甬水邊。", "家中無留貿，饑食困即眠。", "不可學其可，已省區中緣。", "嗟哉我何人，愛慕此二賢。", "素貧乏常産，晚有屋數椽。", "聖君不忍棄，未許車高懸。", "月散官中粟，不蓄俸餘錢。", "性復喜賓客，日日羅槃筵。", "萬事不掛眼，尚爲詩所纏。", "山上列花木，山下疏清泉。", "終日自逍遥，濠上樂亦全。", "起予者誰歟，三誦達哉篇。"]'),
('c11bdd82-a3c8-480b-b113-fc44b361473c','雲岑','姜特立','宋','宋诗','song-poetry','','[]','雲岑抱秋陰，水木起夜色。',24,'全唐诗/poet.song.126000.json','["雲岑抱秋陰，水木起夜色。", "原野漸蕭條，田禾捲阡陌。"]'),
('026e1ecc-8c1d-4f3e-81cc-e27675238b3d','閒吟','姜特立','宋','宋诗','song-poetry','','[]','天公靳惜是虛名，怪我吟詩筆不停。',32,'全唐诗/poet.song.126000.json','["天公靳惜是虛名，怪我吟詩筆不停。", "莫把文章覷天巧，只將渾沌養餘齡。"]'),
('eefa0d91-6bd2-4da5-b80b-4bbc1549d929','偶賦','姜特立','宋','宋诗','song-poetry','','[]','不織不耕日，無憂無惱身。',24,'全唐诗/poet.song.126000.json','["不織不耕日，無憂無惱身。", "曠哉天地德，養此最閒人。"]'),
('fff6b3d2-2ec3-4932-831d-3c3ab48299ad','野坐','姜特立','宋','宋诗','song-poetry','','[]','野坐花飛片，溪行水漲痕。',24,'全唐诗/poet.song.126000.json','["野坐花飛片，溪行水漲痕。", "山中閒日月，世上別乾坤。"]'),
('b1e651b3-8289-4587-9928-c415afb77aec','不貪','姜特立','宋','宋诗','song-poetry','','[]','人間五福少，世事罕兼全。',24,'全唐诗/poet.song.126000.json','["人間五福少，世事罕兼全。", "將此不貪寶，延予有限年。"]'),
('2ef6dd2c-3209-4cac-8d6c-85525a4d1489','偶至郡城','姜特立','宋','宋诗','song-poetry','','[]','老矣息奔走，胡爲此登途。',48,'全唐诗/poet.song.126000.json','["老矣息奔走，胡爲此登途。", "行李雖草草，客懷亦舒舒。", "傾我壺中釀，閲我袖間書。", "在家故云好，愛此暫時娛。"]'),
('9dce26f0-6493-4d36-8a71-0aa44a413a61','無客','姜特立','宋','宋诗','song-poetry','','[]','無客意不佳，獨飲有何好。',48,'全唐诗/poet.song.126000.json','["無客意不佳，獨飲有何好。", "雖非甕下豪，亦匪澤中槁。", "百年會有極，正要舒懷抱。", "不賦獨酌謠，相期醉鄉老。"]'),
('efd59e64-e32a-43ad-bbeb-1499c47940e3','冬夜不寐','姜特立','宋','宋诗','song-poetry','','[]','宵柝迢迢警睡魔，靜思甘分老林坡。',64,'全唐诗/poet.song.126000.json','["宵柝迢迢警睡魔，靜思甘分老林坡。", "忍胞只有嵇康嬾，扣角曾無甯戚歌。", "不起妄心思世事，只將閒意養天和。", "時人休說長生術，學著長生事轉多。"]'),
('32b7acfc-c62f-49ac-a7cd-a60f0edeba40','因赴郡會入城','姜特立','宋','宋诗','song-poetry','','[]','十年林下自由身，已放嚴光作外臣。',64,'全唐诗/poet.song.126000.json','["十年林下自由身，已放嚴光作外臣。", "終日奔馳非我意，有時嚅囁失天真。", "龐公不合來城府，梅福如何走市塵。", "策蹇明朝且歸去，故山猿鶴自相親。"]'),
('a46f4681-c667-4791-a4a2-b86bfe8bb3e6','賀王季發提舉掛冠','姜特立','宋','宋诗','song-poetry','','[]','明主尚書識履聲，君持閩節復儀形。',64,'全唐诗/poet.song.126000.json','["明主尚書識履聲，君持閩節復儀形。", "八年可仕不謀祿，七秩及時斯引經。", "肯把清名誇薄俗，只將厚德養脩齡。", "新詩祖送三千首，疏傅當時得寧馨。"]'),
('e00055f5-96f4-4b18-89e6-9feeb468e09a','次洪監簿惠詩韻五首  其一','姜特立','宋','宋诗','song-poetry','','[]','相逢可恨十年遲，鍼芥相投更不疑。',32,'全唐诗/poet.song.126000.json','["相逢可恨十年遲，鍼芥相投更不疑。", "從此詩筒數來往，不須千里寄相思。"]'),
('a39c46cc-9928-4306-ae44-5f6a2981dcbf','次洪監簿惠詩韻五首  其二','姜特立','宋','宋诗','song-poetry','','[]','新詩三復用功深，始信今人有古心。',32,'全唐诗/poet.song.126000.json','["新詩三復用功深，始信今人有古心。", "鬭葉儷花兒輩事，唱高廟瑟有遺音。"]'),
('45fae687-2e42-4586-9303-6e9d72eca209','次洪監簿惠詩韻五首  其三','姜特立','宋','宋诗','song-poetry','','[]','自古詩人失意多，偶然歲晚慰蹉跎。',32,'全唐诗/poet.song.126000.json','["自古詩人失意多，偶然歲晚慰蹉跎。", "如今世味都如蠟，水際林間自日哦。"]'),
('68dfe70f-113b-46ba-9550-9eb4d2b4a019','次洪監簿惠詩韻五首  其四','姜特立','宋','宋诗','song-poetry','','[]','三洪文字照乾坤，小謝風流筆力存。',32,'全唐诗/poet.song.126000.json','["三洪文字照乾坤，小謝風流筆力存。", "悟解向人難舉似，見花微笑自忘言。"]'),
('70f81584-b367-4597-81f2-4c28f786ea21','次洪監簿惠詩韻五首  其五','姜特立','宋','宋诗','song-poetry','','[]','莫嗟官路昧通津，舉世滔滔豈識真。',32,'全唐诗/poet.song.126000.json','["莫嗟官路昧通津，舉世滔滔豈識真。", "早晚青雲如直上，正須文字爲藩身。"]'),
('a3f02f65-329a-40f0-9c25-90950eee1a4e','幽事','姜特立','宋','宋诗','song-poetry','','[]','日日營幽事，時時有好懷。',48,'全唐诗/poet.song.126000.json','["日日營幽事，時時有好懷。", "雨園殘竹粉，風砌落松釵。", "伴蜨行花逕，聽蛙傍水涯。", "窮通了無謂，不必更安排。"]'),
('9e08a16b-8582-4580-ba10-68b3b572be92','觀插秧','姜特立','宋','宋诗','song-poetry','','[]','插秧如插針，瑣細亦良苦。',48,'全唐诗/poet.song.126000.json','["插秧如插針，瑣細亦良苦。", "分徒一夫積，終畝衆力舉。", "曾不旬日間，綠遍天涯土。", "周家重開國，幸勿輕農圃。"]'),
('6e355003-5c1e-46bb-afde-c4bf10e9f7ac','悼亡','姜特立','宋','宋诗','song-poetry','','[]','平生起居處，杳杳復冥冥。',60,'全唐诗/poet.song.126000.json','["平生起居處，杳杳復冥冥。", "人遠迹亦沈，邈焉居者情。", "以此觀世間，無物可留意。", "有如空中雲，東西適相值。", "雲收天宇開，虛空了無事。"]'),
('13c07f89-13a4-411f-bf6b-92be48692f2c','晨起信筆','姜特立','宋','宋诗','song-poetry','','[]','姜子胸中有至樂，青山白雲也不惡。',80,'全唐诗/poet.song.126000.json','["姜子胸中有至樂，青山白雲也不惡。", "不求作佛不求仙，却笑時人用心錯。", "樂天兜率墮渺茫，徐福神山更遼邈。", "丈夫天地要同流，俯仰隨化吾何求。", "太虛爲體隘九州，不須更述逍遥遊。"]'),
('22529362-3ac5-4a92-bfb6-8050ffe202a6','子陵瀨','姜特立','宋','宋诗','song-poetry','','[]','不爲故人出，出則將如何。',48,'全唐诗/poet.song.126000.json','["不爲故人出，出則將如何。", "交道古難終，豈唯畏虞羅。", "蕭何豐沛舊，未免投金科。", "先生誠高哉，無媿紫芝歌。"]'),
('09c61e93-0f8b-40a9-97a3-b6b14ae37f1d','雅志小飲適寬仲送相州法醖并竹萌同至','姜特立','宋','宋诗','song-poetry','','["\u559c\u60a6", "\u7231\u56fd", "\u5bb4\u996e"]','相州晝錦堂厨醖，衛國淇川岸竹萌。',32,'全唐诗/poet.song.126000.json','["相州晝錦堂厨醖，衛國淇川岸竹萌。", "二物煩君走分餉，時哉乘興倒瑶觥。"]'),
('44c749aa-74a1-4bba-a6ac-f1203e0a2f74','晚晴','姜特立','宋','宋诗','song-poetry','','[]','草木肥梅雨，江山快晚晴。',24,'全唐诗/poet.song.126000.json','["草木肥梅雨，江山快晚晴。", "芳塘荷芰發，香泛葛衣輕。"]'),
('5d438e27-6a3c-4833-839b-6d7081954ee8','齒將脫齟齬牴牾時或隠痛戲成','姜特立','宋','宋诗','song-poetry','','[]','摇齒不可仗，反側如小人。',48,'全唐诗/poet.song.126000.json','["摇齒不可仗，反側如小人。", "王陵雖少戇，信越終難馴。", "魯衛固小弱，秦晉依强鄰。", "更託輔車勢，庶以活吾身。"]'),
('7768b51d-a6ca-475e-9ea6-4fbaf63095dc','讀范文正公上執政書靖康之禍正以人不知兵','姜特立','宋','宋诗','song-poetry','','[]','經籍盡焚秦室亂，孫吳有禁本朝危。',32,'全唐诗/poet.song.126000.json','["經籍盡焚秦室亂，孫吳有禁本朝危。", "聖賢文字初何罪，羣小盈庭事可悲。"]'),
('fb2b1ccf-cbfa-4ff4-a495-681d402adf01','白髭','姜特立','宋','宋诗','song-poetry','','[]','檢校精神日向衰，羲和促轡過如飛。',32,'全唐诗/poet.song.126000.json','["檢校精神日向衰，羲和促轡過如飛。", "白髭可是長無頼，換我紅顔不放歸。"]'),
('f1a2404f-9b1a-48d9-a2e9-376f29d2509e','贈湯仲輝郊居','姜特立','宋','宋诗','song-poetry','','[]','木橋橫野水，竹逕踏晴沙。',24,'全唐诗/poet.song.126000.json','["木橋橫野水，竹逕踏晴沙。", "桑苧交陰處，中藏隠士家。"]'),
('2f014643-a898-43c5-9fbf-0a1e525d2a0a','東坡除夜三十九遂引樂天行年三十九歲暮日斜時之句賦詩余亦於生朝有感','姜特立','宋','宋诗','song-poetry','','[]','昔人三十九，已歎日斜時。',60,'全唐诗/poet.song.126000.json','["昔人三十九，已歎日斜時。", "吾今七十六，屈指一倍之。", "豈唯桑榆晚，正自入崦嵫。", "灰中炭暗盡，豈不心自知。", "且飲生朝酒，更賦梅山詩。"]'),
('4c48d205-0883-43a2-9f5a-3b3f3213ebab','野步','姜特立','宋','宋诗','song-poetry','','[]','倚杖立江干，丹楓疊嶂寒。',24,'全唐诗/poet.song.126000.json','["倚杖立江干，丹楓疊嶂寒。", "何人三昧手，畫我看秋山。"]'),
('5d395e39-7d72-46c0-9971-81c67fa95088','動植','姜特立','宋','宋诗','song-poetry','','[]','動植湊東風，天機各自濃。',24,'全唐诗/poet.song.126000.json','["動植湊東風，天機各自濃。", "花粘蜂股重，絮戀柳腰慵。"]'),
('018b7944-b120-4bd0-bd99-a049caabaaf1','雪晴','姜特立','宋','宋诗','song-poetry','','[]','六出弄陰機，新晴閃夕暉。',24,'全唐诗/poet.song.126000.json','["六出弄陰機，新晴閃夕暉。", "餘寒隨雁去，殘雪带春歸。"]');
